    def _context_slice_triples(
        self,
        graphs: list[str],
        resource_iris: Iterable[str],
        *,
        max_triples: int,
    ) -> tuple[list[ResourceTriple], int]:
        triples: list[ResourceTriple] = []
        queue = list(dict.fromkeys(resource_iris))
        seen_subjects: set[str] = set()
        seen_triples: set[
            tuple[str, str, str, str, str, str | None, str | None]
        ] = set()
        candidate_triple_count = 0

        while queue:
            subject = queue.pop(0)
            if subject in seen_subjects:
                continue
            seen_subjects.add(subject)
            subject_count = self._subject_triple_count(graphs, subject)
            for triple in self._resource_triples(
                graphs,
                subject=subject,
                limit=max(subject_count, 1),
            ):
                triple_key = (
                    triple.graph,
                    triple.subject,
                    triple.predicate,
                    triple.object,
                    triple.object_kind,
                    triple.object_datatype,
                    triple.object_lang,
                )
                if triple_key in seen_triples:
                    continue
                seen_triples.add(triple_key)
                candidate_triple_count += 1
                if triple.object_kind == "bnode" and triple.object not in seen_subjects:
                    queue.append(triple.object)
                if len(triples) < max_triples:
                    triples.append(triple)
        return triples, candidate_triple_count

    def _subject_triple_count(self, graphs: list[str], subject: str) -> int:
        graph_filter, params = self._graph_filter(graphs, alias="q")
        row = self._conn.execute(
            f"""
            SELECT COUNT(*) AS count
            FROM quads q
            WHERE q.subject = ?
              {graph_filter}
            """,
            [subject, *params],
        ).fetchone()
        return int(row["count"])

    def _context_slice_trig(
        self,
        triples: Iterable[ResourceTriple],
        *,
        graph_iri_prefix: str,
    ) -> str:
        dataset = Dataset()
        for prefix, namespace in PREFIXES.items():
            dataset.bind(prefix, namespace)
        dataset.bind("rcg", graph_iri_prefix)
        for triple in triples:
            context = dataset.graph(
                URIRef(self._export_graph_identifier(triple.graph, graph_iri_prefix))
            )
            context.add(
                (
                    self._term_from_row(triple.subject, triple.subject_kind),
                    URIRef(triple.predicate),
                    self._resource_triple_object_term(triple),
                )
            )
        return dataset.serialize(format="trig")

    def _resource_triple_object_term(self, triple: ResourceTriple) -> Identifier:
        if triple.object_kind == "uri":
            return URIRef(triple.object)
        if triple.object_kind == "bnode":
            return BNode(triple.object)
        if triple.object_kind == "literal":
            return Literal(
                triple.object,
                lang=triple.object_lang,
                datatype=triple.object_datatype,
            )
        raise TypeError(f"Unsupported object kind: {triple.object_kind}")

    def search(
        self,
        query: str,
        *,
        graph: str | None = None,
        limit: int = 20,
        offset: int = 0,
    ) -> SearchResults:
        if not query.strip():
            raise DoxaBaseError("Search query must not be empty")
        if limit < 1:
            raise DoxaBaseError("Search limit must be at least 1")
        if offset < 0:
            raise DoxaBaseError("Search offset must be non-negative")

        search_tokens = _search_tokens(query)
        fts_query = _fts_query_from_tokens(search_tokens)
        graphs = self._expand_graphs([graph] if graph else None)
        graph_filter, graph_params = self._graph_filter(graphs)
        rows = self._conn.execute(
            f"""
            SELECT
                graph,
                subject,
                predicate,
                text,
                snippet(literal_search, 4, '[', ']', ' ... ', 18) AS snippet
            FROM literal_search
            WHERE literal_search MATCH ?
              {graph_filter}
            ORDER BY bm25(literal_search), graph, subject, predicate
            LIMIT ? OFFSET ?
            """,
            [fts_query, *graph_params, limit, offset],
        ).fetchall()
        if not rows and len(search_tokens) > 1:
            rows = self._co_mentioned_search_rows(
                search_tokens,
                graphs,
                limit=limit,
                offset=offset,
            )

        ontology_graphs = self._expand_graphs(["ontology"])
        matches = [
            SearchMatch(
                iri=row["subject"],
                graph=row["graph"],
                label=self._display_label_from_graphs(
                    self._lookup_graphs([row["graph"]]),
                    row["subject"],
                ),
                types=self._types(row["graph"], row["subject"]),
                predicate=row["predicate"],
                predicate_label=self._label_from_graphs(
                    ontology_graphs,
                    row["predicate"],
                ),
                text=row["text"],
                snippet=row["snippet"],
            )
            for row in rows
        ]
        return SearchResults(
            query=query,
            graph=graph,
            matches=matches,
            limit=limit,
            offset=offset,
        )

    def _co_mentioned_search_rows(
        self,
        tokens: list[str],
        graphs: list[str],
        *,
        limit: int,
        offset: int,
    ) -> list[sqlite3.Row]:
        graph_filter, graph_params = self._graph_filter(graphs)
        fts_query = _fts_or_query_from_tokens(tokens)
        candidate_limit = max((limit + offset) * 20, 100)
        rows = self._conn.execute(
            f"""
            SELECT
                graph,
                subject,
                predicate,
                text,
                snippet(literal_search, 4, '[', ']', ' ... ', 18) AS snippet
            FROM literal_search
            WHERE literal_search MATCH ?
              {graph_filter}
            ORDER BY graph, subject, predicate
            LIMIT ?
            """,
            [fts_query, *graph_params, candidate_limit],
        ).fetchall()
        grouped: dict[str, tuple[set[str], list[sqlite3.Row]]] = {}
        for row in rows:
            matched_tokens = {
                token for token in tokens if token in row["text"].lower()
            }
            if not matched_tokens:
                continue
            context_key = self._search_context_key(graphs, row["subject"])
            token_set, grouped_rows = grouped.setdefault(context_key, (set(), []))
            token_set.update(matched_tokens)
            grouped_rows.append(row)

        required_tokens = set(tokens)
        selected_rows: list[sqlite3.Row] = []
        seen: set[tuple[str, str, str, str]] = set()
        for context_key, (token_set, grouped_rows) in sorted(grouped.items()):
            if not required_tokens.issubset(token_set):
                continue
            for row in grouped_rows:
                row_key = (
                    row["graph"],
                    row["subject"],
                    row["predicate"],
                    row["text"],
                )
                if row_key in seen:
                    continue
                seen.add(row_key)
                selected_rows.append(row)
        return selected_rows[offset : offset + limit]

    def _search_context_key(self, graphs: list[str], subject: str) -> str:
        return self._first_owner_dataset_iri(graphs, subject) or subject

    def describe_dataset(self, iri: str, graph: str | None = "map") -> DatasetDescription:
        dataset_iri = self.expand_iri(iri)
        data_graphs = self._expand_graphs([graph] if graph else None)
        lookup_graphs = self._lookup_graphs(data_graphs)
        if not self._subject_exists(dataset_iri, data_graphs):
            graph_label = graph if graph is not None else "all graphs"
            raise DoxaBaseError(
                f"Dataset '{iri}' was not found in {graph_label}"
                f"{self._missing_dataset_profile_hint(dataset_iri, iri)}"
            )

        columns = [
            self._describe_column(column_iri, data_graphs, lookup_graphs)
            for column_iri in self._objects(data_graphs, dataset_iri, "rc:hasColumn")
        ]
        columns.sort(key=lambda column: (column.column_name or "", column.iri))
        column_iris = [column.iri for column in columns]

        physical_layouts = [
            self._describe_physical_layout(layout_iri, data_graphs, lookup_graphs)
            for layout_iri in self._objects(data_graphs, dataset_iri, "rc:hasPhysicalLayout")
        ]
        storage_accesses = [
            self._describe_storage_access(access_iri, data_graphs, lookup_graphs)
            for access_iri in self._objects(data_graphs, dataset_iri, "rc:hasStorageAccess")
        ]
        partition_schemes = [
            self._describe_partition(partition_iri, data_graphs, lookup_graphs)
            for partition_iri in self._objects(data_graphs, dataset_iri, "rc:partitionedBy")
        ]
        direct_path_templates = self._objects(data_graphs, dataset_iri, "rc:pathTemplate")
        access_path_templates = [
            path_template
            for storage_access in storage_accesses
            for path_template in storage_access.path_templates
        ]
        partition_path_templates = [
            partition.path_template
            for partition in partition_schemes
            if partition.path_template is not None
        ]
        path_templates = list(
            dict.fromkeys(
                direct_path_templates + partition_path_templates + access_path_templates
            )
        )
        caveat_iris = self._objects(data_graphs, dataset_iri, "rc:hasKnownCaveat")
        provenance_iris = self._objects(data_graphs, dataset_iri, "rc:hasProvenance")
        relationships = self._relationships_for_dataset(
            dataset_iri,
            column_iris,
            data_graphs,
            lookup_graphs,
        )
        linked_pattern_targets = [
            dataset_iri,
            *column_iris,
            *caveat_iris,
            *(relationship.iri for relationship in relationships),
        ]
        related_datasets = self._related_datasets(
            dataset_iri,
            data_graphs,
            lookup_graphs,
            relationships=relationships,
        )
        linked_pattern_reasons = self._linked_pattern_reasons_for_dataset(
            linked_pattern_targets,
        )
        caveats = [
            self._describe_caveat(caveat_iri, data_graphs, lookup_graphs)
            for caveat_iri in caveat_iris
        ]
        profile_observations = self._profile_observations_for_target(
            target_iri=dataset_iri,
            target_predicate="rc:observedAsset",
            exclude_observed_column=True,
        )
        unmapped_column_profile_observations = (
            self._unmapped_column_profile_observations_for_dataset(
                dataset_iri,
                mapped_column_iris=column_iris,
            )
        )
        total_dataset_profile_count = self._profile_observation_count_for_target(
            target_iri=dataset_iri,
            target_predicate="rc:observedAsset",
            exclude_observed_column=True,
        )
        total_mapped_column_profile_count = sum(
            self._profile_observation_count_for_target(
                target_iri=column_iri,
                target_predicate="rc:observedColumn",
            )
            for column_iri in column_iris
        )
        total_unmapped_column_profile_count = (
            self._unmapped_column_profile_observation_count_for_dataset(
                dataset_iri,
                mapped_column_iris=column_iris,
            )
        )

        row_count_snapshot = self._int_object(
            data_graphs,
            dataset_iri,
            "rc:rowCountSnapshot",
        )
        description = DatasetDescription(
            iri=dataset_iri,
            graph=graph,
            label=self._label_from_graphs(lookup_graphs, dataset_iri),
            description=self._description_from_graphs(lookup_graphs, dataset_iri),
            types=self._types_from_graphs(data_graphs, dataset_iri),
            row_semantics=self._optional_resource_summary(
                lookup_graphs,
                self._first_object(data_graphs, dataset_iri, "rc:rowSemantics"),
            ),
            entity_key=self._optional_resource_summary(
                lookup_graphs,
                self._first_object(data_graphs, dataset_iri, "rc:entityKey"),
            ),
            snapshot_timestamp=self._optional_resource_summary(
                lookup_graphs,
                self._first_object(data_graphs, dataset_iri, "rc:snapshotTimestamp"),
            ),
            schema_stability=self._optional_resource_summary(
                lookup_graphs,
                self._first_object(data_graphs, dataset_iri, "rc:schemaStability"),
            ),
            row_count_snapshot=row_count_snapshot,
            layout_verification_status=self._optional_resource_summary(
                lookup_graphs,
                self._first_object(
                    data_graphs,
                    dataset_iri,
                    "rc:layoutVerificationStatus",
                ),
            ),
            layout_verification_note=self._first_object(
                data_graphs,
                dataset_iri,
                "rc:layoutVerificationNote",
            ),
            profile_summary=self._profile_summary(
                profile_observations,
                columns,
                unmapped_column_profile_observations,
                total_dataset_profile_count=total_dataset_profile_count,
                total_mapped_column_profile_count=(
                    total_mapped_column_profile_count
                ),
                total_unmapped_column_profile_count=(
                    total_unmapped_column_profile_count
                ),
                row_count_snapshot=row_count_snapshot,
            ),
            profile_observations=profile_observations,
            unmapped_column_profile_observations=unmapped_column_profile_observations,
            columns=columns,
            path_templates=path_templates,
            physical_layouts=physical_layouts,
            storage_accesses=storage_accesses,
            partition_schemes=partition_schemes,
            caveats=caveats,
            upstream_caveats=self._upstream_caveats_for_dataset(
                caveat_iris,
                relationships,
            ),
            operational_warnings=[],
            provenance=[
                self._resource_summary(
                    lookup_graphs,
                    provenance_iri,
                    description_predicate="rc:sourceDescription",
                )
                for provenance_iri in provenance_iris
            ],
            transformations=self._transformations_for_provenance(
                provenance_iris,
                data_graphs,
                lookup_graphs,
            ),
            related_datasets=related_datasets,
            related_dataset_groups=self._related_dataset_groups(
                dataset_iri,
                related_datasets,
                relationships,
            ),
            relationships=relationships,
            linked_patterns=self._linked_patterns_for_dataset(
                linked_pattern_targets,
            ),
            linked_pattern_reasons=linked_pattern_reasons,
        )
        return replace(
            description,
            operational_warnings=self._query_planning_issues(description),
        )

    def describe_profile_run(
        self,
        dataset_iri: str,
        evidence_iri: str,
        *,
        graph: str | None = "map",
        limit: int | None = None,
    ) -> ProfileRunDescription:
        if limit is not None and limit < 1:
            raise DoxaBaseError("limit must be a positive integer or None")
        dataset_value = self._required_iri("dataset_iri", dataset_iri)
        evidence_value = self._required_iri("evidence_iri", evidence_iri)
        data_graphs = self._expand_graphs([graph] if graph else None)
        lookup_graphs = self._lookup_graphs(data_graphs)
        evidence_graphs = ["evidence"]
        column_iris = self._objects(data_graphs, dataset_value, "rc:hasColumn")

        dataset_profiles = self._profiles_with_evidence(
            self._profile_observations_for_target(
                target_iri=dataset_value,
                target_predicate="rc:observedAsset",
                exclude_observed_column=True,
                limit=None,
            ),
            evidence_value,
        )
        mapped_column_profiles = self._profiles_with_evidence(
            [
                profile
                for column_iri in column_iris
                for profile in self._profile_observations_for_target(
                    target_iri=column_iri,
                    target_predicate="rc:observedColumn",
                    limit=None,
                )
            ],
            evidence_value,
        )
        unmapped_column_profiles = self._profiles_with_evidence(
            self._unmapped_column_profile_observations_for_dataset(
                dataset_value,
                mapped_column_iris=column_iris,
                limit=None,
            ),
            evidence_value,
        )

        categorized_profiles = [
            *[("dataset", profile) for profile in dataset_profiles],
            *[("mapped", profile) for profile in mapped_column_profiles],
            *[("unmapped", profile) for profile in unmapped_column_profiles],
        ]
        categorized_profiles.sort(
            key=lambda item: self._profile_observation_sort_key(item[1]),
            reverse=True,
        )
        returned_profiles = (
            categorized_profiles[:limit] if limit is not None else categorized_profiles
        )
        returned_dataset_profiles = [
            profile for category, profile in returned_profiles if category == "dataset"
        ]
        returned_mapped_column_profiles = [
            profile for category, profile in returned_profiles if category == "mapped"
        ]
        returned_unmapped_column_profiles = [
            profile for category, profile in returned_profiles if category == "unmapped"
        ]
        total_dataset_profile_count = len(dataset_profiles)
        total_mapped_column_profile_count = len(mapped_column_profiles)
        total_unmapped_column_profile_count = len(unmapped_column_profiles)
        total_profile_count = len(categorized_profiles)
        returned_profile_count = len(returned_profiles)
        omitted_dataset_profile_count = (
            total_dataset_profile_count - len(returned_dataset_profiles)
        )
        omitted_mapped_column_profile_count = (
            total_mapped_column_profile_count - len(returned_mapped_column_profiles)
        )
        omitted_unmapped_column_profile_count = (
            total_unmapped_column_profile_count - len(returned_unmapped_column_profiles)
        )
        omitted_profile_count = total_profile_count - returned_profile_count
        row_count_snapshot = self._int_object(
            data_graphs,
            dataset_value,
            "rc:rowCountSnapshot",
        )
        dataset_profile_row_count_bases: dict[int, set[str]] = {}
        for profile in dataset_profiles:
            if profile.row_count is None:
                continue
            dataset_profile_row_count_bases.setdefault(
                profile.row_count,
                set(),
            ).add(self._profile_observation_basis(profile))

        return ProfileRunDescription(
            dataset=self._resource_summary(lookup_graphs, dataset_value),
            evidence=self._describe_evidence(
                evidence_value,
                evidence_graphs,
                lookup_graphs,
            ),
            evidence_iri=evidence_value,
            row_count_snapshot=row_count_snapshot,
            dataset_profile_row_counts=sorted(dataset_profile_row_count_bases),
            dataset_profile_row_count_bases={
                str(row_count): sorted(bases)
                for row_count, bases in sorted(
                    dataset_profile_row_count_bases.items()
                )
            },
            row_count_snapshot_matches=(
                row_count_snapshot is not None
                and row_count_snapshot in dataset_profile_row_count_bases
            ),
            row_count_snapshot_basis=self._profile_row_count_snapshot_basis(
                row_count_snapshot,
                dataset_profile_row_count_bases,
            ),
            returned_dataset_profile_count=len(returned_dataset_profiles),
            returned_mapped_column_profile_count=len(returned_mapped_column_profiles),
            returned_unmapped_column_profile_count=len(
                returned_unmapped_column_profiles
            ),
            returned_profile_count=returned_profile_count,
            total_dataset_profile_count=total_dataset_profile_count,
            total_mapped_column_profile_count=total_mapped_column_profile_count,
            total_unmapped_column_profile_count=total_unmapped_column_profile_count,
            total_profile_count=total_profile_count,
            omitted_dataset_profile_count=omitted_dataset_profile_count,
            omitted_mapped_column_profile_count=omitted_mapped_column_profile_count,
            omitted_unmapped_column_profile_count=omitted_unmapped_column_profile_count,
            omitted_profile_count=omitted_profile_count,
            profile_observation_iris=[profile.iri for _, profile in returned_profiles],
            dataset_profile_observations=returned_dataset_profiles,
            mapped_column_profile_observations=returned_mapped_column_profiles,
            unmapped_column_profile_observations=returned_unmapped_column_profiles,
            retrieval_note=(
                "Profile run membership is inferred from returned profile "
                "observations for this dataset that link to the requested evidence "
                "IRI; no separate persisted profile-run node is implied."
            ),
        )

    def draft_profile_map_updates(
        self,
        dataset_iri: str,
        evidence_iri: str,
        *,
        graph: str | None = "map",
    ) -> ProfileMapUpdateDraft:
        dataset_value = self._required_iri("dataset_iri", dataset_iri)
        evidence_value = self._required_iri("evidence_iri", evidence_iri)
        data_graphs = self._expand_graphs([graph] if graph else None)
        map_dataset_found = self._subject_exists(dataset_value, data_graphs)
        dataset_description = (
            self.describe_dataset(dataset_value, graph=graph)
            if map_dataset_found
            else None
        )
        profile_run = self.describe_profile_run(
            dataset_value,
            evidence_value,
            graph=graph,
        )
        columns_by_iri = (
            {column.iri: column for column in dataset_description.columns}
            if dataset_description is not None
            else {}
        )

        recommendations: list[ProfileMapUpdateRecommendation] = []
        for profile in profile_run.dataset_profile_observations:
            if profile.row_count is None:
                continue
            if (
                dataset_description is not None
                and not self._dataset_description_is_table(dataset_description)
            ):
                continue
            current_row_count = (
                dataset_description.row_count_snapshot
                if dataset_description is not None
                else None
            )
            if current_row_count == profile.row_count:
                continue
            basis = self._profile_observation_basis(profile)
            action = (
                "record_map_value"
                if current_row_count is None
                else "replace_map_value"
            )
            recommendations.append(
                ProfileMapUpdateRecommendation(
                    recommendation_index=len(recommendations),
                    kind="dataset_row_count_snapshot",
                    action=action,
                    resource=profile_run.dataset,
                    predicate="rc:rowCountSnapshot",
                    current_value=current_row_count,
                    observed_value=profile.row_count,
                    observed_count=profile.row_count,
                    sample_size=profile.sample_size,
                    sample_scope=profile.sample_scope,
                    sample_method=profile.sample_method,
                    profile_row_count=profile.row_count,
                    profile_observation_iri=profile.iri,
                    evidence_iri=evidence_value,
                    basis=basis,
                    confidence="high" if basis == "full_scan" else "medium",
                    helper_name="record_map_dataset",
                    helper_arguments={
                        "iri": dataset_value,
                        "row_count_snapshot": profile.row_count,
                    },
                    rationale=(
                        "Profile row_count differs from the current map "
                        "row-count snapshot; review before recording the "
                        "profile value as current map context."
                        if map_dataset_found
                        else "No current map dataset was found; review the "
                        "profile scope before recording this intentionally "
                        "thin dataset shell with a row-count snapshot."
                    ),
                )
            )

        for profile in profile_run.mapped_column_profile_observations:
            if profile.null_count is None or profile.observed_column is None:
                continue
            column = columns_by_iri.get(profile.observed_column.iri)
            if column is None:
                continue
            observed_nullable = profile.null_count > 0
            if column.nullable == observed_nullable:
                continue
            basis = self._profile_observation_basis(profile)
            if not observed_nullable and basis != "full_scan":
                continue
            column_name = self._profile_map_column_name(column, profile)
            action = (
                "record_map_value"
                if column.nullable is None
                else "replace_map_value"
            )
            recommendations.append(
                ProfileMapUpdateRecommendation(
                    recommendation_index=len(recommendations),
                    kind="column_nullable",
                    action=action,
                    resource=profile.observed_column,
                    predicate="rc:nullable",
                    current_value=column.nullable,
                    observed_value=observed_nullable,
                    observed_count=profile.null_count,
                    sample_size=profile.sample_size,
                    sample_scope=profile.sample_scope,
                    sample_method=profile.sample_method,
                    profile_row_count=profile.row_count,
                    profile_observation_iri=profile.iri,
                    evidence_iri=evidence_value,
                    basis=basis,
                    confidence=(
                        "high" if basis == "full_scan" else "medium"
                    ),
                    helper_name="record_map_column",
                    helper_arguments={
                        "iri": column.iri,
                        "table_iri": dataset_value,
                        "column_name": column_name,
                        "nullable": observed_nullable,
                    },
                    rationale=(
                        "Profile null_count implies a different nullable "
                        "value than the current map column. Sampled zero-null "
                        "profiles are not promoted; positive null findings and "
                        "full-scan zero-null findings are review candidates."
                    ),
                )
            )

        for profile in profile_run.unmapped_column_profile_observations:
            if profile.observed_column is None:
                continue
            column_name = self._profile_observed_column_name(profile)
            if not column_name:
                continue
            basis = self._profile_observation_basis(profile)
            recommendations.append(
                ProfileMapUpdateRecommendation(
                    recommendation_index=len(recommendations),
                    kind="unmapped_profiled_column",
                    action="add_map_column_shell",
                    resource=profile.observed_column,
                    predicate="rc:hasColumn",
                    current_value=None,
                    observed_value=column_name,
                    observed_count=profile.row_count,
                    sample_size=profile.sample_size,
                    sample_scope=profile.sample_scope,
                    sample_method=profile.sample_method,
                    profile_row_count=profile.row_count,
                    profile_observation_iri=profile.iri,
                    evidence_iri=evidence_value,
                    basis=basis,
                    confidence="medium" if basis == "full_scan" else "low",
                    helper_name="record_map_column",
                    helper_arguments={
                        "iri": profile.observed_column.iri,
                        "table_iri": dataset_value,
                        "column_name": column_name,
                    },
                    rationale=(
                        "The profile run observed a column that is not mapped "
                        "as a current column. The draft only proposes a column "
                        "shell because observed type findings need separate "
                        "semantic review before becoming map type facts."
                        if map_dataset_found
                        else "No current map dataset was found; this draft "
                        "proposes only a thin column shell under the profiled "
                        "asset because observed type findings need separate "
                        "semantic review before becoming map type facts."
                    ),
                )
            )

        all_profiles = [
            *profile_run.dataset_profile_observations,
            *profile_run.mapped_column_profile_observations,
            *profile_run.unmapped_column_profile_observations,
        ]
        metric_advisories = self._profile_metric_vocabulary_advisories(
            all_profiles,
            evidence_value,
        )
        type_advisories = self._profile_type_finding_advisories(
            all_profiles,
            evidence_value,
            columns_by_iri=columns_by_iri,
            recommendations=recommendations,
        )
        metric_advisories, type_advisories = (
            self._with_profile_advisory_mixed_support(
                metric_advisories,
                type_advisories,
            )
        )
        recommendations = self._with_profile_update_default_staging_metadata(
            recommendations
        )
        recommendations = self._with_profile_update_duplicate_metadata(
            recommendations
        )
        representative_recommendation_indexes = (
            self._profile_update_representative_indexes(recommendations)
        )
        representative_metric_advisory_indexes = (
            self._profile_advisory_representative_indexes(metric_advisories)
        )
        representative_type_advisory_indexes = (
            self._profile_advisory_representative_indexes(type_advisories)
        )
        default_stageable_representative_indexes = [
            index
            for index in representative_recommendation_indexes
            if recommendations[index].default_stageable
        ]
        metric_advisory_status_counts = (
            self._profile_metric_advisory_status_counts(metric_advisories)
        )
        type_advisory_status_counts = self._profile_type_advisory_status_counts(
            type_advisories
        )
        scalar_conflict_groups = self._profile_update_scalar_conflict_groups(
            recommendations,
            dataset_iri=dataset_value,
            evidence_iri=evidence_value,
        )
        profile_supporting_pattern_iris = (
            self._profile_map_update_supporting_pattern_iris(
                profile_run,
                recommendations=recommendations,
                type_advisories=type_advisories,
            )
        )
        query_context_review_actions = (
            self._profile_query_context_review_actions(
                dataset_description,
                graph=graph,
            )
            if dataset_description is not None
            else []
        )
        suggested_next_action_groups = (
            self._profile_map_update_draft_action_groups(
                dataset_iri=dataset_value,
                evidence_iri=evidence_value,
                query_context_review_actions=query_context_review_actions,
                default_stageable_representative_indexes=(
                    default_stageable_representative_indexes
                ),
                scalar_conflict_groups=scalar_conflict_groups,
                supporting_patterns=profile_supporting_pattern_iris,
                metric_advisories=metric_advisories,
                type_advisories=type_advisories,
            )
        )
        suggested_next_actions = (
            self._profile_map_update_draft_actions_from_groups(
                suggested_next_action_groups
            )
        )
        suggested_next_call_groups = {
            group: [action.call for action in actions]
            for group, actions in suggested_next_action_groups.items()
        }
        return ProfileMapUpdateDraft(
            dataset=profile_run.dataset,
            evidence=profile_run.evidence,
            evidence_iri=evidence_value,
            map_dataset_found=map_dataset_found,
            profile_observation_iris=profile_run.profile_observation_iris,
            recommendations=recommendations,
            recommendation_count=len(recommendations),
            representative_recommendation_indexes=representative_recommendation_indexes,
            scalar_conflict_groups=scalar_conflict_groups,
            scalar_conflict_group_count=len(scalar_conflict_groups),
            metric_advisories=metric_advisories,
            metric_advisory_count=len(metric_advisories),
            representative_metric_advisory_indexes=(
                representative_metric_advisory_indexes
            ),
            metric_advisory_status_counts=metric_advisory_status_counts,
            type_advisories=type_advisories,
            type_advisory_count=len(type_advisories),
            representative_type_advisory_indexes=(
                representative_type_advisory_indexes
            ),
            type_advisory_status_counts=type_advisory_status_counts,
            suggested_next_actions=suggested_next_actions,
            suggested_next_calls=[
                action.call for action in suggested_next_actions
            ],
            suggested_next_action_groups=suggested_next_action_groups,
            suggested_next_call_groups=suggested_next_call_groups,
            review_note=(
                self._profile_map_update_draft_review_note(
                    query_context_review_actions=query_context_review_actions
                )
            ),
        )

    def _profile_map_update_draft_action_groups(
        self,
        *,
        dataset_iri: str,
        evidence_iri: str,
        query_context_review_actions: list[SuggestedNextAction],
        default_stageable_representative_indexes: list[int],
        scalar_conflict_groups: list[ProfileScalarConflictGroup],
        supporting_patterns: list[str],
        metric_advisories: list[ProfileMetricVocabularyAdvisory],
        type_advisories: list[ProfileTypeFindingAdvisory],
    ) -> dict[str, list[SuggestedNextAction]]:
        groups: dict[str, list[SuggestedNextAction]] = {}
        if query_context_review_actions:
            groups["query_context_review"] = query_context_review_actions
        profile_map_actions = self._profile_map_update_draft_profile_map_actions(
            dataset_iri=dataset_iri,
            evidence_iri=evidence_iri,
            default_stageable_representative_indexes=(
                default_stageable_representative_indexes
            ),
            supporting_patterns=supporting_patterns,
        )
        if profile_map_actions:
            groups["profile_map_updates"] = profile_map_actions
        scalar_conflict_actions = self._profile_scalar_conflict_suggested_actions(
            scalar_conflict_groups,
        )
        if scalar_conflict_actions:
            groups["profile_scalar_conflict_review"] = scalar_conflict_actions
        metric_actions = self._profile_metric_advisory_suggested_actions(
            metric_advisories
        )
        if metric_actions:
            groups["metric_vocabulary_review"] = metric_actions
        type_actions = self._profile_type_advisory_suggested_actions(
            type_advisories
        )
        if type_actions:
            groups["profile_type_review"] = type_actions
        return groups

    def _profile_query_context_review_actions(
        self,
        dataset: DatasetDescription,
        *,
        graph: str | None,
    ) -> list[SuggestedNextAction]:
        if not self._profile_query_context_has_physical_intent(dataset):
            return []
        context = self.describe_query_context(dataset.iri, graph=graph)
        if context.readiness not in {
            "insufficient_metadata",
            "blocked_by_contradiction",
        }:
            return []
        blocking_issues = [
            issue
            for issue in context.issues
            if issue.severity == "error" or issue.code == "contradicted_layout"
        ]
        if not blocking_issues:
            return []
        issue_codes = self._query_issue_codes(blocking_issues)
        arguments: dict[str, Any] = {"iri": dataset.iri}
        if graph is not None and graph != "map":
            arguments["graph"] = graph
        issue_summary = ", ".join(issue_codes)
        reason = (
            "Query context has blocking physical metadata issue(s) "
            f"({issue_summary}) and readiness "
            f"'{context.readiness}'. Review or repair query context before "
            "treating profile-derived map updates as query-ready context."
        )
        return [
            ProfileQueryContextSuggestedNextAction(
                action_label="Review query context blockers",
                tool_name="describe_query_context",
                mcp_tool_name="doxabase.describe_query_context",
                arguments=arguments,
                reason=reason,
                call=self._suggested_call_string(
                    "describe_query_context",
                    arguments,
                ),
                source_query_context={
                    "review_lane": "query_context_review",
                    "readiness": context.readiness,
                    "readiness_note": context.readiness_note,
                    "blocking_issue_codes": issue_codes,
                    "issue_codes": self._query_issue_codes(context.issues),
                    "suggested_repair_action_group_count": (
                        context.suggested_repair_action_group_count
                    ),
                },
            )
        ]

    @staticmethod
    def _profile_query_context_has_physical_intent(
        dataset: DatasetDescription,
    ) -> bool:
        return bool(
            dataset.path_templates
            or dataset.physical_layouts
            or dataset.storage_accesses
            or dataset.partition_schemes
        )

    @staticmethod
    def _profile_map_update_draft_review_note(
        *,
        query_context_review_actions: list[SuggestedNextAction],
    ) -> str:
        note = (
            "This draft is read-only review context derived from profile "
            "observations and current map facts. Apply accepted changes "
            "through map helpers or staged revisions after checking sample "
            "scope, evidence, caveats, and project modelling intent."
        )
        if query_context_review_actions:
            return (
                f"{note} Query context has blocking physical metadata issues; "
                "follow query_context_review before relying on profile-derived "
                "map updates for query-planning work."
            )
        return note

    @staticmethod
    def _profile_map_update_draft_actions_from_groups(
        groups: dict[str, list[SuggestedNextAction]],
    ) -> list[SuggestedNextAction]:
        actions: list[SuggestedNextAction] = []
        for group_name in (
            "query_context_review",
            "profile_map_updates",
            "metric_vocabulary_review",
            "profile_type_review",
        ):
            actions.extend(groups.get(group_name, []))
        return actions

    @staticmethod
    def _profile_scalar_conflict_suggested_actions(
        scalar_conflict_groups: list[ProfileScalarConflictGroup],
    ) -> list[SuggestedNextAction]:
        actions: list[SuggestedNextAction] = []
        for group in scalar_conflict_groups:
            for option_index, option in enumerate(group.options):
                action = option.suggested_next_action
                actions.append(
                    ProfileScalarConflictSuggestedNextAction(
                        action_label=action.action_label,
                        tool_name=action.tool_name,
                        mcp_tool_name=action.mcp_tool_name,
                        arguments=action.arguments,
                        reason=action.reason,
                        call=action.call,
                        source_scalar_conflict={
                            "review_lane": "profile_scalar_conflict_review",
                            "selection_rule": (
                                "choose_at_most_one_option_per_conflict_group"
                            ),
                            "conflict_group_index": group.conflict_group_index,
                            "evidence_iri": group.evidence_iri,
                            "resource_iri": group.resource.iri,
                            "resource_label": group.resource.label,
                            "predicate": group.predicate,
                            "kind": group.kind,
                            "current_value": group.current_value,
                            "option_index": option_index,
                            "option_count": group.option_count,
                            "observed_value": option.observed_value,
                            "representative_recommendation_index": (
                                option.representative_recommendation_index
                            ),
                            "recommendation_indexes": (
                                option.recommendation_indexes
                            ),
                            "duplicate_recommendation_indexes": (
                                option.duplicate_recommendation_indexes
                            ),
                            "duplicate_profile_observation_iris": (
                                option.duplicate_profile_observation_iris
                            ),
                            "review_note": group.review_note,
                        },
                    )
                )
        return actions

    def stage_profile_map_updates(
        self,
        dataset_iri: str,
        evidence_iri: str,
        *,
        accepted_recommendation_indexes: Iterable[int] | None,
        graph: TypingLiteral["map"] = "map",
        allow_sampled_row_count_updates: bool = False,
        summary: str | None = None,
        rationale: str | None = None,
        created_at: datetime | str | None = None,
        created_by: str | None = None,
        supporting_claims: Iterable[str] | str | None = None,
        supporting_patterns: Iterable[str] | str | None = None,
        revision_anchors: Iterable[str] | str | None = None,
        validation_scope: TypingLiteral[
            "map",
            "ontology",
            "patterns",
            "shapes",
            "all",
        ] = "all",
    ) -> ProfileMapUpdateStagingRecord:
        if graph != "map":
            raise DoxaBaseError("stage_profile_map_updates currently targets map only")
        accepted_indexes = self._profile_update_accepted_indexes(
            accepted_recommendation_indexes,
        )
        draft = self.draft_profile_map_updates(
            dataset_iri=dataset_iri,
            evidence_iri=evidence_iri,
            graph=graph,
        )
        recommendations = draft.recommendations
        out_of_range = [
            index for index in accepted_indexes if index >= len(recommendations)
        ]
        if out_of_range:
            raise DoxaBaseError(
                "accepted_recommendation_indexes out of range: "
                + ", ".join(str(index) for index in out_of_range)
            )

        accepted_index_set = set(accepted_indexes)
        selected_conflict_skip_reasons = (
            self._profile_update_scalar_conflict_skip_reasons(
                recommendations,
                selected_indexes=accepted_index_set,
            )
        )
        additions_graph = Graph()
        removals_graph = Graph()
        self._bind_prefixes(additions_graph)
        self._bind_prefixes(removals_graph)
        staged_indexes: list[int] = []
        skipped_indexes: list[int] = []
        not_selected_indexes: list[int] = []
        items: list[ProfileMapUpdateStagingItem] = []
        support_observations: list[str] = []
        profile_revision_anchors: list[str] = [draft.dataset.iri]

        for index, recommendation in enumerate(recommendations):
            status = "not_selected"
            reason: str | None = "Recommendation index was not accepted by caller."
            supporting_profile_observation_iris = (
                recommendation.duplicate_profile_observation_iris
                or [recommendation.profile_observation_iri]
            )
            if index in accepted_index_set:
                reason = selected_conflict_skip_reasons.get(index)
                if reason is None:
                    reason = self._profile_update_skip_reason(
                        recommendation,
                        allow_sampled_row_count_updates=(
                            allow_sampled_row_count_updates
                        ),
                    )
                if reason is None:
                    self._add_profile_update_patch_triples(
                        recommendation,
                        dataset_iri=draft.dataset.iri,
                        map_dataset_found=draft.map_dataset_found,
                        additions_graph=additions_graph,
                        removals_graph=removals_graph,
                    )
                    status = "staged"
                    staged_indexes.append(index)
                    support_observations.extend(supporting_profile_observation_iris)
                    for anchor in self._profile_update_revision_anchors(
                        recommendation,
                        dataset_iri=draft.dataset.iri,
                    ):
                        profile_revision_anchors.append(anchor)
                else:
                    status = "skipped"
                    skipped_indexes.append(index)
            else:
                not_selected_indexes.append(index)

            items.append(
                ProfileMapUpdateStagingItem(
                    recommendation_index=index,
                    kind=recommendation.kind,
                    action=recommendation.action,
                    resource=recommendation.resource,
                    status=status,
                    reason=reason,
                    basis=recommendation.basis,
                    confidence=recommendation.confidence,
                    sample_size=recommendation.sample_size,
                    sample_scope=recommendation.sample_scope,
                    sample_method=recommendation.sample_method,
                    profile_observation_iri=recommendation.profile_observation_iri,
                    supporting_profile_observation_iris=(
                        supporting_profile_observation_iris
                    ),
                )
            )

        status_counts = self._profile_update_status_counts(items)
        additions: list[dict[str, str]] = []
        removals: list[dict[str, str]] = []
        if len(additions_graph) > 0:
            additions.append(
                {
                    "graph": "map",
                    "content": additions_graph.serialize(format="turtle").strip(),
                }
            )
        if len(removals_graph) > 0:
            removals.append(
                {
                    "graph": "map",
                    "content": removals_graph.serialize(format="turtle").strip(),
                }
            )

        staged_revision: StagedGraphRevisionRecord | None = None
        if additions or removals:
            dataset_label = draft.dataset.label or self._local_name(draft.dataset.iri)
            staged_revision = self.stage_graph_revision(
                summary=summary
                or f"Stage profile map updates for {dataset_label}",
                rationale=rationale
                or (
                    "Accepted profile map-update recommendations from "
                    "draft_profile_map_updates and grouped them into one "
                    "reviewable map revision so helper-equivalent shells and "
                    "scalar updates can be applied together after review."
                ),
                additions=additions,
                removals=removals,
                created_at=created_at,
                created_by=created_by,
                supporting_observations=list(dict.fromkeys(support_observations)),
                supporting_claims=self._merge_iri_values(supporting_claims, []),
                supporting_patterns=self._merge_iri_values(supporting_patterns, []),
                evidence=[draft.evidence_iri],
                revision_anchors=self._merge_iri_values(
                    revision_anchors,
                    profile_revision_anchors,
                ),
                review_note=self._profile_update_staging_review_note(
                    items,
                    staged_indexes=staged_indexes,
                    skipped_indexes=skipped_indexes,
                    status_counts=status_counts,
                    metric_advisory_count=draft.metric_advisory_count,
                    metric_advisory_status_counts=(
                        draft.metric_advisory_status_counts
                    ),
                    type_advisory_count=draft.type_advisory_count,
                    type_advisory_status_counts=draft.type_advisory_status_counts,
                    allow_sampled_row_count_updates=allow_sampled_row_count_updates,
                ),
                review_recommendation=(
                    "Review staged profile-derived map changes, especially "
                    "sample scope, before applying; review any metric "
                    "vocabulary advisories separately before reusing them."
                ),
                validation_scope=validation_scope,
            )

        suggested_next_actions = self._profile_update_staging_actions(
            staged_revision,
            items=items,
            dataset_iri=draft.dataset.iri,
            evidence_iri=draft.evidence_iri,
        )
        metric_advisory_suggested_next_actions = (
            self._profile_metric_advisory_suggested_actions(
                draft.metric_advisories,
            )
        )
        type_advisory_suggested_next_actions = (
            self._profile_type_advisory_suggested_actions(
                draft.type_advisories,
            )
        )
        return ProfileMapUpdateStagingRecord(
            result_kind="profile_map_update_staging",
            dataset=draft.dataset,
            evidence=draft.evidence,
            evidence_iri=draft.evidence_iri,
            map_dataset_found=draft.map_dataset_found,
            recommendation_count=len(recommendations),
            accepted_recommendation_indexes=accepted_indexes,
            staged_recommendation_indexes=staged_indexes,
            skipped_recommendation_indexes=skipped_indexes,
            not_selected_recommendation_indexes=not_selected_indexes,
            status_counts=status_counts,
            items=items,
            metric_advisories=draft.metric_advisories,
            metric_advisory_count=draft.metric_advisory_count,
            metric_advisory_status_counts=draft.metric_advisory_status_counts,
            metric_vocabulary_review_required=bool(
                metric_advisory_suggested_next_actions
            ),
            metric_advisory_suggested_next_actions=(
                metric_advisory_suggested_next_actions
            ),
            metric_advisory_suggested_next_calls=[
                action.call for action in metric_advisory_suggested_next_actions
            ],
            type_advisories=draft.type_advisories,
            type_advisory_count=draft.type_advisory_count,
            type_advisory_status_counts=draft.type_advisory_status_counts,
            type_review_required=bool(type_advisory_suggested_next_actions),
            type_advisory_suggested_next_actions=(
                type_advisory_suggested_next_actions
            ),
            type_advisory_suggested_next_calls=[
                action.call for action in type_advisory_suggested_next_actions
            ],
            staged_revision=staged_revision,
            suggested_next_actions=suggested_next_actions,
            suggested_next_calls=[
                action.call for action in suggested_next_actions
            ],
            review_note=self._profile_update_staging_review_note(
                items,
                staged_indexes=staged_indexes,
                skipped_indexes=skipped_indexes,
                status_counts=status_counts,
                metric_advisory_count=draft.metric_advisory_count,
                metric_advisory_status_counts=draft.metric_advisory_status_counts,
                type_advisory_count=draft.type_advisory_count,
                type_advisory_status_counts=draft.type_advisory_status_counts,
                allow_sampled_row_count_updates=allow_sampled_row_count_updates,
            ),
        )

    def _profile_update_staging_actions(
        self,
        staged_revision: StagedGraphRevisionRecord | None,
        *,
        items: list[ProfileMapUpdateStagingItem],
        dataset_iri: str,
        evidence_iri: str,
    ) -> list[SuggestedNextAction]:
        actions: list[SuggestedNextAction] = []
        if staged_revision is None:
            return actions
        arguments = {"iri": staged_revision.revision_iri}
        actions.append(
            SuggestedNextAction(
                action_label="Check staged profile map updates",
                tool_name="check_staged_revision_apply",
                mcp_tool_name="doxabase.check_staged_revision_apply",
                arguments=arguments,
                reason=(
                    "Run the read-only apply check before reviewing, exporting, "
                    "or applying the grouped profile-derived map revision."
                ),
                call=self._suggested_call_string(
                    "check_staged_revision_apply",
                    arguments,
                ),
            )
        )
        export_arguments = {
            "dataset_iri": dataset_iri,
            "evidence_iri": evidence_iri,
            "path": self._suggested_review_export_path(
                "profile-insight-review",
                [staged_revision.revision_iri],
            ),
            "revision_iris": [staged_revision.revision_iri],
            "overwrite": True,
        }
        actions.append(
            SuggestedNextAction(
                action_label="Export profile insight review bundle",
                tool_name="export_profile_insight_review_bundle",
                mcp_tool_name="doxabase.export_profile_insight_review_bundle",
                arguments=export_arguments,
                reason=(
                    "Export a grouped review bundle for staged revisions tied "
                    "to this profile run. Re-run this export after staging any "
                    "related metric vocabulary, type-review, or caveat "
                    "alternatives so the bundle can compare the lanes together."
                ),
                call=self._suggested_call_string(
                    "export_profile_insight_review_bundle",
                    export_arguments,
                ),
            )
        )
        if any(
            item.status == "staged" and item.kind == "unmapped_profiled_column"
            for item in items
        ):
            rerun_arguments = {
                "dataset_iri": dataset_iri,
                "evidence_iri": evidence_iri,
            }
            actions.append(
                ProfileMapUpdateRerunSuggestedNextAction(
                    action_label="Rerun profile map update draft",
                    tool_name="draft_profile_map_updates",
                    mcp_tool_name="doxabase.draft_profile_map_updates",
                    arguments=rerun_arguments,
                    reason=(
                        "After reviewing and applying the staged unmapped "
                        "column shell(s), rerun the profile map-update draft "
                        "for the same dataset and evidence so type advisories "
                        "and follow-up map recommendations can reclassify "
                        "against map-present columns."
                    ),
                    call=self._suggested_call_string(
                        "draft_profile_map_updates",
                        rerun_arguments,
                    ),
                    preconditions={
                        "staged_revision_applied": staged_revision.revision_iri,
                        "why": (
                            "The rerun only reflects the newly mapped column "
                            "after the staged profile map-update revision has "
                            "been reviewed and applied."
                        ),
                    },
                )
            )
        return actions

    def _profile_map_update_draft_profile_map_actions(
        self,
        *,
        dataset_iri: str,
        evidence_iri: str,
        default_stageable_representative_indexes: list[int],
        supporting_patterns: list[str],
    ) -> list[SuggestedNextAction]:
        actions: list[SuggestedNextAction] = []
        if default_stageable_representative_indexes:
            arguments = {
                "dataset_iri": dataset_iri,
                "evidence_iri": evidence_iri,
                "accepted_recommendation_indexes": (
                    default_stageable_representative_indexes
                ),
            }
            if supporting_patterns:
                arguments["supporting_patterns"] = supporting_patterns
            actions.append(
                SuggestedNextAction(
                    action_label="Review and stage profile map updates",
                    tool_name="stage_profile_map_updates",
                    mcp_tool_name="doxabase.stage_profile_map_updates",
                    arguments=arguments,
                    reason=(
                        "Review recommendation rows, sample scope, default "
                        "staging guardrails, evidence, and metric/type advisory "
                        "lanes; "
                        "then pass accepted default-stageable indexes to "
                        "stage_profile_map_updates. Sampled row-count updates "
                        "require an explicit override; same-evidence scalar "
                        "conflicts require choosing one value explicitly."
                    ),
                    call=self._suggested_call_string(
                        "stage_profile_map_updates",
                        arguments,
                    ),
                )
            )

        return actions

    def _profile_map_update_supporting_pattern_iris(
        self,
        profile_run: ProfileRunDescription,
        *,
        recommendations: list[ProfileMapUpdateRecommendation],
        type_advisories: list[ProfileTypeFindingAdvisory],
    ) -> list[str]:
        pattern_graphs = ["patterns"]
        same_evidence_patterns = set(
            self._subjects(pattern_graphs, "rc:evidence", profile_run.evidence_iri)
        )
        if not same_evidence_patterns:
            return []

        relevant_resource_iris = {profile_run.dataset.iri}
        for recommendation in recommendations:
            relevant_resource_iris.add(recommendation.resource.iri)
        type_review_resource_iris = {
            resource.iri
            for advisory in type_advisories
            for resource in (
                advisory.observed_physical_type,
                advisory.observed_value_type,
            )
            if resource is not None
        }

        pattern_iris: list[str] = []
        for pattern_iri in sorted(same_evidence_patterns):
            pattern_resources = {
                *self._objects(pattern_graphs, pattern_iri, "rc:patternTarget"),
                *self._objects(pattern_graphs, pattern_iri, "rc:mapImplication"),
            }
            if pattern_resources & type_review_resource_iris:
                continue
            if pattern_resources & relevant_resource_iris:
                pattern_iris.append(pattern_iri)
        return pattern_iris

    @staticmethod
    def _profile_update_representative_indexes(
        recommendations: list[ProfileMapUpdateRecommendation],
    ) -> list[int]:
        representatives: list[int] = []
        seen_group_keys: set[str] = set()
        for recommendation in recommendations:
            group_key = (
                recommendation.duplicate_group_key
                or f"recommendation:{recommendation.recommendation_index}"
            )
            if group_key in seen_group_keys:
                continue
            seen_group_keys.add(group_key)
            representatives.append(recommendation.recommendation_index)
        return representatives

    @staticmethod
    def _profile_advisory_representative_indexes(
        advisories: Iterable[
            ProfileMetricVocabularyAdvisory | ProfileTypeFindingAdvisory
        ],
    ) -> list[int]:
        representatives: list[int] = []
        seen_group_keys: set[str] = set()
        for index, advisory in enumerate(advisories):
            group_key = advisory.duplicate_group_key or f"advisory:{index}"
            if group_key in seen_group_keys:
                continue
            seen_group_keys.add(group_key)
            representatives.append(index)
        return representatives

    @staticmethod
    def _profile_update_scalar_value_key(value: Any) -> str:
        payload = {
            "type": type(value).__name__,
            "value": to_jsonable(value),
        }
        return json.dumps(payload, sort_keys=True, default=str)

    @staticmethod
    def _profile_update_scalar_value_label(value: Any) -> str:
        if isinstance(value, bool):
            return str(value).lower()
        if isinstance(value, str):
            return repr(value)
        return str(value)

    @staticmethod
    def _profile_update_scalar_conflict_skip_reasons(
        recommendations: list[ProfileMapUpdateRecommendation],
        *,
        selected_indexes: set[int] | None = None,
    ) -> dict[int, str]:
        groups: dict[
            tuple[str, str, str, str],
            dict[str, list[ProfileMapUpdateRecommendation]],
        ] = {}
        for recommendation in recommendations:
            if (
                selected_indexes is not None
                and recommendation.recommendation_index not in selected_indexes
            ):
                continue
            if recommendation.kind not in PROFILE_SCALAR_MAP_UPDATE_KINDS:
                continue
            group_key = (
                recommendation.evidence_iri,
                recommendation.resource.iri,
                recommendation.predicate,
                recommendation.kind,
            )
            value_key = DoxaBase._profile_update_scalar_value_key(
                recommendation.observed_value
            )
            groups.setdefault(group_key, {}).setdefault(value_key, []).append(
                recommendation
            )

        skip_reasons: dict[int, str] = {}
        for (_evidence_iri, resource_iri, predicate, _kind), value_groups in (
            groups.items()
        ):
            if len(value_groups) <= 1:
                continue
            value_labels = sorted(
                DoxaBase._profile_update_scalar_value_label(
                    group[0].observed_value
                )
                for group in value_groups.values()
            )
            reason = (
                "Same-evidence profile recommendations propose conflicting "
                f"values for scalar map assertion {predicate} on "
                f"{resource_iri}: {', '.join(value_labels)}. Review the "
                "profile observations and choose one observed value explicitly "
                "before staging."
            )
            for group in value_groups.values():
                for recommendation in group:
                    skip_reasons[recommendation.recommendation_index] = reason
        return skip_reasons

    def _profile_update_scalar_conflict_groups(
        self,
        recommendations: list[ProfileMapUpdateRecommendation],
        *,
        dataset_iri: str,
        evidence_iri: str,
    ) -> list[ProfileScalarConflictGroup]:
        groups: dict[
            tuple[str, str, str, str],
            dict[str, list[ProfileMapUpdateRecommendation]],
        ] = {}
        for recommendation in recommendations:
            if recommendation.kind not in PROFILE_SCALAR_MAP_UPDATE_KINDS:
                continue
            group_key = (
                recommendation.evidence_iri,
                recommendation.resource.iri,
                recommendation.predicate,
                recommendation.kind,
            )
            value_key = self._profile_update_scalar_value_key(
                recommendation.observed_value
            )
            groups.setdefault(group_key, {}).setdefault(value_key, []).append(
                recommendation
            )

        conflict_groups: list[ProfileScalarConflictGroup] = []
        for (_group_evidence_iri, _resource_iri, predicate, kind), value_groups in (
            groups.items()
        ):
            if len(value_groups) <= 1:
                continue
            first_recommendation = next(iter(value_groups.values()))[0]
            options: list[ProfileScalarConflictOption] = []
            for value_group in sorted(
                value_groups.values(),
                key=lambda group: min(
                    recommendation.recommendation_index
                    for recommendation in group
                ),
            ):
                representative = value_group[0]
                recommendation_indexes = [
                    recommendation.recommendation_index
                    for recommendation in value_group
                ]
                duplicate_recommendation_indexes = list(
                    dict.fromkeys(
                        index
                        for recommendation in value_group
                        for index in (
                            recommendation.duplicate_recommendation_indexes
                            or [recommendation.recommendation_index]
                        )
                    )
                )
                duplicate_profile_observation_iris = list(
                    dict.fromkeys(
                        observation_iri
                        for recommendation in value_group
                        for observation_iri in (
                            recommendation.duplicate_profile_observation_iris
                            or [recommendation.profile_observation_iri]
                        )
                    )
                )
                arguments = {
                    "dataset_iri": dataset_iri,
                    "evidence_iri": evidence_iri,
                    "accepted_recommendation_indexes": [
                        representative.recommendation_index
                    ],
                }
                action = SuggestedNextAction(
                    action_label="Review and stage chosen profile scalar value",
                    tool_name="stage_profile_map_updates",
                    mcp_tool_name="doxabase.stage_profile_map_updates",
                    arguments=arguments,
                    reason=(
                        "This same-evidence scalar conflict is not "
                        "default-stageable. Use this action only after "
                        "reviewing the conflicting profile observations and "
                        "choosing this observed value for the current map "
                        "assertion."
                    ),
                    call=self._suggested_call_string(
                        "stage_profile_map_updates",
                        arguments,
                    ),
                )
                options.append(
                    ProfileScalarConflictOption(
                        observed_value=representative.observed_value,
                        representative_recommendation_index=(
                            representative.recommendation_index
                        ),
                        recommendation_indexes=recommendation_indexes,
                        duplicate_recommendation_indexes=(
                            duplicate_recommendation_indexes
                        ),
                        duplicate_profile_observation_iris=(
                            duplicate_profile_observation_iris
                        ),
                        suggested_next_action=action,
                        suggested_next_call=action.call,
                    )
                )
            conflict_groups.append(
                ProfileScalarConflictGroup(
                    conflict_group_index=len(conflict_groups),
                    evidence_iri=evidence_iri,
                    resource=first_recommendation.resource,
                    predicate=predicate,
                    kind=kind,
                    current_value=first_recommendation.current_value,
                    option_count=len(options),
                    options=options,
                    review_note=(
                        "Same-evidence profile recommendations propose "
                        "multiple values for this scalar map assertion. These "
                        "options stay out of default profile_map_updates; "
                        "choose at most one option after reviewing the "
                        "supporting profile observations."
                    ),
                )
            )
        return conflict_groups

    def _with_profile_update_default_staging_metadata(
        self,
        recommendations: list[ProfileMapUpdateRecommendation],
    ) -> list[ProfileMapUpdateRecommendation]:
        conflict_skip_reasons = self._profile_update_scalar_conflict_skip_reasons(
            recommendations
        )
        annotated: list[ProfileMapUpdateRecommendation] = []
        for recommendation in recommendations:
            default_skip_reason = conflict_skip_reasons.get(
                recommendation.recommendation_index
            )
            if default_skip_reason is None:
                default_skip_reason = self._profile_update_skip_reason(
                    recommendation,
                    allow_sampled_row_count_updates=False,
                )
            annotated.append(
                replace(
                    recommendation,
                    default_stageable=default_skip_reason is None,
                    default_skip_reason=default_skip_reason,
                )
            )
        return annotated

    def _with_profile_update_duplicate_metadata(
        self,
        recommendations: list[ProfileMapUpdateRecommendation],
    ) -> list[ProfileMapUpdateRecommendation]:
        groups: dict[str, list[ProfileMapUpdateRecommendation]] = {}
        for recommendation in recommendations:
            groups.setdefault(
                self._profile_update_duplicate_group_key(recommendation),
                [],
            ).append(recommendation)

        annotated: list[ProfileMapUpdateRecommendation] = []
        for recommendation in recommendations:
            group_key = self._profile_update_duplicate_group_key(recommendation)
            group = groups[group_key]
            annotated.append(
                replace(
                    recommendation,
                    duplicate_group_key=group_key,
                    duplicate_count=len(group),
                    duplicate_recommendation_indexes=[
                        item.recommendation_index for item in group
                    ],
                    duplicate_profile_observation_iris=list(
                        dict.fromkeys(item.profile_observation_iri for item in group)
                    ),
                )
            )
        return annotated

    @staticmethod
    def _profile_update_duplicate_group_key(
        recommendation: ProfileMapUpdateRecommendation,
    ) -> str:
        payload = {
            "kind": recommendation.kind,
            "action": recommendation.action,
            "resource_iri": recommendation.resource.iri,
            "predicate": recommendation.predicate,
            "current_value": recommendation.current_value,
            "observed_value": recommendation.observed_value,
            "observed_count": recommendation.observed_count,
            "sample_size": recommendation.sample_size,
            "sample_scope": recommendation.sample_scope,
            "sample_method": recommendation.sample_method,
            "profile_row_count": recommendation.profile_row_count,
            "evidence_iri": recommendation.evidence_iri,
            "basis": recommendation.basis,
            "confidence": recommendation.confidence,
            "helper_name": recommendation.helper_name,
            "helper_arguments": recommendation.helper_arguments,
        }
        digest = hashlib.sha256(
            json.dumps(payload, sort_keys=True, default=str).encode("utf-8")
        ).hexdigest()[:12]
        return f"profile-map-update:{digest}"

    @staticmethod
    def _profile_metric_advisory_suggested_actions(
        metric_advisories: list[ProfileMetricVocabularyAdvisory],
    ) -> list[SuggestedNextAction]:
        return DoxaBase._profile_advisory_suggested_actions(
            metric_advisories,
            advisory_kind="metric_vocabulary_review",
            index_field="metric_advisory_index",
        )

    def _profile_update_accepted_indexes(
        self,
        accepted_recommendation_indexes: Iterable[int] | None,
    ) -> list[int]:
        if accepted_recommendation_indexes is None:
            raise DoxaBaseError(
                "accepted_recommendation_indexes must name at least one "
                "accepted draft recommendation"
            )
        indexes: list[int] = []
        for value in accepted_recommendation_indexes:
            if isinstance(value, bool) or not isinstance(value, int):
                raise DoxaBaseError(
                    "accepted_recommendation_indexes values must be integers"
                )
            if value < 0:
                raise DoxaBaseError(
                    "accepted_recommendation_indexes values must be non-negative"
                )
            indexes.append(value)
        indexes = list(dict.fromkeys(indexes))
        if not indexes:
            raise DoxaBaseError(
                "accepted_recommendation_indexes must name at least one "
                "accepted draft recommendation"
            )
        return indexes

    @staticmethod
    def _profile_update_status_counts(
        items: list[ProfileMapUpdateStagingItem],
    ) -> dict[str, int]:
        counts = {"staged": 0, "skipped": 0, "not_selected": 0}
        for item in items:
            counts[item.status] = counts.get(item.status, 0) + 1
        return counts

    @staticmethod
    def _profile_metric_advisory_status_counts(
        advisories: Iterable[ProfileMetricVocabularyAdvisory],
    ) -> dict[str, int]:
        counts: dict[str, int] = {}
        for advisory in advisories:
            counts[advisory.advisory_status] = (
                counts.get(advisory.advisory_status, 0) + 1
            )
        return counts

    @staticmethod
    def _profile_type_advisory_status_counts(
        advisories: Iterable[ProfileTypeFindingAdvisory],
    ) -> dict[str, int]:
        counts: dict[str, int] = {}
        for advisory in advisories:
            counts[advisory.advisory_status] = (
                counts.get(advisory.advisory_status, 0) + 1
            )
        return counts

    def _profile_update_skip_reason(
        self,
        recommendation: ProfileMapUpdateRecommendation,
        *,
        allow_sampled_row_count_updates: bool,
    ) -> str | None:
        if (
            recommendation.kind == "dataset_row_count_snapshot"
            and recommendation.basis != "full_scan"
            and not allow_sampled_row_count_updates
        ):
            return (
                "Sampled or unknown-scope row-count recommendations are not "
                "staged by default; set allow_sampled_row_count_updates=True "
                "only when the profile scope is the intended durable "
                "population."
            )
        return None

    def _profile_update_revision_anchors(
        self,
        recommendation: ProfileMapUpdateRecommendation,
        *,
        dataset_iri: str,
    ) -> list[str]:
        return list(dict.fromkeys([dataset_iri, recommendation.resource.iri]))

    def _profile_update_staging_review_note(
        self,
        items: list[ProfileMapUpdateStagingItem],
        *,
        staged_indexes: list[int],
        skipped_indexes: list[int],
        status_counts: dict[str, int],
        metric_advisory_count: int,
        metric_advisory_status_counts: dict[str, int],
        type_advisory_count: int,
        type_advisory_status_counts: dict[str, int],
        allow_sampled_row_count_updates: bool,
    ) -> str:
        staged_summary = ", ".join(str(index) for index in staged_indexes) or "none"
        skipped_summary = ", ".join(str(index) for index in skipped_indexes) or "none"
        status_summary = ", ".join(
            f"{status}={count}" for status, count in status_counts.items()
        )
        metric_advisory_summary = self._profile_metric_advisory_review_summary(
            metric_advisory_count,
            metric_advisory_status_counts,
        )
        type_advisory_summary = self._profile_type_advisory_review_summary(
            type_advisory_count,
            type_advisory_status_counts,
        )
        type_followthrough_note = ""
        if type_advisory_status_counts.get(
            "type_finding_unmapped_column",
            0,
        ) and any(
            item.status == "staged" and item.kind == "unmapped_profiled_column"
            for item in items
        ):
            type_followthrough_note = (
                " After applying staged unmapped column shells, rerun "
                "draft_profile_map_updates for the same dataset and evidence "
                "so related profile type advisories can reclassify against "
                "map-present columns."
            )
        evidence_summary = "; ".join(
            (
                f"{item.recommendation_index}:{item.kind}:"
                f"{item.status}:basis={item.basis}:confidence={item.confidence}"
            )
            for item in items
        )
        return (
            "Generated by stage_profile_map_updates. Staged recommendation "
            f"indexes: {staged_summary}. Skipped accepted indexes: "
            f"{skipped_summary}. Status counts: {status_summary}. "
            "allow_sampled_row_count_updates="
            f"{allow_sampled_row_count_updates}. Review sample scope, evidence, "
            "caveats, and project modelling intent before applying. "
            "Metric vocabulary advisories (review separately; not staged as map "
            f"patches): {metric_advisory_summary}. Profile type advisories "
            "(review separately; not staged as map patches): "
            f"{type_advisory_summary}.{type_followthrough_note} "
            f"Items: {evidence_summary}"
        )

    @staticmethod
    def _profile_metric_advisory_review_summary(
        advisory_count: int,
        status_counts: dict[str, int],
    ) -> str:
        if advisory_count == 0:
            return "none"
        status_summary = ", ".join(
            f"{status}={count}" for status, count in status_counts.items()
        )
        return f"{advisory_count} ({status_summary})"

    @staticmethod
    def _profile_type_advisory_review_summary(
        advisory_count: int,
        status_counts: dict[str, int],
    ) -> str:
        if advisory_count == 0:
            return "none"
        status_summary = ", ".join(
            f"{status}={count}" for status, count in status_counts.items()
        )
        return f"{advisory_count} ({status_summary})"

    def _add_profile_update_patch_triples(
        self,
        recommendation: ProfileMapUpdateRecommendation,
        *,
        dataset_iri: str,
        map_dataset_found: bool,
        additions_graph: Graph,
        removals_graph: Graph,
    ) -> None:
        if recommendation.kind == "dataset_row_count_snapshot":
            if not isinstance(recommendation.observed_value, int):
                raise DoxaBaseError(
                    "dataset_row_count_snapshot recommendations require an "
                    "integer observed value"
                )
            subject = URIRef(dataset_iri)
            if map_dataset_found:
                self._add_profile_update_current_triples_to_graph(
                    removals_graph,
                    subject=dataset_iri,
                    predicate="rc:rowCountSnapshot",
                )
            else:
                additions_graph.add(
                    (
                        subject,
                        RDF.type,
                        URIRef(self.expand_iri("rc:Dataset")),
                    )
                )
            additions_graph.add(
                (
                    subject,
                    URIRef(self.expand_iri("rc:rowCountSnapshot")),
                    Literal(recommendation.observed_value, datatype=XSD.integer),
                )
            )
            return

        if recommendation.kind == "column_nullable":
            if not isinstance(recommendation.observed_value, bool):
                raise DoxaBaseError(
                    "column_nullable recommendations require a boolean observed value"
                )
            self._add_profile_update_current_triples_to_graph(
                removals_graph,
                subject=recommendation.resource.iri,
                predicate="rc:nullable",
            )
            additions_graph.add(
                (
                    URIRef(recommendation.resource.iri),
                    URIRef(self.expand_iri("rc:nullable")),
                    Literal(recommendation.observed_value, datatype=XSD.boolean),
                )
            )
            return

        if recommendation.kind == "unmapped_profiled_column":
            column_name = str(recommendation.observed_value).strip()
            if not column_name:
                raise DoxaBaseError(
                    "unmapped_profiled_column recommendations require a column name"
                )
            dataset_ref = URIRef(dataset_iri)
            column_ref = URIRef(recommendation.resource.iri)
            if not map_dataset_found:
                additions_graph.add(
                    (
                        dataset_ref,
                        RDF.type,
                        URIRef(self.expand_iri("rc:Dataset")),
                    )
                )
            additions_graph.add(
                (
                    column_ref,
                    RDF.type,
                    URIRef(self.expand_iri("rc:Column")),
                )
            )
            additions_graph.add(
                (
                    column_ref,
                    URIRef(self.expand_iri("rc:columnName")),
                    Literal(column_name),
                )
            )
            additions_graph.add(
                (
                    dataset_ref,
                    URIRef(self.expand_iri("rc:hasColumn")),
                    column_ref,
                )
            )
            return

        raise DoxaBaseError(
            f"Unsupported profile map update recommendation kind: {recommendation.kind}"
        )

    def _add_profile_update_current_triples_to_graph(
        self,
        target_graph: Graph,
        *,
        subject: str,
        predicate: str,
    ) -> None:
        for triple in self._assertion_triples(
            ["map"],
            subject=self.expand_iri(subject),
            predicate=self.expand_iri(predicate),
            object_filter=None,
            limit=1000,
        ):
            target_graph.add(
                (
                    self._subject_node_from_resource_triple(triple),
                    URIRef(triple.predicate),
                    self._object_node_from_resource_triple(triple),
                )
            )

    def describe_query_context(
        self,
        iri: str,
        graph: str | None = "map",
    ) -> QueryPlanningContext:
        dataset = self.describe_dataset(iri, graph=graph)
        data_graphs = self._expand_graphs([graph] if graph else None)
        dataset_summary = ResourceSummary(
            iri=dataset.iri,
            label=dataset.label or self._local_name(dataset.iri),
            description=dataset.description,
        )
        if not self._dataset_description_is_table(dataset):
            return self._non_tabular_query_context(dataset, dataset_summary)
        direct_path_templates = self._objects(data_graphs, dataset.iri, "rc:pathTemplate")
        issues = self._sort_query_planning_issues(
            [
                *dataset.operational_warnings,
                *self._query_target_candidate_metadata_issues(
                    dataset,
                    dataset_summary=dataset_summary,
                    direct_path_templates=direct_path_templates,
                ),
            ]
        )
        analysis_warnings = self._query_analysis_warnings(dataset)
        readiness = self._query_planning_readiness(issues)
        query_target_candidates = self._query_target_candidates(
            dataset,
            dataset_summary=dataset_summary,
            direct_path_templates=direct_path_templates,
            issues=issues,
        )
        query_target_decision = self._query_target_decision(query_target_candidates)
        ready_candidate_indexes = self._query_ready_candidate_indexes(
            query_target_candidates
        )
        issues = self._query_context_repair_hinted_issues(
            issues,
            dataset=dataset,
            decision=query_target_decision,
            candidates=query_target_candidates,
        )
        suggested_repair_action_groups = self._query_repair_action_groups(issues)
        unselected_ready_candidate_indexes = [
            index
            for index in ready_candidate_indexes
            if index != query_target_decision.candidate_index
        ]
        direct_clean_candidate_indexes = self._query_direct_clean_candidate_indexes(
            query_target_candidates
        )
        unselected_direct_clean_candidate_indexes = [
            index
            for index in direct_clean_candidate_indexes
            if index != query_target_decision.candidate_index
        ]
        suggested_next_actions = self._query_context_next_actions(
            dataset_iri=dataset.iri,
            graph=graph,
            readiness=readiness,
            issues=issues,
            profile_summary=dataset.profile_summary,
            decision=query_target_decision,
            candidates=query_target_candidates,
            unselected_ready_candidate_indexes=unselected_ready_candidate_indexes,
            unselected_direct_clean_candidate_indexes=(
                unselected_direct_clean_candidate_indexes
            ),
        )
        return QueryPlanningContext(
            dataset=dataset_summary,
            readiness=readiness,
            readiness_note=self._query_readiness_note(
                readiness,
                issues=issues,
                analysis_warnings=analysis_warnings,
            ),
            issues=issues,
            analysis_warnings=analysis_warnings,
            suggested_repair_action_groups=suggested_repair_action_groups,
            suggested_repair_action_group_count=len(suggested_repair_action_groups),
            planning_notes=[
                (
                    "DoxaBase records non-secret planning metadata only; local "
                    "runtime configuration must resolve endpoint profiles, "
                    "credential references, and actual query execution."
                ),
                (
                    "Read caveats and verification notes before generating or "
                    "running a query, and record query results or failures as "
                    "evidence-backed observations."
                ),
            ],
            row_count_snapshot=dataset.row_count_snapshot,
            profile_summary=dataset.profile_summary,
            layout_verification_status=dataset.layout_verification_status,
            layout_verification_note=dataset.layout_verification_note,
            columns=dataset.columns,
            path_templates=dataset.path_templates,
            query_target_decision=query_target_decision,
            query_target_candidates=query_target_candidates,
            ready_candidate_indexes=ready_candidate_indexes,
            unselected_ready_candidate_indexes=unselected_ready_candidate_indexes,
            direct_clean_candidate_indexes=direct_clean_candidate_indexes,
            unselected_direct_clean_candidate_indexes=(
                unselected_direct_clean_candidate_indexes
            ),
            physical_layouts=dataset.physical_layouts,
            storage_accesses=dataset.storage_accesses,
            partition_schemes=dataset.partition_schemes,
            caveats=dataset.caveats,
            upstream_caveats=dataset.upstream_caveats,
            suggested_next_actions=suggested_next_actions,
            suggested_next_calls=[
                action.call for action in suggested_next_actions
            ],
        )

    def _non_tabular_query_context(
        self,
        dataset: DatasetDescription,
        dataset_summary: ResourceSummary,
    ) -> QueryPlanningContext:
        issue = QueryPlanningIssue(
            code="non_tabular_asset_query_not_applicable",
            severity="info",
            message=(
                "This map dataset is not typed as rc:Table, so DoxaBase will "
                "not treat it as a table query-planning target."
            ),
            resource=dataset_summary,
            details={
                "dataset_iri": dataset.iri,
                "is_table": False,
                "suggested_profile": "deep_lore",
                "query_readiness": "not_applicable_non_tabular_asset",
            },
        )
        suggested_next_actions = [
            self._project_brief_describe_context_slice_action(dataset.iri)
        ]
        return QueryPlanningContext(
            dataset=dataset_summary,
            readiness="not_applicable_non_tabular_asset",
            readiness_note=(
                "This map dataset is not typed as rc:Table; use resource or "
                "context-slice handoffs unless an explicit queryable table "
                "route is modeled."
            ),
            issues=[issue],
            analysis_warnings=[],
            suggested_repair_action_groups=[],
            suggested_repair_action_group_count=0,
            planning_notes=[
                (
                    "DoxaBase does not draft table query plans for map assets "
                    "that are not typed as rc:Table."
                ),
                (
                    "Use describe_context_slice or describe_resource to inspect "
                    "non-tabular map context, caveats, observations, patterns, "
                    "and evidence."
                ),
            ],
            row_count_snapshot=dataset.row_count_snapshot,
            profile_summary=dataset.profile_summary,
            layout_verification_status=dataset.layout_verification_status,
            layout_verification_note=dataset.layout_verification_note,
            columns=dataset.columns,
            path_templates=dataset.path_templates,
            query_target_decision=QueryTargetDecision(
                status="not_applicable_non_tabular_asset",
                summary=(
                    "Dataset is not typed as rc:Table; no query target "
                    "candidate is selected."
                ),
                candidate_index=None,
                candidate_path=None,
                candidate_path_status=None,
                direct_review_required=None,
                selected_candidate_direct_clean=None,
                reason_codes=[issue.code],
            ),
            query_target_candidates=[],
            ready_candidate_indexes=[],
            unselected_ready_candidate_indexes=[],
            direct_clean_candidate_indexes=[],
            unselected_direct_clean_candidate_indexes=[],
            physical_layouts=dataset.physical_layouts,
            storage_accesses=dataset.storage_accesses,
            partition_schemes=dataset.partition_schemes,
            caveats=dataset.caveats,
            upstream_caveats=dataset.upstream_caveats,
            suggested_next_actions=suggested_next_actions,
            suggested_next_calls=[
                action.call for action in suggested_next_actions
            ],
        )

    def _query_repair_action_groups(
        self,
        issues: list[QueryPlanningIssue],
    ) -> list[QueryRepairActionGroup]:
        groups: list[QueryRepairActionGroup] = []
        for issue_index, issue in enumerate(issues):
            if issue.details is None:
                continue
            repair_hint = issue.details.get("repair_hint")
            if not isinstance(repair_hint, MappingABC):
                continue
            actions = repair_hint.get("actions")
            if not isinstance(actions, list) or not actions:
                continue
            repair_context = {
                str(key): copy.deepcopy(value)
                for key, value in repair_hint.items()
                if key != "actions"
            }
            action_type = repair_hint.get("action_type")
            (
                action_status_counts,
                pending_action_count,
                skippable_action_count,
                already_satisfied_action_count,
                pending_required_extra_arguments,
            ) = self._query_repair_action_group_summary(actions)
            groups.append(
                QueryRepairActionGroup(
                    group_name="query_repair_review",
                    issue_index=issue_index,
                    issue_code=issue.code,
                    issue_severity=issue.severity,
                    issue_message=issue.message,
                    issue_resource=issue.resource,
                    repair_hint_path=f"issues[{issue_index}].details.repair_hint",
                    repair_action_type=(
                        str(action_type) if action_type is not None else None
                    ),
                    requires_review=repair_hint.get("requires_review") is not False,
                    repair_context=repair_context,
                    actions=copy.deepcopy(actions),
                    action_count=len(actions),
                    action_status_counts=action_status_counts,
                    pending_action_count=pending_action_count,
                    skippable_action_count=skippable_action_count,
                    already_satisfied_action_count=(
                        already_satisfied_action_count
                    ),
                    pending_required_extra_arguments=(
                        pending_required_extra_arguments
                    ),
                )
            )
        return groups

    def _query_context_repair_hinted_issues(
        self,
        issues: list[QueryPlanningIssue],
        *,
        dataset: DatasetDescription,
        decision: QueryTargetDecision,
        candidates: list[QueryTargetCandidate],
    ) -> list[QueryPlanningIssue]:
        if (
            decision.status != "context_blocked"
            or decision.candidate_index is None
            or decision.selected_candidate_direct_clean is not True
            or decision.candidate_index >= len(candidates)
        ):
            return issues
        selected_candidate = candidates[decision.candidate_index]
        blocker_iris = self._query_context_blocker_resource_iris(
            selected_candidate
        )
        if not blocker_iris:
            return issues
        partitions_by_iri = {
            partition.iri: partition for partition in dataset.partition_schemes
        }
        repair_partitions = [
            partitions_by_iri[iri] for iri in blocker_iris if iri in partitions_by_iri
        ]
        if not repair_partitions:
            return issues

        repair_partition_iris = {partition.iri for partition in repair_partitions}
        updated: list[QueryPlanningIssue] = []
        for issue in issues:
            resource_iri = issue.resource.iri if issue.resource is not None else None
            if (
                issue.code == "layout_needs_verification"
                and resource_iri in repair_partition_iris
            ):
                partition = partitions_by_iri[resource_iri]
                details = copy.deepcopy(issue.details) if issue.details else {}
                details["repair_hint"] = self._query_partition_context_blocker_repair_hint(
                    dataset,
                    partition,
                    decision=decision,
                    selected_candidate=selected_candidate,
                )
                updated.append(
                    QueryPlanningIssue(
                        code=issue.code,
                        severity=issue.severity,
                        message=issue.message,
                        domain=issue.domain,
                        resource=issue.resource,
                        details=details,
                    )
                )
                continue
            updated.append(issue)
        return updated

    @staticmethod
    def _query_context_blocker_resource_iris(
        candidate: QueryTargetCandidate,
    ) -> list[str]:
        blocker_iris: list[str] = []
        for reason in candidate.review_reasons:
            if reason.code != "query_context_has_other_blockers":
                continue
            details = reason.details or {}
            values = details.get("excluded_blocker_resource_iris")
            if not isinstance(values, list):
                continue
            for value in values:
                iri = str(value)
                if iri not in blocker_iris:
                    blocker_iris.append(iri)
        return blocker_iris

    def _query_partition_context_blocker_repair_hint(
        self,
        dataset: DatasetDescription,
        partition: PartitionDescription,
        *,
        decision: QueryTargetDecision,
        selected_candidate: QueryTargetCandidate,
    ) -> dict[str, Any]:
        storage_access_iri = (
            selected_candidate.storage_access.iri
            if selected_candidate.storage_access is not None
            else None
        )
        return {
            "action_type": "remove_stale_partition_scheme_link",
            "requires_review": True,
            "target_dataset_iri": dataset.iri,
            "partition_scheme": {
                "iri": partition.iri,
                "label": partition.label,
                "path_template": partition.path_template,
            },
            "selected_candidate": {
                "candidate_index": decision.candidate_index,
                "candidate_path": selected_candidate.candidate_path,
                "candidate_path_status": selected_candidate.candidate_path_status,
                "template_source": selected_candidate.template_source,
                "source_resource_iri": selected_candidate.source_resource.iri,
                "storage_access_iri": storage_access_iri,
            },
            "actions": [
                {
                    "action_type": "remove_stale_partition_scheme_link",
                    "tool_name": "stage_map_assertion_change",
                    "mcp_tool_name": "doxabase.stage_map_assertion_change",
                    "action_label": "Stage stale partition-scheme removal",
                    "reason": (
                        "Use after review confirms the selected direct-clean "
                        "query target supersedes this partition scheme for the "
                        "dataset."
                    ),
                    "required_extra_arguments": ["rationale"],
                    "rationale_template": (
                        "Reviewed stale partition-scheme link for "
                        f"{dataset.iri}; selected query target "
                        f"{selected_candidate.candidate_path!r} should be the "
                        "planning route."
                    ),
                    "arguments": {
                        "subject": dataset.iri,
                        "predicate": "rc:partitionedBy",
                        "object": partition.iri,
                        "object_kind": "iri",
                        "change_kind": "remove",
                        "graph": "map",
                        "validation_scope": "all",
                    },
                    "condition": (
                        "Only after review confirms this partition scheme is a "
                        "stale blocker for the selected direct-clean candidate, "
                        "not merely an unverified alternate route that should "
                        "remain linked."
                    ),
                }
            ],
        }

    @staticmethod
    def _query_repair_action_group_summary(
        actions: list[Any],
    ) -> tuple[dict[str, int], int, int, int, list[str]]:
        action_status_counts: dict[str, int] = {}
        pending_action_count = 0
        skippable_action_count = 0
        already_satisfied_action_count = 0
        pending_required_extra_arguments: list[str] = []

        for action in actions:
            if not isinstance(action, MappingABC):
                status = "pending_review"
                skippable = False
                required_extra_arguments: list[Any] = []
            else:
                raw_status = action.get("action_status")
                status = str(raw_status) if raw_status else "pending_review"
                skippable = (
                    status == "already_satisfied"
                    and action.get("skip_when_already_satisfied") is True
                )
                required_extra_arguments = action.get("required_extra_arguments")
                if not isinstance(required_extra_arguments, list):
                    required_extra_arguments = []

            action_status_counts[status] = action_status_counts.get(status, 0) + 1
            if status == "already_satisfied":
                already_satisfied_action_count += 1
            if skippable:
                skippable_action_count += 1
                continue

            pending_action_count += 1
            for argument in required_extra_arguments:
                argument_name = str(argument)
                if argument_name not in pending_required_extra_arguments:
                    pending_required_extra_arguments.append(argument_name)

        return (
            action_status_counts,
            pending_action_count,
            skippable_action_count,
            already_satisfied_action_count,
            pending_required_extra_arguments,
        )

    def _query_context_next_actions(
        self,
        *,
        dataset_iri: str,
        graph: str | None,
        readiness: str,
        issues: list[QueryPlanningIssue],
        profile_summary: ProfileSummary,
        decision: QueryTargetDecision,
        candidates: list[QueryTargetCandidate],
        unselected_ready_candidate_indexes: list[int],
        unselected_direct_clean_candidate_indexes: list[int],
    ) -> list[SuggestedNextAction]:
        actions: list[SuggestedNextAction] = []
        if profile_summary.profile_run_candidates:
            profile_candidates = profile_summary.profile_run_candidates
            for candidate_index, candidate_run in enumerate(
                profile_candidates
            ):
                if candidate_index > 0 and not (
                    self._query_context_should_inspect_profile_candidate(
                        profile_candidates[0],
                        candidate_run,
                        profile_candidates,
                    )
                ):
                    continue
                profile_arguments = {
                    "dataset_iri": dataset_iri,
                    "evidence_iri": candidate_run.evidence_iri,
                }
                if candidate_index == 0:
                    action_label = "Inspect profile run evidence"
                    reason = (
                        "Inspect the profile observations behind the selected "
                        "row-count/profile handoff before relying on profiler "
                        "evidence in a query plan."
                    )
                else:
                    action_label = "Inspect additional profile run evidence"
                    reason = (
                        "Multiple profile-run candidates carry different row "
                        "count evidence, or the selected snapshot-matching "
                        "candidate is sampled, unknown, or mixed basis. Inspect "
                        "this additional run before treating a profile-derived "
                        "row count as current."
                    )
                actions.append(
                    SuggestedNextAction(
                        action_label=action_label,
                        tool_name="describe_profile_run",
                        mcp_tool_name="doxabase.describe_profile_run",
                        arguments=profile_arguments,
                        reason=reason,
                        call=self._suggested_call_string(
                            "describe_profile_run",
                            profile_arguments,
                        ),
                    )
                )
        if (
            decision.candidate_index is None
            or decision.candidate_index < 0
            or decision.candidate_index >= len(candidates)
        ):
            return actions
        candidate = candidates[decision.candidate_index]
        arguments: dict[str, Any] = {
            "iri": dataset_iri,
            "candidate_index": decision.candidate_index,
        }
        if graph is not None and graph != "map":
            arguments["graph"] = graph

        action_label = "Draft selected query plan"
        reason = (
            "Draft a non-executed query plan for the selected query target "
            "candidate, then read review_gate, scan, bindings, and issues."
        )
        if (
            readiness != "ready_for_query_planning"
            and candidate.direct_review_required is False
        ):
            arguments["allow_context_blocked_candidate"] = True
            action_label = "Draft direct-clean candidate with context allowance"
            reason = (
                "The selected candidate has no direct warning or error, but "
                "sibling or broader context blockers make the whole context "
                "review-required. Draft it with an explicit selector and "
                "allow_context_blocked_candidate=True while preserving the "
                "context issue audit."
            )
            if unselected_direct_clean_candidate_indexes:
                peers = ", ".join(
                    str(index)
                    for index in unselected_direct_clean_candidate_indexes
                )
                reason = (
                    f"{reason} Other direct-clean candidate indexes exist "
                    f"({peers}); inspect query_target_candidates and rerun "
                    "with an explicit candidate_index if another route is "
                    "intended."
                )
        elif decision.status == "candidate_needs_review":
            action_label = "Draft review-gated query plan"
            reason = (
                "Draft a non-executed review plan for this candidate so the "
                "scan, relation, runtime, and blocking reason fields are "
                "available before repair or execution."
            )
        elif decision.status == "ready":
            action_label = "Draft metadata-ready query plan"
            reason = (
                "Draft the selected query target and inspect bindings, runtime "
                "resolution requirements, and analysis caveats before any "
                "execution attempt."
            )
            if unselected_ready_candidate_indexes:
                peers = ", ".join(
                    str(index) for index in unselected_ready_candidate_indexes
                )
                reason = (
                    f"{reason} Other direct-ready candidate indexes exist "
                    f"({peers}); inspect query_target_candidates and rerun with "
                    "an explicit candidate_index if another route is intended."
                )

        actions.append(
            SuggestedNextAction(
                action_label=action_label,
                tool_name="draft_query_plan",
                mcp_tool_name="doxabase.draft_query_plan",
                arguments=arguments,
                reason=reason,
                call=self._suggested_call_string("draft_query_plan", arguments),
            )
        )
        peer_action_indexes: list[int] = []
        peer_action_allowance = False
        peer_action_needs_context_allowance = (
            readiness != "ready_for_query_planning"
            and candidate.direct_review_required is False
        )
        if decision.status == "ready":
            peer_action_indexes = unselected_ready_candidate_indexes
            peer_action_allowance = peer_action_needs_context_allowance
        elif (
            peer_action_needs_context_allowance
        ):
            peer_action_indexes = unselected_direct_clean_candidate_indexes
            peer_action_allowance = True
        for peer_index in peer_action_indexes:
            if peer_index < 0 or peer_index >= len(candidates):
                continue
            peer_arguments: dict[str, Any] = {
                "iri": dataset_iri,
                "candidate_index": peer_index,
            }
            if graph is not None and graph != "map":
                peer_arguments["graph"] = graph
            peer_candidate = candidates[peer_index]
            if peer_action_allowance and peer_candidate.direct_review_required is False:
                peer_arguments["allow_context_blocked_candidate"] = True
                peer_label = "Draft peer direct-clean candidate with context allowance"
                peer_reason = (
                    "A peer candidate has no direct warning or error, but "
                    "sibling or broader context blockers make the whole context "
                    "review-required. Draft this reviewed peer with an explicit "
                    "candidate_index and allow_context_blocked_candidate=True "
                    "instead of parsing peer indexes from prose."
                )
            else:
                peer_label = "Draft peer metadata-ready query plan"
                peer_reason = (
                    "A peer candidate is also direct-ready. Draft this explicit "
                    "candidate_index when candidate review shows this path or "
                    "relation is the intended handoff."
                )
            actions.append(
                SuggestedNextAction(
                    action_label=peer_label,
                    tool_name="draft_query_plan",
                    mcp_tool_name="doxabase.draft_query_plan",
                    arguments=peer_arguments,
                    reason=peer_reason,
                    call=self._suggested_call_string(
                        "draft_query_plan",
                        peer_arguments,
                    ),
                )
            )
        layout_action_indexes = [
            decision.candidate_index,
            *(
                index
                for index, candidate_item in enumerate(candidates)
                if index != decision.candidate_index
                and self._query_context_candidate_only_layout_blocked(
                    candidate_item
                )
            ),
        ]
        for layout_action_index in layout_action_indexes:
            layout_candidate = candidates[layout_action_index]
            actions.extend(
                self._query_context_physical_layout_selection_actions(
                    dataset_iri=dataset_iri,
                    graph=graph,
                    candidate_index=layout_action_index,
                    candidate=layout_candidate,
                    allow_context_blocked_candidate=(
                        self._query_context_layout_selection_needs_context_allowance(
                            candidate=layout_candidate,
                            issues=issues,
                        )
                    ),
                )
            )
        return actions

    @staticmethod
    def _query_context_should_inspect_profile_candidate(
        primary_candidate: ProfileRunCandidate,
        candidate: ProfileRunCandidate,
        candidates: list[ProfileRunCandidate],
    ) -> bool:
        if candidate.evidence_iri == primary_candidate.evidence_iri:
            return False
        row_count_sets = {
            tuple(candidate_item.dataset_profile_row_counts)
            for candidate_item in candidates
            if candidate_item.dataset_profile_row_counts
        }
        if len(row_count_sets) > 1:
            return True
        return (
            primary_candidate.row_count_snapshot_matches
            and primary_candidate.row_count_snapshot_basis
            in {"mixed", "sample", "unknown"}
        )

    def _query_context_candidate_only_layout_blocked(
        self,
        candidate: QueryTargetCandidate,
    ) -> bool:
        direct_blockers = self._query_target_blocking_reasons(
            candidate.direct_review_reasons
        )
        return bool(direct_blockers) and all(
            reason.code == "ambiguous_physical_layout"
            for reason in direct_blockers
        )

    def _query_context_layout_selection_needs_context_allowance(
        self,
        *,
        candidate: QueryTargetCandidate,
        issues: list[QueryPlanningIssue],
    ) -> bool:
        if not self._query_context_candidate_only_layout_blocked(candidate):
            return False
        remaining_blockers = [
            reason
            for reason in self._query_target_blocking_reasons(issues)
            if reason.code != "ambiguous_physical_layout"
        ]
        if not remaining_blockers:
            return False
        return all(
            self._is_candidate_metadata_issue(reason)
            for reason in remaining_blockers
        )

    def _query_context_physical_layout_selection_actions(
        self,
        *,
        dataset_iri: str,
        graph: str | None,
        candidate_index: int,
        candidate: QueryTargetCandidate,
        allow_context_blocked_candidate: bool,
    ) -> list[SuggestedNextAction]:
        issue = next(
            (
                reason
                for reason in candidate.direct_review_reasons
                if reason.code == "ambiguous_physical_layout"
                and reason.details is not None
            ),
            None,
        )
        if issue is None or issue.details is None:
            return []
        signatures = issue.details.get("layout_signatures")
        if not isinstance(signatures, list):
            return []
        actions: list[SuggestedNextAction] = []
        seen_layout_iris: set[str] = set()
        for signature in signatures:
            if not isinstance(signature, Mapping):
                continue
            layout_iris = signature.get("layout_iris")
            if not isinstance(layout_iris, list):
                continue
            file_format_iri = signature.get("file_format_iri")
            compression_codec_iri = signature.get("compression_codec_iri")
            signature_note_parts: list[str] = []
            if isinstance(file_format_iri, str) and file_format_iri:
                file_format_label = (
                    self._compact_iri(file_format_iri)
                    or self._local_name(file_format_iri)
                    or file_format_iri
                )
                signature_note_parts.append(f"file format {file_format_label}")
            if isinstance(compression_codec_iri, str) and compression_codec_iri:
                compression_label = (
                    self._compact_iri(compression_codec_iri)
                    or self._local_name(compression_codec_iri)
                    or compression_codec_iri
                )
                signature_note_parts.append(f"compression {compression_label}")
            signature_note = (
                " with " + " and ".join(signature_note_parts)
                if signature_note_parts
                else ""
            )
            for layout_iri in layout_iris:
                if not isinstance(layout_iri, str) or not layout_iri:
                    continue
                if layout_iri in seen_layout_iris:
                    continue
                seen_layout_iris.add(layout_iri)
                arguments: dict[str, Any] = {
                    "iri": dataset_iri,
                    "candidate_index": candidate_index,
                    "physical_layout_iri": layout_iri,
                }
                if graph is not None and graph != "map":
                    arguments["graph"] = graph
                allowance_reason = ""
                if allow_context_blocked_candidate:
                    arguments["allow_context_blocked_candidate"] = True
                    allowance_reason = (
                        " Because this candidate's only direct blocker is "
                        "layout ambiguity and the remaining blockers are "
                        "candidate metadata on sibling routes, the action "
                        "includes allow_context_blocked_candidate=True to "
                        "draft the reviewed direct-clean route while keeping "
                        "context audit fields visible."
                    )
                actions.append(
                    SuggestedNextAction(
                        action_label="Select physical layout for draft",
                        tool_name="draft_query_plan",
                        mcp_tool_name="doxabase.draft_query_plan",
                        arguments=arguments,
                        reason=(
                            f"Candidate {candidate_index} is blocked by ambiguous "
                            "physical layout metadata. After reviewing that "
                            f"{layout_iri} is the intended layout"
                            f"{signature_note}, draft the query plan with "
                            "physical_layout_iri so scan.function is inferred "
                            "from an explicit layout choice."
                            f"{allowance_reason}"
                        ),
                        call=self._suggested_call_string(
                            "draft_query_plan",
                            arguments,
                        ),
                    )
                )
        return actions

    def draft_query_plan(
        self,
        iri: str,
        *,
        graph: str | None = "map",
        engine: str = "duckdb",
        candidate_index: int | None = None,
        storage_access_iri: str | None = None,
        physical_layout_iri: str | None = None,
        allow_context_blocked_candidate: bool = False,
    ) -> DraftQueryPlan:
        engine_value = engine.strip().lower()
        if engine_value != "duckdb":
            raise DoxaBaseError("draft_query_plan currently supports engine='duckdb'")
        context = self.describe_query_context(iri=iri, graph=graph)
        if context.readiness == "not_applicable_non_tabular_asset":
            return self._non_tabular_draft_query_plan(
                context,
                engine=engine_value,
                candidate_index=candidate_index,
                storage_access_iri=storage_access_iri,
                physical_layout_iri=physical_layout_iri,
                allow_context_blocked_candidate=allow_context_blocked_candidate,
            )
        selected_physical_layout, requested_physical_layout_iri = (
            self._draft_query_plan_selected_physical_layout(
                context,
                physical_layout_iri=physical_layout_iri,
            )
        )
        physical_layout_selected = requested_physical_layout_iri is not None
        effective_issues = self._draft_query_plan_effective_issues(
            context.issues,
            physical_layout_selected=physical_layout_selected,
        )
        (
            selected_candidate_index,
            selected_candidate,
            selection_mode,
            selection_status,
            selection_note,
            requested_storage_access_iri,
        ) = self._draft_query_plan_select_candidate(
            context,
            candidate_index=candidate_index,
            storage_access_iri=storage_access_iri,
            physical_layout_selected=physical_layout_selected,
        )
        selected_candidate = self._draft_query_plan_effective_layout_candidate(
            selected_candidate,
            physical_layout_selected=physical_layout_selected,
        )
        original_selected_candidate = selected_candidate
        (
            selected_candidate,
            context_blocked_candidate_used,
            context_blocking_reasons,
        ) = self._draft_query_plan_effective_candidate(
            context,
            selected_candidate,
            issues=effective_issues,
            selection_mode=selection_mode,
            allow_context_blocked_candidate=allow_context_blocked_candidate,
        )
        selected_decision = self._draft_query_plan_selected_decision(
            context,
            selected_candidate,
            selected_candidate_index=selected_candidate_index,
            selection_mode=selection_mode,
            selection_overridden=(
                selection_mode != "automatic" or physical_layout_selected
            ),
            context_blocked_candidate_used=context_blocked_candidate_used,
        )
        storage_access = self._draft_query_plan_storage_access(
            context,
            selected_candidate,
        )
        binding_requirements = self._draft_query_plan_binding_requirements(
            selected_candidate,
            columns=context.columns,
            partition_schemes=context.partition_schemes,
        )
        scan = self._draft_query_plan_scan(
            selected_candidate,
            dataset_verification_status=context.layout_verification_status,
            dataset_verification_note=context.layout_verification_note,
            partition_schemes=context.partition_schemes,
            physical_layouts=context.physical_layouts,
            selected_physical_layout=selected_physical_layout,
            physical_layout_selected=physical_layout_selected,
            storage_accesses=context.storage_accesses,
            engine=engine_value,
        )
        storage_environment = self._draft_query_plan_storage_environment(
            selected_candidate,
            storage_access,
            engine=engine_value,
        )
        review_gate = self._draft_query_plan_review_gate(
            context,
            selected_candidate,
            original_selected_candidate=original_selected_candidate,
            selected_decision=selected_decision,
            scan=scan,
            issues=effective_issues,
            storage_environment=storage_environment,
            binding_requirements=binding_requirements,
            selection_overridden=(
                selection_mode != "automatic" or physical_layout_selected
            ),
            allow_context_blocked_candidate=allow_context_blocked_candidate,
            context_blocked_candidate_used=context_blocked_candidate_used,
            context_blocking_reasons=context_blocking_reasons,
        )
        scan = replace(
            scan,
            execution_attempt_ready=review_gate.ready_for_execution_attempt,
            primary_execution_attempt_blocking_reason_code=(
                review_gate.primary_execution_attempt_blocking_reason_code
            ),
            execution_attempt_blocking_reason_codes=list(
                review_gate.execution_attempt_blocking_reason_codes
            ),
        )
        handoff_kind = self._draft_query_plan_handoff_kind(
            selected_candidate,
            scan=scan,
            binding_requirements=binding_requirements,
            storage_environment=storage_environment,
            review_gate=review_gate,
        )
        ready_candidate_indexes = self._query_ready_candidate_indexes(
            context.query_target_candidates
        )
        direct_clean_candidate_indexes = self._query_direct_clean_candidate_indexes(
            context.query_target_candidates
        )
        return DraftQueryPlan(
            helper="draft_query_plan",
            mode="non_executed_review_draft",
            handoff_kind=handoff_kind,
            engine=DraftQueryPlanEngine(
                name=engine_value,
                source="caller_requested_target_engine",
            ),
            dataset=context.dataset,
            source_context=DraftQueryPlanSourceContext(
                api="DoxaBase.describe_query_context",
                readiness=context.readiness,
                readiness_note=context.readiness_note,
                query_target_decision=context.query_target_decision,
                selected_candidate_index=selected_candidate_index,
                candidate_count=len(context.query_target_candidates),
                ready_candidate_indexes=ready_candidate_indexes,
                unselected_ready_candidate_indexes=[
                    index
                    for index in ready_candidate_indexes
                    if index != selected_candidate_index
                ],
                direct_clean_candidate_indexes=direct_clean_candidate_indexes,
                unselected_direct_clean_candidate_indexes=[
                    index
                    for index in direct_clean_candidate_indexes
                    if index != selected_candidate_index
                ],
                selection_mode=selection_mode,
                requested_candidate_index=candidate_index,
                requested_storage_access_iri=requested_storage_access_iri,
                requested_physical_layout_iri=requested_physical_layout_iri,
                selection_status=selection_status,
                selection_note=selection_note,
                selected_candidate_note=(
                    self._draft_query_plan_selected_candidate_note(
                        selected_candidate,
                        selected_candidate_index,
                        handoff_kind=handoff_kind,
                        review_gate=review_gate,
                        context_blocking_reasons=context_blocking_reasons,
                    )
                ),
                allow_context_blocked_candidate=allow_context_blocked_candidate,
            ),
            selected_candidate=selected_candidate,
            scan=scan,
            required_bindings=[binding.name for binding in binding_requirements],
            binding_requirements=binding_requirements,
            binding_note=(
                "Bindings are placeholder names parsed from the selected path "
                "template. When a selected partition template has matching "
                "partition metadata, binding rows include the likely partition "
                "column and granularity. Non-partition templates may carry "
                "best-effort candidate column matches by placeholder name; "
                "DoxaBase still does not infer execution-time values."
            ),
            storage_environment=storage_environment,
            review_gate=review_gate,
            issues=effective_issues,
            analysis_warnings=context.analysis_warnings,
            caveats=context.caveats,
            upstream_caveats=context.upstream_caveats,
            planning_notes=[
                *context.planning_notes,
                (
                    "This draft is not executable code and does not resolve "
                    "endpoint profiles, credentials, object existence, or "
                    "runtime settings."
                ),
            ],
        )

    def _non_tabular_draft_query_plan(
        self,
        context: QueryPlanningContext,
        *,
        engine: str,
        candidate_index: int | None,
        storage_access_iri: str | None,
        physical_layout_iri: str | None,
        allow_context_blocked_candidate: bool,
    ) -> DraftQueryPlan:
        reason_code = "non_tabular_asset_query_not_applicable"
        scan = DraftQueryPlanScan(
            function=None,
            uri_template=None,
            relation_identifier=None,
            connection_reference=None,
            file_format=None,
            compression=None,
            candidate_path_status=None,
            dataset_verification_status=context.layout_verification_status,
            dataset_verification_note=context.layout_verification_note,
            template=None,
            template_source=None,
            template_source_resource=None,
            template_source_verification_status=None,
            template_source_verification_note=None,
            template_lineage=None,
            composition=None,
            physical_layout=None,
            physical_layout_selection_note=None,
            non_executed_note=(
                "No scan is drafted because the dataset is not typed as "
                "rc:Table."
            ),
            execution_attempt_ready=False,
            primary_execution_attempt_blocking_reason_code=reason_code,
            execution_attempt_blocking_reason_codes=[reason_code],
        )
        storage_environment = DraftQueryPlanStorageEnvironment(
            storage_protocol=None,
            storage_root=None,
            bucket_name=None,
            key_prefix=None,
            region=None,
            endpoint_profile=None,
            credential_reference=None,
            access_mode=None,
            path_style_access=None,
            requires_endpoint_profile=False,
            runtime_resolution_required=False,
            duckdb_settings_from_context=[],
            runtime_resolution_note=(
                "No runtime storage environment is drafted for a non-tabular "
                "asset."
            ),
        )
        review_gate = DraftQueryPlanReviewGate(
            executable_without_review=False,
            runtime_resolution_required=False,
            binding_values_required=False,
            ready_for_execution_attempt=False,
            status="not_applicable_non_tabular_asset",
            direct_review_required=None,
            candidate_path_status=None,
            blocking_reason_codes=[reason_code],
            execution_attempt_blocking_reason_codes=[reason_code],
            primary_execution_attempt_blocking_reason_code=reason_code,
            all_issue_codes=self._query_issue_codes(context.issues),
            reason_codes=[reason_code],
            review_note=(
                "DoxaBase does not draft table query plans for map assets that "
                "are not typed as rc:Table. Inspect the asset with resource or "
                "context-slice handoffs instead."
            ),
            selection_overridden=(
                candidate_index is not None
                or storage_access_iri is not None
                or physical_layout_iri is not None
            ),
            context_blocked_candidate_allowed=allow_context_blocked_candidate,
            context_blocked_candidate_used=False,
            direct_blocking_reason_codes=[reason_code],
            context_blocking_reason_codes=[],
        )
        return DraftQueryPlan(
            helper="draft_query_plan",
            mode="non_executed_review_draft",
            handoff_kind="not_applicable_non_tabular_asset",
            engine=DraftQueryPlanEngine(
                name=engine,
                source="caller_requested_target_engine",
            ),
            dataset=context.dataset,
            source_context=DraftQueryPlanSourceContext(
                api="DoxaBase.describe_query_context",
                readiness=context.readiness,
                readiness_note=context.readiness_note,
                query_target_decision=context.query_target_decision,
                selected_candidate_index=None,
                candidate_count=0,
                ready_candidate_indexes=[],
                unselected_ready_candidate_indexes=[],
                direct_clean_candidate_indexes=[],
                unselected_direct_clean_candidate_indexes=[],
                selection_mode="not_applicable",
                requested_candidate_index=candidate_index,
                requested_storage_access_iri=storage_access_iri,
                requested_physical_layout_iri=physical_layout_iri,
                selection_status="not_applicable_non_tabular_asset",
                selection_note=(
                    "Candidate selection is not applicable because the dataset "
                    "is not typed as rc:Table."
                ),
                selected_candidate_note=(
                    "No query target candidate is selected for a non-tabular "
                    "asset."
                ),
                allow_context_blocked_candidate=allow_context_blocked_candidate,
            ),
            selected_candidate=None,
            scan=scan,
            required_bindings=[],
            binding_requirements=[],
            binding_note=(
                "No path-template bindings are inferred because no table query "
                "plan is drafted for this non-tabular asset."
            ),
            storage_environment=storage_environment,
            review_gate=review_gate,
            issues=context.issues,
            analysis_warnings=context.analysis_warnings,
            caveats=context.caveats,
            upstream_caveats=context.upstream_caveats,
            planning_notes=[
                *context.planning_notes,
                (
                    "This draft is intentionally not a query handoff. Model an "
                    "explicit table/queryable relation first if query planning "
                    "is genuinely intended."
                ),
            ],
        )

    @staticmethod
    def _query_ready_candidate_indexes(
        candidates: list[QueryTargetCandidate],
    ) -> list[int]:
        return [
            index
            for index, candidate in enumerate(candidates)
            if candidate.candidate_path_status == "ready"
            and not candidate.direct_review_required
        ]

    @staticmethod
    def _query_direct_clean_candidate_indexes(
        candidates: list[QueryTargetCandidate],
    ) -> list[int]:
        return [
            index
            for index, candidate in enumerate(candidates)
            if not candidate.direct_review_required
        ]

    def _draft_query_plan_select_candidate(
        self,
        context: QueryPlanningContext,
        *,
        candidate_index: int | None,
        storage_access_iri: str | None,
        physical_layout_selected: bool = False,
    ) -> tuple[int | None, QueryTargetCandidate | None, str, str, str, str | None]:
        if candidate_index is not None and storage_access_iri is not None:
            raise DoxaBaseError(
                "Pass either candidate_index or storage_access_iri, not both."
            )

        if candidate_index is not None:
            if candidate_index < 0 or candidate_index >= len(
                context.query_target_candidates
            ):
                raise DoxaBaseError(
                    "candidate_index must point into query_target_candidates; "
                    f"got {candidate_index} for "
                    f"{len(context.query_target_candidates)} candidate(s)."
                )
            return (
                candidate_index,
                context.query_target_candidates[candidate_index],
                "candidate_index",
                "matched",
                f"Caller selected candidate {candidate_index} by candidate_index.",
                None,
            )

        if storage_access_iri is not None:
            storage_access_value = self._required_iri(
                "storage_access_iri",
                storage_access_iri,
            )
            matches = [
                (index, candidate)
                for index, candidate in enumerate(context.query_target_candidates)
                if candidate.storage_access is not None
                and candidate.storage_access.iri == storage_access_value
            ]
            if not matches:
                raise DoxaBaseError(
                    "storage_access_iri did not match any query target "
                    f"candidate: {storage_access_value}"
                )
            if len(matches) > 1:
                indexes = ", ".join(str(index) for index, _candidate in matches)
                snippets = "; ".join(
                    self._draft_query_plan_candidate_selection_snippet(
                        index,
                        candidate,
                    )
                    for index, candidate in matches
                )
                layout_note = (
                    " physical_layout_iri was matched, but storage_access_iri "
                    "still identifies multiple query target candidates; pass "
                    "candidate_index for the exact path/relation."
                    if physical_layout_selected
                    else ""
                )
                raise DoxaBaseError(
                    "storage_access_iri matched multiple query target candidates "
                    f"({indexes}): {snippets}. Pass candidate_index for an "
                    f"exact selection.{layout_note}"
                )
            selected_index, selected_candidate = matches[0]
            return (
                selected_index,
                selected_candidate,
                "storage_access_iri",
                "matched",
                (
                    "Caller selected storage_access_iri "
                    f"{storage_access_value}, matching candidate {selected_index}."
                ),
                storage_access_value,
            )

        decision = context.query_target_decision
        if (
            decision.candidate_index is not None
            and 0 <= decision.candidate_index < len(context.query_target_candidates)
        ):
            return (
                decision.candidate_index,
                context.query_target_candidates[decision.candidate_index],
                "automatic",
                "automatic",
                (
                    "Automatic query_target_decision selected candidate "
                    f"{decision.candidate_index}."
                ),
                None,
            )
        return (
            None,
            None,
            "automatic",
            "automatic",
            "Automatic query_target_decision did not select a candidate.",
            None,
        )

    def _draft_query_plan_candidate_selection_snippet(
        self,
        index: int,
        candidate: QueryTargetCandidate,
    ) -> str:
        source_label = candidate.source_resource.label or self._local_name(
            candidate.source_resource.iri
        )
        storage_label = None
        if candidate.storage_access is not None:
            storage_label = candidate.storage_access.label or self._local_name(
                candidate.storage_access.iri
            )
        parts = [
            f"candidate {index}",
            f"template_source={candidate.template_source}",
            f"source={source_label!r}",
            f"status={candidate.candidate_path_status}",
        ]
        if candidate.candidate_path is not None:
            parts.append(f"candidate_path={candidate.candidate_path!r}")
        if candidate.relation_identifier is not None:
            parts.append(f"relation_identifier={candidate.relation_identifier!r}")
        if candidate.connection_reference is not None:
            parts.append(f"connection_reference={candidate.connection_reference!r}")
        if candidate.template is not None:
            parts.append(f"template={candidate.template!r}")
        if storage_label is not None:
            parts.append(f"storage={storage_label!r}")
        return " ".join(parts)

    def _draft_query_plan_effective_candidate(
        self,
        context: QueryPlanningContext,
        selected_candidate: QueryTargetCandidate | None,
        *,
        issues: list[QueryPlanningIssue],
        selection_mode: str,
        allow_context_blocked_candidate: bool,
    ) -> tuple[QueryTargetCandidate | None, bool, list[QueryPlanningIssue]]:
        if selected_candidate is None:
            return None, False, []
        context_blockers = self._query_target_context_blocking_reasons(
            selected_candidate.review_reasons
        )
        sibling_metadata_blockers = (
            self._draft_query_plan_sibling_candidate_metadata_context_blockers(
                context,
                selected_candidate,
                issues=issues,
            )
        )
        context_blocking_reasons = list(context_blockers)
        if not context_blocking_reasons and sibling_metadata_blockers:
            context_blocking_reasons = [
                self._draft_query_plan_sibling_context_blocker_issue(
                    context,
                    sibling_metadata_blockers,
                )
            ]
        if (
            not allow_context_blocked_candidate
            or selected_candidate.direct_review_required
            or selection_mode == "automatic"
        ):
            return selected_candidate, False, context_blocking_reasons

        if context_blockers:
            direct_review_reasons = list(selected_candidate.direct_review_reasons)
            direct_review_required = any(
                reason.severity in {"error", "warning"}
                for reason in direct_review_reasons
            )
            review_required = direct_review_required
            return (
                replace(
                    selected_candidate,
                    review_required=review_required,
                    review_reasons=direct_review_reasons,
                    direct_review_required=direct_review_required,
                    candidate_path_status=self._query_candidate_path_status(
                        selected_candidate.candidate_path,
                        review_required=review_required,
                        review_reasons=direct_review_reasons,
                    ),
                ),
                True,
                context_blocking_reasons,
            )

        if selection_mode != "automatic" and sibling_metadata_blockers:
            return selected_candidate, True, context_blocking_reasons

        return selected_candidate, False, context_blocking_reasons

    def _draft_query_plan_sibling_candidate_metadata_context_blockers(
        self,
        context: QueryPlanningContext,
        selected_candidate: QueryTargetCandidate,
        *,
        issues: list[QueryPlanningIssue],
    ) -> list[QueryPlanningIssue]:
        if (
            context.readiness == "ready_for_query_planning"
            or selected_candidate.direct_review_required
            or selected_candidate.candidate_path_status != "ready"
        ):
            return []
        blockers = self._query_target_blocking_reasons(issues)
        if not blockers or not all(
            self._is_candidate_metadata_issue(issue) for issue in blockers
        ):
            return []
        return blockers

    def _draft_query_plan_sibling_context_blocker_issue(
        self,
        context: QueryPlanningContext,
        blockers: list[QueryPlanningIssue],
    ) -> QueryPlanningIssue:
        resource_iris = [
            issue.resource.iri
            for issue in blockers
            if issue.resource is not None
        ]
        return QueryPlanningIssue(
            code="query_context_has_other_blockers",
            severity=(
                "error"
                if any(issue.severity == "error" for issue in blockers)
                else "warning"
            ),
            message=(
                "Overall query context has candidate-metadata blocker(s) on "
                "other query target candidates; inspect context.issues before "
                "executing this candidate."
            ),
            resource=context.dataset,
            details={
                "excluded_blocker_count": len(blockers),
                "excluded_blocker_codes": self._query_issue_codes(blockers),
                "excluded_blocker_resource_iris": list(dict.fromkeys(resource_iris)),
            },
        )

    def _draft_query_plan_selected_decision(
        self,
        context: QueryPlanningContext,
        selected_candidate: QueryTargetCandidate | None,
        *,
        selected_candidate_index: int | None,
        selection_mode: str,
        selection_overridden: bool,
        context_blocked_candidate_used: bool,
    ) -> QueryTargetDecision:
        if (
            selection_mode == "automatic"
            and not selection_overridden
            and not context_blocked_candidate_used
        ):
            return context.query_target_decision
        if selected_candidate is None or selected_candidate_index is None:
            return QueryTargetDecision(
                status="no_candidate",
                summary=(
                    "No query target candidate is available for this "
                    "draft_query_plan call."
                ),
                candidate_index=None,
                candidate_path=None,
                candidate_path_status=None,
                direct_review_required=None,
                selected_candidate_direct_clean=None,
                reason_codes=[],
            )

        if (
            selected_candidate.candidate_path_status == "ready"
            and not selected_candidate.review_required
        ):
            status = "ready"
            state_summary = "is ready for query planning"
        elif (
            selected_candidate.review_required
            and not selected_candidate.direct_review_required
        ):
            status = "context_blocked"
            state_summary = (
                "has no direct warning or error, but broader context has "
                "blockers"
            )
        else:
            status = "candidate_needs_review"
            state_summary = "needs review before executable query use"

        selector_summary = (
            "Automatic selection"
            if selection_mode == "automatic"
            else f"Explicit {selection_mode} selection"
        )
        if context_blocked_candidate_used:
            state_summary = (
                "is treated as direct-clean for this draft because "
                "allow_context_blocked_candidate=True ignored sibling-only "
                "context blockers"
            )
        return self._query_target_decision_for_candidate(
            selected_candidate,
            index=selected_candidate_index,
            status=status,
            summary=(
                f"{selector_summary} chose candidate {selected_candidate_index}, "
                f"which {state_summary}."
            ),
        )

    @staticmethod
    def _draft_query_plan_handoff_kind(
        selected_candidate: QueryTargetCandidate | None,
        *,
        scan: DraftQueryPlanScan,
        binding_requirements: list[DraftQueryPlanBinding],
        storage_environment: DraftQueryPlanStorageEnvironment,
        review_gate: DraftQueryPlanReviewGate,
    ) -> str:
        if selected_candidate is None:
            return "no_query_target"

        blocking_reason_codes = set(review_gate.blocking_reason_codes)
        if (
            "scan_function_not_inferred" in blocking_reason_codes
            and scan.relation_identifier is not None
        ):
            return "database_relation_handoff"
        if (
            "query_context_has_other_blockers" in blocking_reason_codes
            and review_gate.direct_review_required is False
        ):
            return "context_review_required"
        if "s3_access_resolution_unrecorded" in blocking_reason_codes:
            return "runtime_resolution_required"
        if not review_gate.executable_without_review:
            return "metadata_review_required"
        if storage_environment.runtime_resolution_required:
            return "runtime_resolution_required"
        if any(binding.required for binding in binding_requirements):
            return "binding_values_required"
        if review_gate.ready_for_execution_attempt:
            return "execution_attempt_ready"
        return "metadata_review_required"

    @staticmethod
    def _draft_query_plan_selected_candidate_note(
        selected_candidate: QueryTargetCandidate | None,
        selected_candidate_index: int | None,
        *,
        handoff_kind: str,
        review_gate: DraftQueryPlanReviewGate,
        context_blocking_reasons: list[QueryPlanningIssue],
    ) -> str:
        if selected_candidate is None or selected_candidate_index is None:
            return "No query target candidate is selected."
        direct_state = (
            "direct-clean"
            if selected_candidate.direct_review_required is False
            else "review-gated"
        )
        route_label = handoff_kind.replace("_", " ")
        note = (
            f"Selected candidate {selected_candidate_index} is a "
            f"{direct_state} {route_label}."
        )
        if review_gate.context_blocked_candidate_used:
            sibling_codes: list[str] = []
            for reason in context_blocking_reasons:
                details = reason.details or {}
                excluded_codes = details.get("excluded_blocker_codes")
                if isinstance(excluded_codes, list):
                    sibling_codes.extend(str(code) for code in excluded_codes)
            sibling_codes = list(dict.fromkeys(sibling_codes))
            if sibling_codes:
                return (
                    f"{note} Sibling/context metadata still has "
                    f"{', '.join(sibling_codes)}; these codes remain in "
                    "review_gate.all_issue_codes."
                )
            if review_gate.context_blocking_reason_codes:
                return (
                    f"{note} Context blockers still have "
                    f"{', '.join(review_gate.context_blocking_reason_codes)}; "
                    "see review_gate.all_issue_codes."
                )
        if review_gate.blocking_reason_codes:
            return (
                f"{note} Blocking reason codes: "
                f"{', '.join(review_gate.blocking_reason_codes)}."
            )
        return note

    def _draft_query_plan_storage_access(
        self,
        context: QueryPlanningContext,
        selected_candidate: QueryTargetCandidate | None,
    ) -> StorageAccessDescription | None:
        if selected_candidate is None or selected_candidate.storage_access is None:
            return None
        storage_iri = selected_candidate.storage_access.iri
        for storage_access in context.storage_accesses:
            if storage_access.iri == storage_iri:
                return storage_access
        return None

    def _draft_query_plan_selected_physical_layout(
        self,
        context: QueryPlanningContext,
        *,
        physical_layout_iri: str | None,
    ) -> tuple[PhysicalLayoutDescription | None, str | None]:
        if physical_layout_iri is None:
            return None, None
        layout_iri = self._required_iri("physical_layout_iri", physical_layout_iri)
        for layout in context.physical_layouts:
            if layout.iri == layout_iri:
                return layout, layout_iri
        raise DoxaBaseError(
            "physical_layout_iri did not match any physical layout linked to "
            f"'{context.dataset.iri}': {layout_iri}"
        )

    def _draft_query_plan_effective_layout_candidate(
        self,
        selected_candidate: QueryTargetCandidate | None,
        *,
        physical_layout_selected: bool,
    ) -> QueryTargetCandidate | None:
        if selected_candidate is None or not physical_layout_selected:
            return selected_candidate
        review_reasons = self._without_query_issue_code(
            selected_candidate.review_reasons,
            "ambiguous_physical_layout",
        )
        direct_review_reasons = self._without_query_issue_code(
            selected_candidate.direct_review_reasons,
            "ambiguous_physical_layout",
        )
        review_required = any(
            reason.severity in {"error", "warning"} for reason in review_reasons
        )
        direct_review_required = any(
            reason.severity in {"error", "warning"}
            for reason in direct_review_reasons
        )
        return replace(
            selected_candidate,
            review_required=review_required,
            review_reasons=review_reasons,
            direct_review_required=direct_review_required,
            direct_review_reasons=direct_review_reasons,
            candidate_path_status=self._query_candidate_path_status(
                selected_candidate.candidate_path,
                review_required=review_required,
                review_reasons=review_reasons,
            ),
        )

    def _draft_query_plan_effective_issues(
        self,
        issues: list[QueryPlanningIssue],
        *,
        physical_layout_selected: bool,
    ) -> list[QueryPlanningIssue]:
        if not physical_layout_selected:
            return issues
        return self._without_query_issue_code(issues, "ambiguous_physical_layout")

    @staticmethod
    def _without_query_issue_code(
        issues: list[QueryPlanningIssue],
        code: str,
    ) -> list[QueryPlanningIssue]:
        return [issue for issue in issues if issue.code != code]

    def _draft_query_plan_scan(
        self,
        selected_candidate: QueryTargetCandidate | None,
        *,
        dataset_verification_status: ResourceSummary | None,
        dataset_verification_note: str | None,
        partition_schemes: list[PartitionDescription],
        physical_layouts: list[PhysicalLayoutDescription],
        selected_physical_layout: PhysicalLayoutDescription | None,
        physical_layout_selected: bool,
        storage_accesses: list[StorageAccessDescription],
        engine: str,
    ) -> DraftQueryPlanScan:
        selected_layout = selected_physical_layout or (
            self._unique_physical_layout_for_query_plan(physical_layouts)
        )
        file_format = self._draft_query_plan_resource_label(
            selected_layout.file_format if selected_layout is not None else None
        )
        compression = self._draft_query_plan_resource_label(
            selected_layout.compression_codec if selected_layout is not None else None
        )
        template_status, template_note = self._draft_query_plan_template_verification(
            selected_candidate,
            dataset_verification_status=dataset_verification_status,
            dataset_verification_note=dataset_verification_note,
            partition_schemes=partition_schemes,
            storage_accesses=storage_accesses,
        )
        scan_function = (
            None
            if selected_candidate is not None
            and self._is_database_storage(selected_candidate.storage_protocol)
            else self._draft_query_plan_scan_function(engine, file_format)
        )
        database_storage = (
            selected_candidate is not None
            and self._is_database_storage(selected_candidate.storage_protocol)
        )
        return DraftQueryPlanScan(
            function=scan_function,
            uri_template=(
                selected_candidate.candidate_path
                if selected_candidate is not None and not database_storage
                else None
            ),
            relation_identifier=(
                selected_candidate.relation_identifier
                if selected_candidate is not None and database_storage
                else None
            ),
            connection_reference=(
                selected_candidate.connection_reference
                if selected_candidate is not None and database_storage
                else None
            ),
            file_format=file_format,
            compression=compression,
            candidate_path_status=(
                selected_candidate.candidate_path_status
                if selected_candidate is not None
                else None
            ),
            dataset_verification_status=dataset_verification_status,
            dataset_verification_note=dataset_verification_note,
            template=selected_candidate.template if selected_candidate is not None else None,
            template_source=(
                selected_candidate.template_source
                if selected_candidate is not None
                else None
            ),
            template_source_resource=(
                selected_candidate.source_resource
                if selected_candidate is not None
                else None
            ),
            template_source_verification_status=template_status,
            template_source_verification_note=template_note,
            template_lineage=self._draft_query_plan_template_lineage(
                selected_candidate,
                verification_status=template_status,
                verification_note=template_note,
            ),
            composition=(
                selected_candidate.composition if selected_candidate is not None else None
            ),
            physical_layout=(
                self._summary_from_description(selected_layout)
                if selected_layout is not None
                else None
            ),
            physical_layout_selection_note=(
                "Caller selected this physical layout for the draft query plan."
                if physical_layout_selected
                else (
                    "A single linked physical layout signature was selected "
                    "automatically."
                    if selected_layout is not None
                    else (
                        "No unambiguous physical layout was selected; scan "
                        "function inference is withheld."
                    )
                )
            ),
            non_executed_note=(
                "Review-only draft; do not run without resolving runtime "
                "configuration and reviewing issues, verification notes, and "
                "analysis caveats."
            ),
        )

    def _unique_physical_layout_for_query_plan(
        self,
        physical_layouts: list[PhysicalLayoutDescription],
    ) -> PhysicalLayoutDescription | None:
        if not physical_layouts:
            return None
        signatures = self._physical_layout_signatures(physical_layouts)
        if len(signatures) != 1:
            return None
        return physical_layouts[0]

    def _draft_query_plan_template_verification(
        self,
        selected_candidate: QueryTargetCandidate | None,
        *,
        dataset_verification_status: ResourceSummary | None,
        dataset_verification_note: str | None,
        partition_schemes: list[PartitionDescription],
        storage_accesses: list[StorageAccessDescription],
    ) -> tuple[ResourceSummary | None, str | None]:
        if selected_candidate is None:
            return None, None
        if selected_candidate.template_source == "dataset":
            return dataset_verification_status, dataset_verification_note
        if selected_candidate.template_source == "partition_scheme":
            for partition in partition_schemes:
                if partition.iri == selected_candidate.source_resource.iri:
                    return (
                        partition.layout_verification_status,
                        partition.layout_verification_note,
                    )
        if selected_candidate.template_source in {
            "storage_access",
            "storage_access_location",
        }:
            for storage_access in storage_accesses:
                if storage_access.iri == selected_candidate.source_resource.iri:
                    return (
                        storage_access.layout_verification_status,
                        storage_access.layout_verification_note,
                    )
        return None, None

    @staticmethod
    def _draft_query_plan_template_lineage(
        selected_candidate: QueryTargetCandidate | None,
        *,
        verification_status: ResourceSummary | None,
        verification_note: str | None,
    ) -> str | None:
        if selected_candidate is None:
            return None
        source_label = (
            selected_candidate.source_resource.label
            or selected_candidate.source_resource.iri
        )
        if selected_candidate.template_source == "storage_access_location":
            lineage = f"Candidate storage root comes from storage access {source_label}."
        else:
            lineage = (
                f"Template comes from {selected_candidate.template_source} "
                f"{source_label}."
            )
        if verification_status is not None:
            status_label = verification_status.label or verification_status.iri
            lineage = f"{lineage} Verification status: {status_label}."
        if verification_note:
            lineage = f"{lineage} Verification note: {verification_note}"
        return lineage

    @staticmethod
    def _draft_query_plan_resource_label(resource: ResourceSummary | None) -> str | None:
        if resource is None:
            return None
        return resource.label or resource.iri

    @staticmethod
    def _draft_query_plan_scan_function(
        engine: str,
        file_format: str | None,
    ) -> str | None:
        if engine != "duckdb" or file_format is None:
            return None
        normalized = file_format.lower()
        if "parquet" in normalized:
            return "read_parquet"
        if "csv" in normalized:
            return "read_csv_auto"
        return None

    def _draft_query_plan_binding_requirements(
        self,
        selected_candidate: QueryTargetCandidate | None,
        *,
        columns: list[ColumnDescription],
        partition_schemes: list[PartitionDescription],
    ) -> list[DraftQueryPlanBinding]:
        if selected_candidate is None:
            return []
        template = self._draft_query_plan_binding_source_text(selected_candidate)
        names = list(dict.fromkeys(re.findall(r"{([^{}]+)}", template or "")))
        partition = self._draft_query_plan_binding_partition(
            selected_candidate,
            partition_schemes,
        )

        def binding_for(name: str) -> DraftQueryPlanBinding:
            partition_column = (
                self._draft_query_plan_partition_column_for_binding(
                    name,
                    partition,
                )
                if partition is not None
                else None
            )
            candidate_column_matches = (
                []
                if partition is not None and partition_column is not None
                else self._draft_query_plan_column_matches_for_binding(
                    name,
                    columns,
                )
            )
            candidate_column_match_status = (
                "not_applicable"
                if partition is not None and partition_column is not None
                else self._draft_query_plan_column_match_status(
                    candidate_column_matches
                )
            )
            return DraftQueryPlanBinding(
                name=name,
                source="path_template_placeholder",
                source_text=template,
                required=True,
                derivation_status="not_inferred",
                derivation_note=self._draft_query_plan_binding_derivation_note(
                    name,
                    partition=partition,
                    partition_column=partition_column,
                    candidate_column_matches=candidate_column_matches,
                    candidate_column_match_status=(
                        candidate_column_match_status
                    ),
                ),
                binding_kind=(
                    "partition_template_placeholder"
                    if partition is not None
                    else "path_template_placeholder"
                ),
                partition_scheme=(
                    self._summary_from_description(partition)
                    if partition is not None
                    else None
                ),
                partition_column=partition_column,
                partition_granularity=(
                    partition.granularity if partition is not None else None
                ),
                candidate_column_matches=candidate_column_matches,
                candidate_column_match_status=candidate_column_match_status,
            )

        return [
            binding_for(name)
            for name in names
        ]

    @staticmethod
    def _draft_query_plan_binding_source_text(
        selected_candidate: QueryTargetCandidate,
    ) -> str | None:
        return selected_candidate.candidate_path or selected_candidate.template

    @staticmethod
    def _draft_query_plan_binding_partition(
        selected_candidate: QueryTargetCandidate,
        partition_schemes: list[PartitionDescription],
    ) -> PartitionDescription | None:
        if selected_candidate.template_source == "partition_scheme":
            for partition in partition_schemes:
                if partition.iri == selected_candidate.source_resource.iri:
                    return partition
            return None
        matching_partitions = [
            partition
            for partition in partition_schemes
            if partition.path_template is not None
            and partition.path_template.strip() == selected_candidate.template.strip()
        ]
        if len(matching_partitions) == 1:
            return matching_partitions[0]
        return None

    def _draft_query_plan_column_matches_for_binding(
        self,
        name: str,
        columns: list[ColumnDescription],
    ) -> list[DraftQueryPlanBindingColumnMatch]:
        placeholder = self._normalized_binding_name(name)
        if not placeholder:
            return []
        exact_matches: list[DraftQueryPlanBindingColumnMatch] = []
        suffix_matches: list[DraftQueryPlanBindingColumnMatch] = []
        for column in columns:
            candidates = [
                ("column_name", column.column_name),
                ("label", column.label),
                ("local_name", self._local_name(column.iri)),
            ]
            exact = self._first_binding_column_match(
                placeholder,
                column,
                candidates,
                match_kind="exact_name",
                confidence="high",
            )
            if exact is not None:
                exact_matches.append(exact)
                continue
            suffix = self._first_binding_column_match(
                placeholder,
                column,
                candidates,
                match_kind="suffix_name",
                confidence="medium",
            )
            if suffix is not None:
                suffix_matches.append(suffix)
        return exact_matches or suffix_matches

    def _first_binding_column_match(
        self,
        placeholder: str,
        column: ColumnDescription,
        candidates: list[tuple[str, str | None]],
        *,
        match_kind: str,
        confidence: str,
    ) -> DraftQueryPlanBindingColumnMatch | None:
        for matched_field, matched_value in candidates:
            normalized = self._normalized_binding_name(matched_value)
            if not normalized:
                continue
            if match_kind == "exact_name":
                matched = normalized == placeholder
            else:
                matched = self._binding_name_has_suffix(normalized, placeholder)
            if matched and matched_value is not None:
                return DraftQueryPlanBindingColumnMatch(
                    column=ResourceSummary(
                        iri=column.iri,
                        label=column.label
                        or column.column_name
                        or self._local_name(column.iri),
                        description=column.description,
                        column_name=column.column_name,
                    ),
                    match_kind=match_kind,
                    matched_field=matched_field,
                    matched_value=matched_value,
                    confidence=confidence,
                )
        return None

    @staticmethod
    def _draft_query_plan_column_match_status(
        candidate_column_matches: list[DraftQueryPlanBindingColumnMatch],
    ) -> str:
        if not candidate_column_matches:
            return "none"
        if len(candidate_column_matches) == 1:
            return "single"
        return "ambiguous"

    def _draft_query_plan_partition_column_for_binding(
        self,
        name: str,
        partition: PartitionDescription,
    ) -> ResourceSummary | None:
        placeholder = self._normalized_binding_name(name)
        if not placeholder:
            return None
        exact_matches: list[ResourceSummary] = []
        suffix_matches: list[ResourceSummary] = []
        for column in partition.partition_columns:
            candidate_names = [
                column.column_name,
                column.label,
                self._local_name(column.iri),
            ]
            normalized_names = {
                normalized
                for value in candidate_names
                if (normalized := self._normalized_binding_name(value))
            }
            if placeholder in normalized_names:
                exact_matches.append(column)
            elif any(
                self._binding_name_has_suffix(normalized, placeholder)
                for normalized in normalized_names
            ):
                suffix_matches.append(column)
        for matches in (exact_matches, suffix_matches):
            unique = {column.iri: column for column in matches}
            if len(unique) == 1:
                return next(iter(unique.values()))
        return None

    def _draft_query_plan_binding_derivation_note(
        self,
        name: str,
        *,
        partition: PartitionDescription | None,
        partition_column: ResourceSummary | None,
        candidate_column_matches: list[DraftQueryPlanBindingColumnMatch],
        candidate_column_match_status: str,
    ) -> str:
        base_note = (
            "Supply this value explicitly or derive it in the runtime query "
            "layer after review; DoxaBase has not inferred a type, dependency, "
            "or default value for this placeholder."
        )
        if partition is None:
            if candidate_column_matches:
                match_names = ", ".join(
                    match.column.label
                    or match.column.column_name
                    or match.column.iri
                    for match in candidate_column_matches
                )
                if candidate_column_match_status == "ambiguous":
                    return (
                        f"{base_note} Candidate column hint(s): {match_names}. "
                        "Multiple candidate columns matched this placeholder; "
                        "review which source column, if any, should supply the "
                        "runtime value."
                    )
                return (
                    f"{base_note} Candidate column hint(s): {match_names}. "
                    "These are best-effort placeholder/name matches, not "
                    "inferred runtime binding values."
                )
            return base_note
        details: list[str] = []
        if partition_column is not None:
            partition_column_label = (
                partition_column.label
                or partition_column.column_name
                or partition_column.iri
            )
            details.append(
                f"likely partition column {partition_column_label}"
            )
        if partition.granularity is not None:
            details.append(
                "partition scheme granularity "
                f"{partition.granularity.label or partition.granularity.iri}"
            )
        candidate_note = ""
        if candidate_column_matches:
            match_names = ", ".join(
                match.column.label or match.column.column_name or match.column.iri
                for match in candidate_column_matches
            )
            if candidate_column_match_status == "ambiguous":
                candidate_note = (
                    f" Candidate column hint(s): {match_names}. Multiple "
                    "candidate columns matched this placeholder; review which "
                    "source column, if any, should supply the runtime value."
                )
            else:
                candidate_note = (
                    f" Candidate column hint(s): {match_names}. These are "
                    "best-effort placeholder/name matches, not inferred "
                    "runtime binding values."
                )
        if not details:
            return (
                f"{base_note} The selected template comes from partition scheme "
                f"{partition.label or partition.iri}.{candidate_note}"
            )
        return (
            f"{base_note} The selected template comes from partition scheme "
            f"{partition.label or partition.iri}; metadata indicates "
            f"{'; '.join(details)}.{candidate_note}"
        )

    @staticmethod
    def _normalized_binding_name(value: str | None) -> str:
        if value is None:
            return ""
        return re.sub(r"[^a-z0-9]+", "_", value.strip().lower()).strip("_")

    @staticmethod
    def _binding_name_has_suffix(candidate: str, placeholder: str) -> bool:
        return bool(candidate and placeholder and candidate.endswith(f"_{placeholder}"))

    def _draft_query_plan_storage_environment(
        self,
        selected_candidate: QueryTargetCandidate | None,
        storage_access: StorageAccessDescription | None,
        *,
        engine: str,
    ) -> DraftQueryPlanStorageEnvironment:
        duckdb_settings: list[str] = []
        path_style_access = (
            selected_candidate.path_style_access
            if selected_candidate is not None
            else None
        )
        region = storage_access.region if storage_access is not None else None
        if engine == "duckdb":
            if path_style_access is not None:
                duckdb_settings.append(
                    f"s3_url_style={'path' if path_style_access else 'vhost'}"
                )
            if region is not None:
                duckdb_settings.append(f"s3_region={region}")
        endpoint_profile = (
            selected_candidate.endpoint_profile
            if selected_candidate is not None
            else None
        )
        credential_reference = (
            selected_candidate.credential_reference
            if selected_candidate is not None
            else None
        )
        requires_endpoint_profile = (
            selected_candidate.requires_endpoint_profile
            if selected_candidate is not None
            else False
        )
        unresolved_s3_access = (
            selected_candidate is not None
            and any(
                reason.code == "s3_access_resolution_unrecorded"
                for reason in selected_candidate.review_reasons
            )
        )
        database_storage = (
            selected_candidate is not None
            and self._is_database_storage(selected_candidate.storage_protocol)
        )
        runtime_resolution_required = bool(
            endpoint_profile
            or credential_reference
            or requires_endpoint_profile
            or unresolved_s3_access
        )
        if unresolved_s3_access:
            runtime_resolution_note = (
                "Record or resolve the S3 endpoint profile, credential reference, "
                "region, and object access in the local runtime before running any "
                "query."
            )
        elif runtime_resolution_required:
            if database_storage:
                runtime_resolution_note = (
                    "Resolve the recorded database endpoint profile or credential "
                    "reference in the local runtime, and verify connection, "
                    "schema, table, or source access before running any query."
                )
            else:
                runtime_resolution_note = (
                    "Resolve the recorded endpoint profile or credential reference "
                    "in the local runtime, and verify object access before running "
                    "any query."
                )
        else:
            if database_storage:
                runtime_resolution_note = (
                    "No database endpoint or credential profile is recorded or "
                    "required by the graph; still verify connection, schema, "
                    "table, or source access before running any query."
                )
            else:
                runtime_resolution_note = (
                    "No endpoint or credential profile is recorded or required by "
                    "the graph; still verify local paths or remote object existence "
                    "before running any query."
                )
        return DraftQueryPlanStorageEnvironment(
            storage_protocol=(
                selected_candidate.storage_protocol
                if selected_candidate is not None
                else None
            ),
            storage_root=(
                selected_candidate.storage_root
                if selected_candidate is not None
                else None
            ),
            bucket_name=(
                selected_candidate.bucket_name
                if selected_candidate is not None
                else None
            ),
            key_prefix=(
                selected_candidate.key_prefix
                if selected_candidate is not None
                else None
            ),
            region=region,
            endpoint_profile=endpoint_profile,
            credential_reference=credential_reference,
            access_mode=storage_access.access_mode if storage_access is not None else None,
            path_style_access=path_style_access,
            requires_endpoint_profile=requires_endpoint_profile,
            runtime_resolution_required=runtime_resolution_required,
            duckdb_settings_from_context=duckdb_settings,
            runtime_resolution_note=runtime_resolution_note,
        )

    def _draft_query_plan_review_gate(
        self,
        context: QueryPlanningContext,
        selected_candidate: QueryTargetCandidate | None,
        *,
        original_selected_candidate: QueryTargetCandidate | None,
        selected_decision: QueryTargetDecision,
        scan: DraftQueryPlanScan,
        issues: list[QueryPlanningIssue],
        storage_environment: DraftQueryPlanStorageEnvironment,
        binding_requirements: list[DraftQueryPlanBinding],
        selection_overridden: bool,
        allow_context_blocked_candidate: bool,
        context_blocked_candidate_used: bool,
        context_blocking_reasons: list[QueryPlanningIssue],
    ) -> DraftQueryPlanReviewGate:
        blocking_reason_codes = self._draft_query_plan_blocking_reason_codes(
            context,
            selected_candidate,
            selected_decision=selected_decision,
            scan=scan,
            issues=issues,
            context_blocked_candidate_used=context_blocked_candidate_used,
        )
        context_metadata_ready = (
            context.readiness == "ready_for_query_planning"
            or context_blocked_candidate_used
            or not self._query_blocking_issue_codes(issues)
        )
        executable_without_review = (
            context_metadata_ready
            and selected_decision.status == "ready"
            and selected_decision.candidate_path_status == "ready"
            and selected_decision.direct_review_required is False
            and not blocking_reason_codes
        )
        binding_values_required = any(
            binding.required for binding in binding_requirements
        )
        execution_attempt_blocking_reason_codes = (
            self._draft_query_plan_execution_attempt_blocking_reason_codes(
                blocking_reason_codes=blocking_reason_codes,
                runtime_resolution_required=(
                    storage_environment.runtime_resolution_required
                ),
                binding_values_required=binding_values_required,
            )
        )
        direct_blocking_reason_codes = self._query_issue_codes(
            self._query_target_blocking_reasons(
                selected_candidate.direct_review_reasons
                if selected_candidate is not None
                else []
            )
        )
        context_blocking_reason_codes = self._query_issue_codes(
            context_blocking_reasons
            or self._query_target_context_blocking_reasons(
                original_selected_candidate.review_reasons
                if original_selected_candidate is not None
                else []
            )
        )
        return DraftQueryPlanReviewGate(
            executable_without_review=executable_without_review,
            runtime_resolution_required=(
                storage_environment.runtime_resolution_required
            ),
            binding_values_required=binding_values_required,
            ready_for_execution_attempt=(
                executable_without_review
                and not storage_environment.runtime_resolution_required
                and not binding_values_required
            ),
            status=selected_decision.status,
            direct_review_required=selected_decision.direct_review_required,
            candidate_path_status=selected_decision.candidate_path_status,
            blocking_reason_codes=blocking_reason_codes,
            execution_attempt_blocking_reason_codes=(
                execution_attempt_blocking_reason_codes
            ),
            primary_execution_attempt_blocking_reason_code=(
                execution_attempt_blocking_reason_codes[0]
                if execution_attempt_blocking_reason_codes
                else None
            ),
            all_issue_codes=self._query_issue_codes(issues),
            reason_codes=blocking_reason_codes,
            review_note=(
                "This helper drafts a non-executed plan. Review selected "
                "candidate reasons, physical metadata issues, verification "
                "notes, and analysis warnings before execution."
                if selected_candidate is not None
                else "No query target candidate is available."
            ),
            selection_overridden=selection_overridden,
            context_blocked_candidate_allowed=allow_context_blocked_candidate,
            context_blocked_candidate_used=context_blocked_candidate_used,
            direct_blocking_reason_codes=direct_blocking_reason_codes,
            context_blocking_reason_codes=context_blocking_reason_codes,
        )

    @staticmethod
    def _draft_query_plan_execution_attempt_blocking_reason_codes(
        *,
        blocking_reason_codes: list[str],
        runtime_resolution_required: bool,
        binding_values_required: bool,
    ) -> list[str]:
        codes = list(blocking_reason_codes)
        if runtime_resolution_required:
            codes.append("runtime_resolution_required")
        if binding_values_required:
            codes.append("binding_values_required")
        return list(dict.fromkeys(codes))

    def _draft_query_plan_blocking_reason_codes(
        self,
        context: QueryPlanningContext,
        selected_candidate: QueryTargetCandidate | None,
        *,
        selected_decision: QueryTargetDecision,
        scan: DraftQueryPlanScan,
        issues: list[QueryPlanningIssue],
        context_blocked_candidate_used: bool,
    ) -> list[str]:
        codes = list(selected_decision.reason_codes)
        if (
            not codes
            and context.readiness != "ready_for_query_planning"
            and not context_blocked_candidate_used
        ):
            issue_codes = self._query_blocking_issue_codes(issues)
            if selected_candidate is None:
                codes.extend(issue_codes)
            elif issue_codes and selected_decision.direct_review_required is False:
                codes.append("query_context_has_other_blockers")
            else:
                codes.extend(issue_codes)
        if (
            selected_candidate is not None
            and selected_decision.candidate_path_status == "ready"
            and scan.function is None
        ):
            codes.append("scan_function_not_inferred")
        return list(dict.fromkeys(codes))

    @staticmethod
    def _query_issue_codes(
        issues: Iterable[QueryPlanningIssue],
    ) -> list[str]:
        codes: list[str] = []
        seen: set[str] = set()
        for issue in issues:
            if issue.code in seen:
                continue
            seen.add(issue.code)
            codes.append(issue.code)
        return codes

    @staticmethod
    def _query_blocking_issue_codes(
        issues: Iterable[QueryPlanningIssue],
    ) -> list[str]:
        codes: list[str] = []
        seen: set[str] = set()
        for issue in issues:
            if issue.severity not in {"error", "warning"}:
                continue
            if issue.code in seen:
                continue
            seen.add(issue.code)
            codes.append(issue.code)
        return codes

    def _query_target_candidates(
        self,
        dataset: DatasetDescription,
        *,
        dataset_summary: ResourceSummary,
        direct_path_templates: list[str],
        issues: list[QueryPlanningIssue],
    ) -> list[QueryTargetCandidate]:
        template_sources: list[tuple[str, str, ResourceSummary]] = []
        seen_sources: set[tuple[str, str, str]] = set()

        def add_template_source(
            template: str | None,
            template_source: str,
            source_resource: ResourceSummary,
        ) -> None:
            if template is None:
                return
            key = (template, template_source, source_resource.iri)
            if key in seen_sources:
                return
            seen_sources.add(key)
            template_sources.append((template, template_source, source_resource))

        for template in direct_path_templates:
            add_template_source(template, "dataset", dataset_summary)
        for partition in dataset.partition_schemes:
            add_template_source(
                partition.path_template,
                "partition_scheme",
                self._summary_from_description(partition),
            )

        candidates: list[QueryTargetCandidate] = []
        seen_candidates: set[tuple[str, str, str, str | None]] = set()

        def add_candidate(
            template: str,
            template_source: str,
            source_resource: ResourceSummary,
            storage_access: StorageAccessDescription | None,
        ) -> None:
            access_resource = (
                self._summary_from_description(storage_access)
                if storage_access is not None
                else None
            )
            key = (
                template,
                template_source,
                source_resource.iri,
                access_resource.iri if access_resource is not None else None,
            )
            if key in seen_candidates:
                return
            seen_candidates.add(key)
            database_storage = (
                storage_access is not None
                and self._is_database_storage(storage_access.storage_protocol)
            )
            database_relation_template_source_mismatch = (
                database_storage
                and template_source not in {"storage_access", "storage_access_location"}
            )
            relation_identifier = (
                template.strip() or None
                if database_storage and template_source == "storage_access"
                else None
            )
            connection_reference = (
                storage_access.storage_root
                if database_storage and storage_access is not None
                else None
            )
            if template_source == "storage_access_location":
                candidate_path = template.strip() or None
                if database_storage:
                    composition = (
                        "database_connection_as_candidate"
                        if candidate_path is not None
                        else "unresolved"
                    )
                else:
                    composition = (
                        "storage_root_as_candidate"
                        if candidate_path is not None
                        else "unresolved"
                    )
            elif database_storage:
                if database_relation_template_source_mismatch:
                    candidate_path = None
                    composition = "unresolved"
                else:
                    candidate_path = relation_identifier
                    if candidate_path is None:
                        composition = "unresolved"
                    elif connection_reference:
                        composition = "database_connection_and_relation"
                    else:
                        composition = "database_relation"
            else:
                candidate_path, composition = self._query_candidate_path(
                    template,
                    storage_access,
                )
            review_reasons = self._query_target_review_reasons(
                dataset,
                issues,
                source_resource=source_resource,
                storage_access=access_resource,
            )
            if (
                storage_access is not None
                and template_source != "storage_access_location"
            ):
                object_location_issue = (
                    self._query_storage_object_location_template_issue(
                        template=template,
                        template_source=template_source,
                        source_resource=source_resource,
                        storage_access=storage_access,
                    )
                )
                if object_location_issue is not None and not any(
                    reason.code == object_location_issue.code
                    and (
                        reason.resource.iri if reason.resource is not None else None
                    )
                    == (
                        object_location_issue.resource.iri
                        if object_location_issue.resource is not None
                        else None
                    )
                    for reason in review_reasons
                ):
                    review_reasons.append(object_location_issue)
                relation_source_issue = (
                    self._query_database_relation_template_source_issue(
                        template=template,
                        template_source=template_source,
                        source_resource=source_resource,
                        storage_access=storage_access,
                    )
                )
                if relation_source_issue is not None and not any(
                    reason.code == relation_source_issue.code
                    and (
                        reason.resource.iri if reason.resource is not None else None
                    )
                    == (
                        relation_source_issue.resource.iri
                        if relation_source_issue.resource is not None
                        else None
                    )
                    for reason in review_reasons
                ):
                    review_reasons.append(relation_source_issue)
                candidate_metadata_issue = self._query_candidate_metadata_issue(
                    template=template,
                    source_resource=source_resource,
                    storage_access=storage_access,
                )
                if candidate_metadata_issue is not None and not any(
                    reason.code == candidate_metadata_issue.code
                    and (
                        reason.resource.iri if reason.resource is not None else None
                    )
                    == (
                        candidate_metadata_issue.resource.iri
                        if candidate_metadata_issue.resource is not None
                        else None
                    )
                    for reason in review_reasons
                ):
                    review_reasons.append(candidate_metadata_issue)
            if (
                storage_access is not None
                and template_source == "storage_access_location"
            ):
                location_issue = self._query_storage_access_location_kind_issue(
                    storage_access
                )
                if location_issue is not None and not any(
                    reason.code == location_issue.code
                    and (
                        reason.resource.iri if reason.resource is not None else None
                    )
                    == (
                        location_issue.resource.iri
                        if location_issue.resource is not None
                        else None
                    )
                    for reason in review_reasons
                ):
                    review_reasons.append(location_issue)
            review_required = any(
                reason.severity in {"error", "warning"}
                for reason in review_reasons
            )
            direct_review_reasons = self._query_target_direct_review_reasons(
                review_reasons
            )
            direct_review_required = any(
                reason.severity in {"error", "warning"}
                for reason in direct_review_reasons
            )
            candidates.append(
                QueryTargetCandidate(
                    template=template,
                    template_source=template_source,
                    source_resource=source_resource,
                    storage_access=access_resource,
                    storage_protocol=(
                        storage_access.storage_protocol
                        if storage_access is not None
                        else None
                    ),
                    location_kind=(
                        storage_access.location_kind
                        if storage_access is not None
                        else None
                    ),
                    storage_root=(
                        storage_access.storage_root
                        if storage_access is not None
                        else None
                    ),
                    endpoint_profile=(
                        storage_access.endpoint_profile
                        if storage_access is not None
                        else None
                    ),
                    bucket_name=(
                        storage_access.bucket_name if storage_access is not None else None
                    ),
                    key_prefix=(
                        storage_access.key_prefix if storage_access is not None else None
                    ),
                    candidate_path=candidate_path,
                    relation_identifier=relation_identifier,
                    connection_reference=connection_reference,
                    composition=composition,
                    candidate_path_status=self._query_candidate_path_status(
                        candidate_path,
                        review_required=review_required,
                        review_reasons=review_reasons,
                    ),
                    requires_endpoint_profile=(
                        bool(storage_access.endpoint_profile)
                        if storage_access is not None
                        else False
                    ),
                    credential_reference=(
                        storage_access.credential_reference
                        if storage_access is not None
                        else None
                    ),
                    path_style_access=(
                        storage_access.path_style_access
                        if storage_access is not None
                        else None
                    ),
                    review_required=review_required,
                    review_reasons=review_reasons,
                    direct_review_required=direct_review_required,
                    direct_review_reasons=direct_review_reasons,
                )
            )

        for template, template_source, source_resource in template_sources:
            if dataset.storage_accesses:
                for storage_access in dataset.storage_accesses:
                    add_candidate(template, template_source, source_resource, storage_access)
            else:
                add_candidate(template, template_source, source_resource, None)
        for storage_access in dataset.storage_accesses:
            access_resource = self._summary_from_description(storage_access)
            for template in storage_access.path_templates:
                add_candidate(template, "storage_access", access_resource, storage_access)
            if storage_access.storage_root is not None and (
                (
                    not template_sources
                    and not storage_access.path_templates
                )
                or (
                    storage_access.location_kind == "object"
                    and not self._is_database_storage(storage_access.storage_protocol)
                )
            ):
                add_candidate(
                    storage_access.storage_root,
                    "storage_access_location",
                    access_resource,
                    storage_access,
                )

        return candidates

    def _query_target_decision(
        self,
        candidates: list[QueryTargetCandidate],
    ) -> QueryTargetDecision:
        if not candidates:
            return QueryTargetDecision(
                status="no_candidate",
                summary=(
                    "No query target candidate is available; inspect issues and "
                    "record storage/path metadata before planning a query."
                ),
                candidate_index=None,
                candidate_path=None,
                candidate_path_status=None,
                direct_review_required=None,
                selected_candidate_direct_clean=None,
                reason_codes=[],
            )

        indexed_candidates = list(enumerate(candidates))
        ready_candidates = [
            item
            for item in indexed_candidates
            if item[1].candidate_path_status == "ready"
            and not item[1].review_required
        ]
        if ready_candidates:
            index, candidate = min(
                ready_candidates,
                key=self._query_target_candidate_decision_rank,
            )
            return self._query_target_decision_for_candidate(
                candidate,
                index=index,
                status="ready",
                summary=(
                    f"Candidate {index} is ready for query planning; review "
                    "analysis_warnings and caveats before trusting results."
                ),
            )

        context_blocked_candidates = [
            item
            for item in indexed_candidates
            if item[1].review_required and not item[1].direct_review_required
        ]
        if context_blocked_candidates:
            index, candidate = min(
                context_blocked_candidates,
                key=self._query_target_candidate_decision_rank,
            )
            return self._query_target_decision_for_candidate(
                candidate,
                index=index,
                status="context_blocked",
                summary=(
                    f"Candidate {index} has no direct warning or error, but "
                    "the overall query context has blockers elsewhere; inspect "
                    "issues before executing it."
                ),
            )

        index, candidate = min(
            indexed_candidates,
            key=self._query_target_candidate_decision_rank,
        )
        return self._query_target_decision_for_candidate(
            candidate,
            index=index,
            status="candidate_needs_review",
            summary=(
                f"No candidate is ready; candidate {index} is the first "
                "review target to inspect before executable query use."
            ),
        )

    def _query_target_decision_for_candidate(
        self,
        candidate: QueryTargetCandidate,
        *,
        index: int,
        status: str,
        summary: str,
    ) -> QueryTargetDecision:
        return QueryTargetDecision(
            status=status,
            summary=summary,
            candidate_index=index,
            candidate_path=candidate.candidate_path,
            candidate_path_status=candidate.candidate_path_status,
            direct_review_required=candidate.direct_review_required,
            selected_candidate_direct_clean=not candidate.direct_review_required,
            reason_codes=self._query_target_decision_reason_codes(
                candidate,
                status=status,
            ),
        )

    def _query_target_candidate_decision_rank(
        self,
        item: tuple[int, QueryTargetCandidate],
    ) -> tuple[int, int, int, int, int, int, int]:
        index, candidate = item
        path_status_rank = {
            "ready": 0,
            "orientation_only": 1,
            "unresolved": 2,
        }.get(candidate.candidate_path_status, 3)
        blocking_reasons = self._query_target_blocking_reasons(
            candidate.direct_review_reasons
        ) or self._query_target_blocking_reasons(candidate.review_reasons)
        severity_rank = self._query_target_blocking_severity_rank(blocking_reasons)
        return (
            path_status_rank,
            severity_rank,
            len(blocking_reasons),
            self._query_target_candidate_binding_count(candidate),
            self._query_target_candidate_relation_rank(candidate),
            self._query_target_candidate_source_rank(candidate),
            index,
        )

    @staticmethod
    def _query_target_candidate_binding_count(
        candidate: QueryTargetCandidate,
    ) -> int:
        template = candidate.candidate_path or candidate.template or ""
        return len(dict.fromkeys(re.findall(r"{([^{}]+)}", template)))

    @staticmethod
    def _query_target_candidate_relation_rank(
        candidate: QueryTargetCandidate,
    ) -> int:
        return 1 if candidate.relation_identifier is not None else 0

    @staticmethod
    def _query_target_candidate_source_rank(
        candidate: QueryTargetCandidate,
    ) -> int:
        return {
            "storage_access_location": 0,
            "storage_access": 1,
            "partition_scheme": 2,
            "dataset": 3,
        }.get(candidate.template_source, 4)

    def _query_target_decision_reason_codes(
        self,
        candidate: QueryTargetCandidate,
        *,
        status: str,
    ) -> list[str]:
        if status == "context_blocked":
            reasons = [
                reason
                for reason in self._query_target_blocking_reasons(
                    candidate.review_reasons
                )
                if reason.code == "query_context_has_other_blockers"
            ]
        elif status == "candidate_needs_review":
            reasons = self._query_target_blocking_reasons(
                candidate.direct_review_reasons
            )
        else:
            reasons = self._query_target_blocking_reasons(candidate.review_reasons)
        if not reasons:
            reasons = self._query_target_blocking_reasons(candidate.review_reasons)

        codes: list[str] = []
        seen: set[str] = set()
        for reason in reasons:
            if reason.code in seen:
                continue
            seen.add(reason.code)
            codes.append(reason.code)
        return codes

    def _query_target_blocking_reasons(
        self,
        reasons: Iterable[QueryPlanningIssue],
    ) -> list[QueryPlanningIssue]:
        return [
            reason
            for reason in reasons
            if reason.severity in {"error", "warning"}
        ]

    def _query_target_blocking_severity_rank(
        self,
        reasons: list[QueryPlanningIssue],
    ) -> int:
        if any(reason.severity == "error" for reason in reasons):
            return 2
        if any(reason.severity == "warning" for reason in reasons):
            return 1
        return 0

    def _query_target_direct_review_reasons(
        self,
        review_reasons: list[QueryPlanningIssue],
    ) -> list[QueryPlanningIssue]:
        return [
            reason
            for reason in review_reasons
            if reason.code != "query_context_has_other_blockers"
        ]

    def _query_target_context_blocking_reasons(
        self,
        review_reasons: Iterable[QueryPlanningIssue],
    ) -> list[QueryPlanningIssue]:
        return [
            reason
            for reason in self._query_target_blocking_reasons(review_reasons)
            if reason.code == "query_context_has_other_blockers"
        ]

    def _query_database_relation_template_source_issue(
        self,
        *,
        template: str,
        template_source: str,
        source_resource: ResourceSummary,
        storage_access: StorageAccessDescription,
    ) -> QueryPlanningIssue | None:
        if not self._is_database_storage(storage_access.storage_protocol):
            return None
        if template_source in {"storage_access", "storage_access_location"}:
            return None
        source_label = source_resource.label or source_resource.iri
        return QueryPlanningIssue(
            code="database_relation_template_source_mismatch",
            severity="warning",
            message=(
                "Database storage candidate uses a path template from "
                f"{source_label}; dataset and partition path templates are "
                "file/object locations, not database relation identifiers. "
                "Record the database relation as a storage-access path_template "
                "before database handoff."
            ),
            resource=self._summary_from_description(storage_access),
            details={
                "template": template,
                "template_source": template_source,
                "template_source_resource_iri": source_resource.iri,
                "storage_access_iri": storage_access.iri,
                "storage_protocol_iri": (
                    storage_access.storage_protocol.iri
                    if storage_access.storage_protocol is not None
                    else None
                ),
                "allowed_relation_template_sources": ["storage_access"],
                "repair_hint": self._query_database_relation_template_repair_hint(
                    template=template,
                    template_source=template_source,
                    source_resource=source_resource,
                    storage_access=storage_access,
                ),
            },
        )

    def _query_database_relation_template_repair_hint(
        self,
        *,
        template: str,
        template_source: str,
        source_resource: ResourceSummary,
        storage_access: StorageAccessDescription,
    ) -> dict[str, Any]:
        add_action = {
            "action_type": "add_reviewed_relation_template",
            "tool_name": "stage_map_assertion_change",
            "mcp_tool_name": "doxabase.stage_map_assertion_change",
            "required_extra_arguments": ["object", "rationale"],
            "rationale_template": (
                "Reviewed database relation identifier for "
                f"{storage_access.iri}."
            ),
            "arguments_template": {
                "subject": storage_access.iri,
                "predicate": "rc:pathTemplate",
                "object": "<reviewed_database_relation_identifier>",
                "object_kind": "literal",
                "change_kind": "add",
                "graph": "map",
            },
            "placeholder_fields": ["object"],
            "reviewed_value_fields": ["object"],
            "condition": (
                "Replace the placeholder object with the reviewed "
                "database relation identifier before staging."
            ),
        }
        remove_action = {
            "action_type": "remove_misplaced_source_template",
            "tool_name": "stage_map_assertion_change",
            "mcp_tool_name": "doxabase.stage_map_assertion_change",
            "required_extra_arguments": ["rationale"],
            "rationale_template": (
                "Reviewed source template as misplaced database "
                "relation metadata."
            ),
            "arguments": {
                "subject": source_resource.iri,
                "predicate": "rc:pathTemplate",
                "object": template,
                "object_kind": "literal",
                "change_kind": "remove",
                "graph": "map",
            },
            "condition": (
                "Only after review confirms the source template was "
                "misplaced relation metadata rather than a real "
                "file/object path."
            ),
        }
        target_already_has_template = template in storage_access.path_templates
        if target_already_has_template:
            add_action = {
                **add_action,
                "action_status": "already_satisfied",
                "skip_when_already_satisfied": True,
                "condition": (
                    "The storage access already carries this relation-like "
                    "template. Review the remaining misplaced source template "
                    "and run remove_misplaced_source_template instead of "
                    "adding a duplicate relation template."
                ),
            }
        actions = (
            [remove_action, add_action]
            if target_already_has_template
            else [add_action, remove_action]
        )
        return {
            "action_type": "move_database_relation_template_to_storage_access",
            "requires_review": True,
            "source": {
                "subject_iri": source_resource.iri,
                "template_source": template_source,
                "predicate": "rc:pathTemplate",
                "template": template,
            },
            "target": {
                "storage_access_iri": storage_access.iri,
                "predicate": "rc:pathTemplate",
                "required_template_source": "storage_access",
            },
            "candidate_relation_identifier": {
                "value": template,
                "requires_review": True,
                "already_on_storage_access": target_already_has_template,
                "review_note": (
                    "Dataset and partition path templates are not database "
                    "relation identifiers by default; replace this value with "
                    "the reviewed schema/table/relation before staging the add."
                ),
            },
            "actions": actions,
        }

    def _query_database_relation_template_missing_repair_hint(
        self,
        storage_access: StorageAccessDescription,
    ) -> dict[str, Any]:
        return {
            "action_type": "record_database_relation_template",
            "requires_review": True,
            "source": {
                "storage_access_iri": storage_access.iri,
                "storage_root": storage_access.storage_root,
                "location_kind": storage_access.location_kind,
            },
            "target": {
                "storage_access_iri": storage_access.iri,
                "predicate": "rc:pathTemplate",
                "required_template_source": "storage_access",
            },
            "candidate_relation_identifier": {
                "value": "<reviewed_database_relation_identifier>",
                "requires_review": True,
                "review_note": (
                    "Review the database schema/table/relation identifier "
                    "before staging; the storage root is only the connection "
                    "reference."
                ),
            },
            "actions": [
                {
                    "action_type": "add_reviewed_relation_template",
                    "tool_name": "stage_map_assertion_change",
                    "mcp_tool_name": "doxabase.stage_map_assertion_change",
                    "required_extra_arguments": ["object", "rationale"],
                    "rationale_template": (
                        "Reviewed database relation identifier for "
                        f"{storage_access.iri}."
                    ),
                    "arguments_template": {
                        "subject": storage_access.iri,
                        "predicate": "rc:pathTemplate",
                        "object": "<reviewed_database_relation_identifier>",
                        "object_kind": "literal",
                        "change_kind": "add",
                        "graph": "map",
                    },
                    "placeholder_fields": ["object"],
                    "reviewed_value_fields": ["object"],
                    "condition": (
                        "Replace the placeholder object with the reviewed "
                        "schema, table, or relation identifier before staging."
                    ),
                }
            ],
        }

    def _query_candidate_metadata_issue(
        self,
        *,
        template: str,
        source_resource: ResourceSummary,
        storage_access: StorageAccessDescription,
    ) -> QueryPlanningIssue | None:
        mismatch_reasons = self._candidate_storage_location_mismatch_reasons(
            storage_access,
            template,
        )
        if not mismatch_reasons:
            return None
        source_label = source_resource.label or source_resource.iri
        return QueryPlanningIssue(
            code="storage_protocol_location_mismatch",
            severity="warning",
            message=(
                "Storage access metadata conflicts with path "
                f"template from {source_label}: "
                + "; ".join(mismatch_reasons)
                + ". Record protocol-appropriate storage metadata "
                "or simplify the template before executable use."
            ),
            resource=self._summary_from_description(storage_access),
            details={
                "template": template,
                "template_source_resource_iri": source_resource.iri,
                "storage_access_iri": storage_access.iri,
                "storage_protocol_iri": (
                    storage_access.storage_protocol.iri
                    if storage_access.storage_protocol is not None
                    else None
                ),
                "storage_root": storage_access.storage_root,
                "bucket_name": storage_access.bucket_name,
                "key_prefix": storage_access.key_prefix,
                "mismatch_reasons": mismatch_reasons,
                "repair_hint": self._storage_protocol_location_repair_hint(
                    storage_access,
                    mismatch_reasons=mismatch_reasons,
                    template=template,
                    template_source_resource=source_resource,
                ),
            },
        )

    def _storage_protocol_location_repair_hint(
        self,
        storage_access: StorageAccessDescription,
        *,
        mismatch_reasons: list[str],
        template: str | None = None,
        template_source_resource: ResourceSummary | None = None,
    ) -> dict[str, Any]:
        actions: list[dict[str, Any]] = [
            {
                "action_type": "set_reviewed_storage_protocol",
                "tool_name": "stage_map_assertion_change",
                "mcp_tool_name": "doxabase.stage_map_assertion_change",
                "required_extra_arguments": ["rationale"],
                "rationale_template": (
                    "Reviewed protocol for storage access "
                    f"{storage_access.iri}."
                ),
                "arguments_template": {
                    "subject": storage_access.iri,
                    "predicate": "rc:storageProtocol",
                    "object": "<reviewed_rc_storage_protocol_iri>",
                    "object_kind": "iri",
                    "change_kind": "replace",
                    "graph": "map",
                },
                "placeholder_fields": ["object"],
                "reviewed_value_fields": ["object"],
                "condition": (
                    "Use when review shows the recorded storage protocol is the "
                    "wrong one for the true storage location."
                ),
            },
            {
                "action_type": "set_reviewed_storage_root",
                "tool_name": "stage_map_assertion_change",
                "mcp_tool_name": "doxabase.stage_map_assertion_change",
                "required_extra_arguments": ["rationale"],
                "rationale_template": (
                    "Reviewed storage root or URL for storage access "
                    f"{storage_access.iri}."
                ),
                "arguments_template": {
                    "subject": storage_access.iri,
                    "predicate": "rc:storageRoot",
                    "object": "<reviewed_protocol_appropriate_root_url_or_connection>",
                    "object_kind": "literal",
                    "change_kind": "replace",
                    "graph": "map",
                },
                "placeholder_fields": ["object"],
                "reviewed_value_fields": ["object"],
                "condition": (
                    "Use when review shows the protocol is right but the root, "
                    "URL, or connection reference is malformed or in the wrong "
                    "scheme."
                ),
            },
            {
                "action_type": "set_reviewed_bucket_name",
                "tool_name": "stage_map_assertion_change",
                "mcp_tool_name": "doxabase.stage_map_assertion_change",
                "required_extra_arguments": ["rationale"],
                "rationale_template": (
                    "Reviewed bucket name for storage access "
                    f"{storage_access.iri}."
                ),
                "arguments_template": {
                    "subject": storage_access.iri,
                    "predicate": "rc:bucketName",
                    "object": "<reviewed_bucket_name>",
                    "object_kind": "literal",
                    "change_kind": "replace",
                    "graph": "map",
                },
                "placeholder_fields": ["object"],
                "reviewed_value_fields": ["object"],
                "condition": (
                    "Use for S3-compatible storage when review confirms the "
                    "bucket should be recorded separately from path templates."
                ),
            },
            {
                "action_type": "set_reviewed_key_prefix",
                "tool_name": "stage_map_assertion_change",
                "mcp_tool_name": "doxabase.stage_map_assertion_change",
                "required_extra_arguments": ["rationale"],
                "rationale_template": (
                    "Reviewed key prefix for storage access "
                    f"{storage_access.iri}."
                ),
                "arguments_template": {
                    "subject": storage_access.iri,
                    "predicate": "rc:keyPrefix",
                    "object": "<reviewed_key_prefix>",
                    "object_kind": "literal",
                    "change_kind": "replace",
                    "graph": "map",
                },
                "placeholder_fields": ["object"],
                "reviewed_value_fields": ["object"],
                "condition": (
                    "Use for S3-compatible storage when review confirms the "
                    "prefix should be recorded separately from path templates."
                ),
            },
        ]
        if storage_access.bucket_name:
            actions.append(
                {
                    "action_type": "remove_conflicting_bucket_name",
                    "tool_name": "stage_map_assertion_change",
                    "mcp_tool_name": "doxabase.stage_map_assertion_change",
                    "required_extra_arguments": ["rationale"],
                    "rationale_template": (
                        "Reviewed bucket metadata as inappropriate for storage "
                        f"access {storage_access.iri}."
                    ),
                    "arguments": {
                        "subject": storage_access.iri,
                        "predicate": "rc:bucketName",
                        "object": storage_access.bucket_name,
                        "object_kind": "literal",
                        "change_kind": "remove",
                        "graph": "map",
                    },
                    "condition": (
                        "Only after review confirms bucket metadata is wrong for "
                        "this storage protocol or should be represented elsewhere."
                    ),
                }
            )
        if storage_access.key_prefix:
            actions.append(
                {
                    "action_type": "remove_conflicting_key_prefix",
                    "tool_name": "stage_map_assertion_change",
                    "mcp_tool_name": "doxabase.stage_map_assertion_change",
                    "required_extra_arguments": ["rationale"],
                    "rationale_template": (
                        "Reviewed key-prefix metadata as inappropriate for "
                        f"storage access {storage_access.iri}."
                    ),
                    "arguments": {
                        "subject": storage_access.iri,
                        "predicate": "rc:keyPrefix",
                        "object": storage_access.key_prefix,
                        "object_kind": "literal",
                        "change_kind": "remove",
                        "graph": "map",
                    },
                    "condition": (
                        "Only after review confirms key-prefix metadata is wrong "
                        "for this storage protocol or duplicates the template."
                    ),
                }
            )
        if template is not None and template_source_resource is not None:
            actions.extend(
                [
                    {
                        "action_type": "add_reviewed_path_template",
                        "tool_name": "stage_map_assertion_change",
                        "mcp_tool_name": "doxabase.stage_map_assertion_change",
                        "required_extra_arguments": ["rationale"],
                        "rationale_template": (
                            "Reviewed protocol-appropriate path template for "
                            f"{template_source_resource.iri}."
                        ),
                        "arguments_template": {
                            "subject": template_source_resource.iri,
                            "predicate": "rc:pathTemplate",
                            "object": "<reviewed_protocol_appropriate_path_template>",
                            "object_kind": "literal",
                            "change_kind": "add",
                            "graph": "map",
                        },
                        "placeholder_fields": ["object"],
                        "reviewed_value_fields": ["object"],
                        "condition": (
                            "Use when review confirms the template value should "
                            "be corrected while preserving the source resource."
                        ),
                    },
                    {
                        "action_type": "remove_conflicting_path_template",
                        "tool_name": "stage_map_assertion_change",
                        "mcp_tool_name": "doxabase.stage_map_assertion_change",
                        "required_extra_arguments": ["rationale"],
                        "rationale_template": (
                            "Reviewed path template as conflicting with storage "
                            f"access {storage_access.iri}."
                        ),
                        "arguments": {
                            "subject": template_source_resource.iri,
                            "predicate": "rc:pathTemplate",
                            "object": template,
                            "object_kind": "literal",
                            "change_kind": "remove",
                            "graph": "map",
                        },
                        "condition": (
                            "Only after review confirms this exact template is "
                            "malformed, duplicated, or belongs on a different "
                            "storage access."
                        ),
                    },
                ]
            )
        hint: dict[str, Any] = {
            "action_type": "repair_storage_protocol_location_mismatch",
            "requires_review": True,
            "storage_access": {
                "storage_access_iri": storage_access.iri,
                "storage_protocol_iri": (
                    storage_access.storage_protocol.iri
                    if storage_access.storage_protocol is not None
                    else None
                ),
                "storage_root": storage_access.storage_root,
                "bucket_name": storage_access.bucket_name,
                "key_prefix": storage_access.key_prefix,
            },
            "mismatch_reasons": mismatch_reasons,
            "actions": actions,
        }
        if template is not None and template_source_resource is not None:
            hint["source"] = {
                "subject_iri": template_source_resource.iri,
                "predicate": "rc:pathTemplate",
                "template": template,
            }
        return hint

    def _query_target_candidate_metadata_issues(
        self,
        dataset: DatasetDescription,
        *,
        dataset_summary: ResourceSummary,
        direct_path_templates: list[str],
    ) -> list[QueryPlanningIssue]:
        if not dataset.storage_accesses:
            return []

        template_sources: list[tuple[str, str, ResourceSummary]] = [
            (template, "dataset", dataset_summary) for template in direct_path_templates
        ]
        template_sources.extend(
            (
                partition.path_template,
                "partition_scheme",
                self._summary_from_description(partition),
            )
            for partition in dataset.partition_schemes
            if partition.path_template is not None
        )

        issues: list[QueryPlanningIssue] = []
        for storage_access in dataset.storage_accesses:
            for template, template_source, source_resource in template_sources:
                object_location_issue = (
                    self._query_storage_object_location_template_issue(
                        template=template,
                        template_source=template_source,
                        source_resource=source_resource,
                        storage_access=storage_access,
                    )
                )
                if object_location_issue is not None:
                    issues.append(object_location_issue)
                relation_source_issue = (
                    self._query_database_relation_template_source_issue(
                        template=template,
                        template_source=template_source,
                        source_resource=source_resource,
                        storage_access=storage_access,
                    )
                )
                if relation_source_issue is not None:
                    issues.append(relation_source_issue)
                issue = self._query_candidate_metadata_issue(
                    template=template,
                    source_resource=source_resource,
                    storage_access=storage_access,
                )
                if issue is not None:
                    issues.append(issue)
            access_resource = self._summary_from_description(storage_access)
            for template in storage_access.path_templates:
                object_location_issue = (
                    self._query_storage_object_location_template_issue(
                        template=template,
                        template_source="storage_access",
                        source_resource=access_resource,
                        storage_access=storage_access,
                    )
                )
                if object_location_issue is not None:
                    issues.append(object_location_issue)
                issue = self._query_candidate_metadata_issue(
                    template=template,
                    source_resource=access_resource,
                    storage_access=storage_access,
                )
                if issue is not None:
                    issues.append(issue)
            if not template_sources and not storage_access.path_templates:
                issue = self._query_storage_access_location_kind_issue(storage_access)
                if issue is not None:
                    issues.append(issue)
        return issues

    def _query_storage_object_location_template_issue(
        self,
        *,
        template: str,
        template_source: str,
        source_resource: ResourceSummary,
        storage_access: StorageAccessDescription,
    ) -> QueryPlanningIssue | None:
        if self._is_database_storage(storage_access.storage_protocol):
            return None
        if storage_access.location_kind != "object" or not storage_access.storage_root:
            return None
        if template_source == "storage_access_location":
            return None
        source_label = source_resource.label or source_resource.iri
        access_resource = self._summary_from_description(storage_access)
        return QueryPlanningIssue(
            code="storage_object_location_has_path_template",
            severity="warning",
            message=(
                "Storage access location_kind='object' says the storage root "
                "names the dataset object/location exactly, but a path template "
                f"from {source_label} would be appended to that object root. "
                "Use the storage_access_location candidate for the exact object "
                "route, or model the storage root as a directory/prefix if "
                "templates should be joined."
            ),
            resource=access_resource,
            details={
                "template": template,
                "template_source": template_source,
                "template_source_resource_iri": source_resource.iri,
                "storage_access_iri": storage_access.iri,
                "storage_root": storage_access.storage_root,
                "location_kind": storage_access.location_kind,
            },
        )

    def _query_storage_access_location_kind_issue(
        self,
        storage_access: StorageAccessDescription,
    ) -> QueryPlanningIssue | None:
        if not storage_access.storage_root:
            return None
        if self._is_database_storage(storage_access.storage_protocol):
            return self._query_database_relation_template_missing_issue(
                storage_access
            )
        if storage_access.location_kind == "object":
            return None
        access_resource = self._summary_from_description(storage_access)
        if storage_access.location_kind is None:
            message = (
                "Storage root is the only candidate location, but location_kind "
                "is not recorded. Record location_kind='object' when the root "
                "names the dataset object/location exactly, or add a path "
                "template for directory, prefix, or connection roots."
            )
        else:
            message = (
                "Storage root is the only candidate location, but location_kind "
                f"is recorded as '{storage_access.location_kind}'. Add a path "
                "template before executable use, or record location_kind='object' "
                "when this root names the dataset object/location exactly."
            )
        return QueryPlanningIssue(
            code="storage_location_kind_needs_path_template",
            severity="warning",
            message=message,
            resource=access_resource,
        )

    def _query_database_relation_template_missing_issue(
        self,
        storage_access: StorageAccessDescription,
    ) -> QueryPlanningIssue:
        access_resource = self._summary_from_description(storage_access)
        return QueryPlanningIssue(
            code="database_relation_template_missing",
            severity="warning",
            message=(
                "Database storage root is the only candidate location, but no "
                "storage-access path_template records a relation identifier. "
                "Record the schema, table, or relation as a storage-access "
                "path_template before database handoff."
            ),
            resource=access_resource,
            details={
                "storage_access_iri": storage_access.iri,
                "storage_protocol_iri": (
                    storage_access.storage_protocol.iri
                    if storage_access.storage_protocol is not None
                    else None
                ),
                "storage_root": storage_access.storage_root,
                "location_kind": storage_access.location_kind,
                "allowed_relation_template_sources": ["storage_access"],
                "repair_hint": (
                    self._query_database_relation_template_missing_repair_hint(
                        storage_access
                    )
                ),
            },
        )

    def _query_candidate_path_status(
        self,
        candidate_path: str | None,
        *,
        review_required: bool,
        review_reasons: list[QueryPlanningIssue],
    ) -> str:
        if candidate_path is None or any(
            reason.code == "missing_storage_location" for reason in review_reasons
        ):
            return "unresolved"
        if review_required:
            return "orientation_only"
        return "ready"

    def _query_candidate_path(
        self,
        template: str,
        storage_access: StorageAccessDescription | None,
    ) -> tuple[str | None, str]:
        template = template.strip()
        if not template:
            return None, "unresolved"
        if self._is_complete_path_template(template):
            return template, "template_as_returned"
        if storage_access is None:
            return template, "template_as_returned"

        storage_root = (storage_access.storage_root or "").strip()
        if storage_root:
            if self._template_starts_with_root(template, storage_root):
                return template, "template_as_returned"
            return self._join_path_template(storage_root, template), "storage_root_joined"

        bucket_name = (storage_access.bucket_name or "").strip().strip("/")
        if bucket_name and self._is_s3_storage(storage_access.storage_protocol):
            parts = [bucket_name]
            key_prefix = (storage_access.key_prefix or "").strip().strip("/")
            if key_prefix:
                parts.append(key_prefix)
            parts.append(template.strip("/"))
            return f"s3://{'/'.join(parts)}", "bucket_prefix_joined"

        key_prefix = (storage_access.key_prefix or "").strip()
        if key_prefix:
            return self._join_path_template(key_prefix, template), "key_prefix_joined"

        return template, "template_as_returned"

    def _query_target_review_reasons(
        self,
        dataset: DatasetDescription,
        issues: list[QueryPlanningIssue],
        *,
        source_resource: ResourceSummary,
        storage_access: ResourceSummary | None,
    ) -> list[QueryPlanningIssue]:
        related_iris = {dataset.iri, source_resource.iri}
        if storage_access is not None:
            related_iris.add(storage_access.iri)
        related_iris.update(layout.iri for layout in dataset.physical_layouts)

        review_reasons: list[QueryPlanningIssue] = []
        seen: set[tuple[str, str | None]] = set()
        excluded_blockers: list[QueryPlanningIssue] = []
        for issue in issues:
            if self._is_candidate_metadata_issue(issue):
                continue
            resource_iri = issue.resource.iri if issue.resource is not None else None
            if resource_iri is not None and resource_iri not in related_iris:
                if issue.severity in {"error", "warning"}:
                    excluded_blockers.append(issue)
                continue
            key = (issue.code, resource_iri)
            if key in seen:
                continue
            seen.add(key)
            review_reasons.append(issue)
        if excluded_blockers:
            severity = (
                "error"
                if any(issue.severity == "error" for issue in excluded_blockers)
                else "warning"
            )
            excluded_resource_iris = [
                issue.resource.iri
                for issue in excluded_blockers
                if issue.resource is not None
            ]
            review_reasons.append(
                QueryPlanningIssue(
                    code="query_context_has_other_blockers",
                    severity=severity,
                    message=(
                        "Overall query context has "
                        f"{len(excluded_blockers)} blocking/review issue(s) "
                        "on other dataset metadata; inspect context.issues "
                        "before executing this candidate."
                    ),
                    resource=ResourceSummary(
                        iri=dataset.iri,
                        label=dataset.label or self._local_name(dataset.iri),
                        description=dataset.description,
                    ),
                    details={
                        "excluded_blocker_count": len(excluded_blockers),
                        "excluded_blocker_codes": self._query_issue_codes(
                            excluded_blockers
                        ),
                        "excluded_blocker_resource_iris": list(
                            dict.fromkeys(excluded_resource_iris)
                        ),
                    },
                )
            )
        return review_reasons

    def _is_candidate_metadata_issue(self, issue: QueryPlanningIssue) -> bool:
        if issue.code in {
            "database_relation_template_source_mismatch",
            "storage_object_location_has_path_template",
        }:
            return True
        return (
            issue.code == "storage_protocol_location_mismatch"
            and issue.message.startswith(
                "Storage access metadata conflicts with path template from "
            )
        )

    def _is_complete_path_template(self, template: str) -> bool:
        return bool(re.match(r"^[A-Za-z][A-Za-z0-9+.-]*://", template)) or template.startswith(
            "/"
        )

    def _template_starts_with_root(self, template: str, storage_root: str) -> bool:
        normalized_template = template.strip("/")
        normalized_root = storage_root.strip("/")
        if not normalized_root:
            return False
        return (
            normalized_template == normalized_root
            or normalized_template.startswith(f"{normalized_root}/")
        )

    def _join_path_template(self, root: str, template: str) -> str:
        cleaned_root = root.rstrip("/")
        cleaned_template = template.lstrip("/")
        if not cleaned_root:
            return f"/{cleaned_template}"
        return f"{cleaned_root}/{cleaned_template}"

    def _is_s3_storage(self, storage_protocol: ResourceSummary | None) -> bool:
        if storage_protocol is None:
            return False
        return storage_protocol.iri == self.expand_iri("rc:S3CompatibleStorage")

    def _is_https_storage(self, storage_protocol: ResourceSummary | None) -> bool:
        if storage_protocol is None:
            return False
        return storage_protocol.iri == self.expand_iri("rc:HTTPSStorage")

    def _is_database_storage(self, storage_protocol: ResourceSummary | None) -> bool:
        if storage_protocol is None:
            return False
        return storage_protocol.iri == self.expand_iri("rc:DatabaseStorage")

    def _is_local_filesystem_storage(
        self,
        storage_protocol: ResourceSummary | None,
    ) -> bool:
        if storage_protocol is None:
            return False
        return storage_protocol.iri == self.expand_iri("rc:LocalFilesystemStorage")

    def _storage_root_scheme(self, storage_root: str | None) -> str | None:
        if storage_root is None:
            return None
        match = re.match(r"^([A-Za-z][A-Za-z0-9+.-]*):", storage_root.strip())
        if match is None:
            return None
        return match.group(1).lower()

    def _path_template_scheme(self, template: str | None) -> str | None:
        if template is None:
            return None
        match = re.match(r"^([A-Za-z][A-Za-z0-9+.-]*)://", template.strip())
        if match is None:
            return None
        return match.group(1).lower()

    def _is_s3_scheme(self, scheme: str | None) -> bool:
        return scheme in {"s3", "s3a", "s3n"}

    def _s3_template_location(
        self,
        template: str,
    ) -> tuple[str, str] | None:
        match = re.match(
            r"^(?:s3|s3a|s3n)://([^/]+)(?:/(.*))?$",
            template.strip(),
            flags=re.IGNORECASE,
        )
        if match is None:
            return None
        return match.group(1), (match.group(2) or "").strip("/")

    def _looks_like_absolute_local_path(self, storage_root: str | None) -> bool:
        if storage_root is None:
            return False
        text = storage_root.strip()
        return text.startswith("/") or bool(re.match(r"^[A-Za-z]:[\\/]", text))

    def _s3_access_resolution_unrecorded(
        self,
        access: StorageAccessDescription,
    ) -> bool:
        if not self._is_s3_storage(access.storage_protocol):
            return False
        if access.endpoint_profile or access.credential_reference or access.region:
            return False
        if access.bucket_name or access.key_prefix:
            return True
        if self._is_s3_scheme(self._storage_root_scheme(access.storage_root)):
            return True
        return any(
            self._is_s3_scheme(self._path_template_scheme(template))
            for template in access.path_templates
        )

    def _candidate_storage_location_mismatch_reasons(
        self,
        access: StorageAccessDescription,
        template: str,
    ) -> list[str]:
        reasons: list[str] = []
        scheme = self._path_template_scheme(template)
        if access.storage_protocol is not None:
            if self._is_s3_storage(access.storage_protocol):
                if self._looks_like_absolute_local_path(template):
                    reasons.append("path template looks like a local filesystem path")
                elif scheme is not None and not self._is_s3_scheme(scheme):
                    reasons.append(
                        f"path template scheme '{scheme}' does not look like S3"
                    )
            elif self._is_https_storage(access.storage_protocol):
                if scheme not in {None, "http", "https"} or (
                    scheme is None and self._looks_like_absolute_local_path(template)
                ):
                    reasons.append("path template does not look like an HTTP(S) URL")
            elif self._is_local_filesystem_storage(access.storage_protocol):
                if scheme in {"s3", "s3a", "s3n", "http", "https"}:
                    reasons.append(
                        "path template looks remote for local filesystem access"
                    )

        s3_location = self._s3_template_location(template)
        if s3_location is not None:
            template_bucket, template_key = s3_location
            bucket_name = (access.bucket_name or "").strip().strip("/")
            if bucket_name and template_bucket != bucket_name:
                reasons.append(
                    "complete S3 path template bucket does not match recorded "
                    f"bucket_name '{bucket_name}'"
                )
            key_prefix = (access.key_prefix or "").strip().strip("/")
            if (
                key_prefix
                and template_key
                and template_key != key_prefix
                and not template_key.startswith(f"{key_prefix}/")
            ):
                reasons.append(
                    "complete S3 path template key does not start with recorded "
                    f"key_prefix '{key_prefix}'"
                )

        key_prefix = (access.key_prefix or "").strip().strip("/")
        normalized_template = template.strip().strip("/")
        if (
            key_prefix
            and scheme is None
            and not self._looks_like_absolute_local_path(template)
            and (
                normalized_template == key_prefix
                or normalized_template.startswith(f"{key_prefix}/")
            )
        ):
            reasons.append(
                f"path template appears to repeat recorded key_prefix '{key_prefix}'"
            )

        return reasons

    def _storage_protocol_location_mismatch_reasons(
        self,
        access: StorageAccessDescription,
    ) -> list[str]:
        reasons: list[str] = []
        if access.storage_protocol is None:
            return reasons
        if not self._is_s3_storage(access.storage_protocol) and (
            access.bucket_name or access.key_prefix
        ):
            reasons.append("bucket/prefix metadata is recorded for a non-S3 protocol")

        scheme = self._storage_root_scheme(access.storage_root)
        if self._is_s3_storage(access.storage_protocol):
            if self._looks_like_absolute_local_path(access.storage_root):
                reasons.append("storage_root looks like a local filesystem path")
        elif self._is_https_storage(access.storage_protocol):
            if scheme in {"s3", "s3a", "s3n", "file"} or (
                scheme is None
                and self._looks_like_absolute_local_path(access.storage_root)
            ):
                reasons.append("storage_root does not look like an HTTP(S) root")
        elif self._is_local_filesystem_storage(access.storage_protocol):
            if scheme in {"s3", "s3a", "s3n", "http", "https"}:
                reasons.append("storage_root looks remote for local filesystem access")
        return reasons

    def _query_planning_issues(
        self,
        dataset: DatasetDescription,
    ) -> list[QueryPlanningIssue]:
        issues: list[QueryPlanningIssue] = []

        def add_issue(
            code: str,
            severity: str,
            message: str,
            resource: ResourceSummary | None = None,
            details: dict[str, Any] | None = None,
        ) -> None:
            issues.append(
                QueryPlanningIssue(
                    code=code,
                    severity=severity,
                    message=message,
                    resource=resource,
                    details=details,
                )
            )

        dataset_resource = ResourceSummary(
            iri=dataset.iri,
            label=dataset.label or self._local_name(dataset.iri),
            description=dataset.description,
        )
        has_storage_root_location = any(
            access.storage_root for access in dataset.storage_accesses
        )
        if not dataset.path_templates and not has_storage_root_location:
            add_issue(
                "missing_path_template",
                "error",
                "No dataset, storage, or partition path template is recorded.",
                dataset_resource,
            )
        if not dataset.storage_accesses:
            add_issue(
                "missing_storage_access",
                "error",
                "No storage access resource is linked to the dataset.",
                dataset_resource,
                self._missing_storage_access_details(
                    dataset,
                    dataset_resource=dataset_resource,
                ),
            )
        for access in dataset.storage_accesses:
            access_resource = self._summary_from_description(access)
            if access.storage_protocol is None:
                add_issue(
                    "missing_storage_protocol",
                    "error",
                    "Storage access does not declare a storage protocol.",
                    access_resource,
                )
            has_location = any(
                [
                    access.storage_root,
                    access.bucket_name,
                    access.key_prefix,
                    access.path_templates,
                ]
            )
            if not has_location:
                add_issue(
                    "missing_storage_location",
                    "error",
                    "Storage access does not include a root, bucket, prefix, or path template.",
                    access_resource,
                )
            if self._s3_access_resolution_unrecorded(access):
                add_issue(
                    "s3_access_resolution_unrecorded",
                    "warning",
                    "S3-compatible access records S3 location metadata but no endpoint profile, credential reference, or region.",
                    access_resource,
                )
            location_mismatch_reasons = (
                self._storage_protocol_location_mismatch_reasons(access)
            )
            if location_mismatch_reasons:
                add_issue(
                    "storage_protocol_location_mismatch",
                    "warning",
                    (
                        "Storage access metadata conflicts with its protocol: "
                        + "; ".join(location_mismatch_reasons)
                        + ". Record a protocol-appropriate storage root, URL, "
                        "or connection reference before executable use."
                    ),
                    access_resource,
                    {
                        "storage_access_iri": access.iri,
                        "storage_protocol_iri": (
                            access.storage_protocol.iri
                            if access.storage_protocol is not None
                            else None
                        ),
                        "storage_root": access.storage_root,
                        "bucket_name": access.bucket_name,
                        "key_prefix": access.key_prefix,
                        "mismatch_reasons": location_mismatch_reasons,
                        "repair_hint": (
                            self._storage_protocol_location_repair_hint(
                                access,
                                mismatch_reasons=location_mismatch_reasons,
                            )
                        ),
                    },
                )
            self._add_layout_status_issue(
                issues,
                status=access.layout_verification_status,
                note=access.layout_verification_note,
                resource=access_resource,
                context="storage access",
                include_missing_status=has_location,
            )
        if not dataset.physical_layouts:
            add_issue(
                "missing_physical_layout",
                "warning",
                "No physical layout resource is linked to the dataset.",
                dataset_resource,
            )
        ambiguous_layout_issue = self._ambiguous_physical_layout_issue(
            dataset.physical_layouts,
            dataset_resource=dataset_resource,
        )
        if ambiguous_layout_issue is not None:
            issues.append(ambiguous_layout_issue)
        for layout in dataset.physical_layouts:
            layout_resource = self._summary_from_description(layout)
            if layout.file_format is None:
                add_issue(
                    "missing_file_format",
                    "warning",
                    "Physical layout does not declare a file format.",
                    layout_resource,
                )
            self._add_layout_status_issue(
                issues,
                status=layout.layout_verification_status,
                note=layout.layout_verification_note,
                resource=layout_resource,
                context="physical layout",
                include_missing_status=layout.file_format is not None,
            )
        self._add_layout_status_issue(
            issues,
            status=dataset.layout_verification_status,
            note=dataset.layout_verification_note,
            resource=dataset_resource,
            context="dataset layout",
            include_missing_status=bool(dataset.path_templates),
        )
        for partition in dataset.partition_schemes:
            self._add_layout_status_issue(
                issues,
                status=partition.layout_verification_status,
                note=partition.layout_verification_note,
                resource=self._summary_from_description(partition),
                context="partition scheme",
                include_missing_status=partition.path_template is not None,
            )

        return self._sort_query_planning_issues(issues)

    def _missing_storage_access_details(
        self,
        dataset: DatasetDescription,
        *,
        dataset_resource: ResourceSummary,
    ) -> dict[str, Any]:
        storage_access_count = self._count_type("rc:StorageAccess")
        (
            candidate_existing_storage_accesses,
            candidate_existing_storage_access_total,
        ) = self._missing_storage_existing_access_candidates(
            dataset,
            limit=8,
        )
        details: dict[str, Any] = {
            "dataset_iri": dataset.iri,
            "global_storage_access_count": storage_access_count,
            "repair_hint": {
                "action_type": "record_or_link_storage_access",
                "target_dataset_iri": dataset.iri,
                "candidate_existing_storage_accesses": (
                    candidate_existing_storage_accesses
                ),
                "candidate_existing_storage_access_count": len(
                    candidate_existing_storage_accesses
                ),
                "candidate_existing_storage_access_total_count": (
                    candidate_existing_storage_access_total
                ),
                "candidate_existing_storage_accesses_truncated": (
                    candidate_existing_storage_access_total
                    > len(candidate_existing_storage_accesses)
                ),
                "actions": [
                    {
                        "action_type": "record_reviewed_storage_access",
                        "tool_name": "record_map_storage_access",
                        "mcp_tool_name": "doxabase.record_map_storage_access",
                        "action_label": "Record storage access and link dataset",
                        "reason": (
                            "Use when review has identified the non-secret "
                            "storage protocol and location for this dataset."
                        ),
                        "required_extra_arguments": [
                            "iri",
                            "storage_protocol",
                            "storage_root",
                        ],
                        "arguments_template": {
                            "iri": "<reviewed storage access IRI>",
                            "datasets": [dataset.iri],
                            "storage_protocol": "<reviewed rc:StorageProtocol IRI>",
                            "storage_root": (
                                "<reviewed root, URL, bucket URI, or connection>"
                            ),
                            "path_templates": [
                                "<optional storage-owned path or relation template>"
                            ],
                        },
                        "placeholder_fields": ["path_templates"],
                        "reviewed_value_fields": ["path_templates"],
                        "condition": (
                            "Include path_templates only when the storage access "
                            "itself owns the path or database relation template. "
                            "Omit this optional field when the dataset or "
                            "partition already carries the reviewed path "
                            "template; duplicating it can create equivalent "
                            "query target candidates. Database relation "
                            "identifiers are the important exception and should "
                            "be storage-access-owned. For database storage, "
                            "rerun describe_query_context after recording the "
                            "relation; if the same relation-like value remains "
                            "on the dataset or partition, follow the "
                            "database_relation_template_source_mismatch repair "
                            "group to remove or move the misplaced template."
                        ),
                        "protocol_guidance": {
                            "file_or_object_storage": (
                                "Omit storage-owned path_templates when the "
                                "dataset or partition already owns the reviewed "
                                "file/object template."
                            ),
                            "rc:DatabaseStorage": (
                                "Use storage-owned path_templates for reviewed "
                                "database relation identifiers. Then rerun "
                                "describe_query_context and follow "
                                "database_relation_template_source_mismatch if "
                                "a dataset or partition still carries the same "
                                "relation-like template."
                            ),
                        },
                        "review_rationale_guidance": (
                            "record_map_storage_access writes current-best map "
                            "facts directly and does not record graph-revision "
                            "rationale. Preserve the reviewed rationale in the "
                            "calling workflow, or use a staged assertion helper "
                            "when durable review history is needed."
                        ),
                    },
                    {
                        "action_type": "stage_existing_storage_access_link",
                        "tool_name": "stage_map_assertion_change",
                        "mcp_tool_name": "doxabase.stage_map_assertion_change",
                        "action_label": (
                            "Stage link to an existing storage access"
                        ),
                        "reason": (
                            "Use when a suitable storage access resource already "
                            "exists and the dataset should link to it after "
                            "review."
                        ),
                        "required_extra_arguments": [
                            "object",
                            "rationale",
                        ],
                        "arguments_template": {
                            "subject": dataset.iri,
                            "predicate": "rc:hasStorageAccess",
                            "object": "<reviewed existing storage access IRI>",
                            "object_kind": "iri",
                            "change_kind": "add",
                            "rationale": "<reviewed rationale>",
                            "review_note": (
                                "Generated from missing_storage_access query "
                                "planning guidance; apply only after confirming "
                                "the storage access is the intended non-secret "
                                "route for this dataset."
                            ),
                            "validation_scope": "all",
                        },
                        "placeholder_fields": ["object"],
                        "reviewed_value_fields": ["object"],
                    },
                ],
            },
        }
        fixture_hint = self._known_fixture_missing_storage_access_hint(
            dataset_resource,
            storage_access_count=storage_access_count,
        )
        if fixture_hint is not None:
            details["fixture_staleness_hint"] = fixture_hint
        return details

    def _missing_storage_existing_access_candidates(
        self,
        dataset: DatasetDescription,
        *,
        limit: int,
    ) -> tuple[list[dict[str, Any]], int]:
        data_graphs = self._expand_graphs(["map"])
        lookup_graphs = self._lookup_graphs(data_graphs)
        dataset_templates = set(dataset.path_templates)
        candidates: list[tuple[int, str, str, dict[str, Any]]] = []
        for access_iri in self._subjects(
            data_graphs,
            "rdf:type",
            self.expand_iri("rc:StorageAccess"),
        ):
            access = self._describe_storage_access(
                access_iri,
                data_graphs,
                lookup_graphs,
            )
            match_reasons: list[str] = []
            score = 0
            if dataset_templates and dataset_templates & set(access.path_templates):
                match_reasons.append("shares_dataset_path_template")
                score += 100
            if access.storage_protocol is not None:
                match_reasons.append("declares_storage_protocol")
                score += 20
            if any(
                [
                    access.storage_root,
                    access.bucket_name,
                    access.key_prefix,
                    access.path_templates,
                ]
            ):
                match_reasons.append("has_location_metadata")
                score += 20
            if access.layout_verification_status is not None:
                match_reasons.append("has_layout_verification_status")
                score += 10
            label = access.label or self._local_name(access.iri)
            candidate = {
                "storage_access": to_jsonable(self._summary_from_description(access)),
                "storage_access_iri": access.iri,
                "storage_protocol": to_jsonable(access.storage_protocol),
                "location_kind": access.location_kind,
                "storage_root": access.storage_root,
                "bucket_name": access.bucket_name,
                "key_prefix": access.key_prefix,
                "path_templates": access.path_templates,
                "layout_verification_status": to_jsonable(
                    access.layout_verification_status
                ),
                "match_reasons": match_reasons,
                "review_note": (
                    "Candidate existing storage access found in the current map. "
                    "Link it only after reviewing that its protocol, location, "
                    "path/relation templates, and access mode fit this dataset."
                ),
            }
            candidates.append((-score, label, access.iri, candidate))

        sorted_candidates = sorted(candidates)
        selected_candidates: list[dict[str, Any]] = []
        for rank, (_score, _label, _iri, candidate) in enumerate(
            sorted_candidates[:limit],
            start=1,
        ):
            ranked_candidate = dict(candidate)
            ranked_candidate["candidate_rank"] = rank
            selected_candidates.append(ranked_candidate)
        return selected_candidates, len(sorted_candidates)

    def _known_fixture_missing_storage_access_hint(
        self,
        dataset_resource: ResourceSummary,
        *,
        storage_access_count: int,
    ) -> dict[str, Any] | None:
        if storage_access_count != 0:
            return None
        known_fixtures = [
            (
                "AIS",
                "https://richcanopy.org/example/manifest/ais#",
                ["DailyBroadcasts", "DailyIndex"],
            ),
            (
                "Polymarket",
                "https://richcanopy.org/example/manifest/polymarket#",
                [
                    "Markets",
                    "PriceSnapshots",
                    "TradeEvents",
                    "OrderBookSnapshots",
                    "MarketOutcomes",
                ],
            ),
        ]
        map_graphs = self._expand_graphs(["map"])
        present_tables: list[str] = []
        fixture_names: list[str] = []
        for fixture_name, namespace, local_names in known_fixtures:
            table_iris = [
                f"{namespace}{local_name}"
                for local_name in local_names
                if self._subject_exists(f"{namespace}{local_name}", map_graphs)
            ]
            if table_iris:
                fixture_names.append(fixture_name)
                present_tables.extend(table_iris)
        if not present_tables:
            return None
        dataset_matches_known_fixture = any(
            dataset_resource.iri == table_iri for table_iri in present_tables
        )
        return {
            "hint_type": "known_fixture_tables_without_storage_accesses",
            "fixture_names": fixture_names,
            "global_storage_access_count": storage_access_count,
            "known_fixture_table_iris": present_tables[:10],
            "dataset_matches_known_fixture": dataset_matches_known_fixture,
            "message": (
                "Known AIS or Polymarket fixture tables are present but no "
                "rc:StorageAccess resources exist in the capsule. Treat this "
                "capsule as stale or intentionally reduced for query-planning "
                "trials; load current fixtures into a scratch capsule before "
                "drawing conclusions about query-target behavior."
            ),
        }

    def _ambiguous_physical_layout_issue(
        self,
        physical_layouts: list[PhysicalLayoutDescription],
        *,
        dataset_resource: ResourceSummary,
    ) -> QueryPlanningIssue | None:
        signatures = self._physical_layout_signatures(physical_layouts)
        if len(signatures) <= 1:
            return None
        signature_details = [
            {
                "file_format_iri": signature[0],
                "compression_codec_iri": signature[1],
                "layout_iris": [
                    layout.iri
                    for layout in layouts
                ],
            }
            for signature, layouts in signatures.items()
        ]
        return QueryPlanningIssue(
            code="ambiguous_physical_layout",
            severity="warning",
            message=(
                "Multiple linked physical layouts declare distinct file formats "
                "or compression codecs. Select or model the layout that belongs "
                "to the chosen query target before inferring a scan function."
            ),
            resource=dataset_resource,
            details={
                "layout_count": len(physical_layouts),
                "distinct_layout_signature_count": len(signatures),
                "layout_signatures": signature_details,
            },
        )

    @staticmethod
    def _physical_layout_signatures(
        physical_layouts: list[PhysicalLayoutDescription],
    ) -> dict[tuple[str | None, str | None], list[PhysicalLayoutDescription]]:
        signatures: dict[
            tuple[str | None, str | None],
            list[PhysicalLayoutDescription],
        ] = {}
        for layout in physical_layouts:
            signature = (
                layout.file_format.iri if layout.file_format is not None else None,
                (
                    layout.compression_codec.iri
                    if layout.compression_codec is not None
                    else None
                ),
            )
            signatures.setdefault(signature, []).append(layout)
        return signatures

    def _sort_query_planning_issues(
        self,
        issues: Iterable[QueryPlanningIssue],
    ) -> list[QueryPlanningIssue]:
        deduped: list[QueryPlanningIssue] = []
        seen: set[tuple[str, str, str, str | None]] = set()
        for issue in issues:
            key = (
                issue.code,
                issue.severity,
                issue.message,
                issue.resource.iri if issue.resource is not None else None,
            )
            if key in seen:
                continue
            seen.add(key)
            deduped.append(issue)
        severity_rank = {"error": 0, "warning": 1, "info": 2}
        return sorted(
            deduped,
            key=lambda issue: (
                severity_rank.get(issue.severity, 3),
                issue.code,
                issue.resource.iri if issue.resource is not None else "",
                issue.message,
            ),
        )

    def _query_planning_readiness(
        self,
        issues: list[QueryPlanningIssue],
    ) -> str:
        if any(issue.code == "contradicted_layout" for issue in issues):
            return "blocked_by_contradiction"
        if any(issue.severity == "error" for issue in issues):
            return "insufficient_metadata"
        if any(issue.severity == "warning" for issue in issues):
            return "needs_review"
        return "ready_for_query_planning"

    def _query_analysis_warnings(
        self,
        dataset: DatasetDescription,
    ) -> list[QueryPlanningIssue]:
        warnings: list[QueryPlanningIssue] = []
        seen: set[tuple[str, str]] = set()
        for scope, caveats in (
            ("direct", dataset.caveats),
            ("upstream", dataset.upstream_caveats),
        ):
            for caveat in caveats:
                key = (scope, caveat.iri)
                if key in seen:
                    continue
                seen.add(key)
                summary = self._summary_from_description(caveat)
                severity = self._analysis_caveat_severity(caveat.severity)
                label = (
                    caveat.label or caveat.description or caveat.iri
                ).strip()
                label = label.rstrip(".?!")
                message = (
                    f"{scope.capitalize()} caveat may affect query interpretation: "
                    f"{label}."
                )
                if caveat.impact:
                    message = f"{message} Impact: {caveat.impact}"
                warnings.append(
                    QueryPlanningIssue(
                        code=f"{scope}_analysis_caveat",
                        severity=severity,
                        message=message,
                        domain="analysis",
                        resource=summary,
                        details={
                            "scope": scope,
                            "caveat_iri": caveat.iri,
                            "caveat_label": caveat.label,
                            "caveat_description": caveat.description,
                            "caveat_impact": caveat.impact,
                            "caveat_severity_iri": (
                                caveat.severity.iri
                                if caveat.severity is not None
                                else None
                            ),
                            "caveat_severity_label": (
                                caveat.severity.label
                                if caveat.severity is not None
                                else None
                            ),
                        },
                    )
                )
        severity_rank = {"warning": 0, "info": 1}
        return sorted(
            warnings,
            key=lambda warning: (
                severity_rank.get(warning.severity, 2),
                warning.code,
                warning.resource.iri if warning.resource is not None else "",
            ),
        )

    def _analysis_caveat_severity(
        self,
        severity: ResourceSummary | None,
    ) -> str:
        if severity is None:
            return "info"
        if severity.iri in {
            self.expand_iri("rc:Moderate"),
            self.expand_iri("rc:Severe"),
        }:
            return "warning"
        return "info"

    def _query_readiness_note(
        self,
        readiness: str,
        *,
        issues: list[QueryPlanningIssue],
        analysis_warnings: list[QueryPlanningIssue],
    ) -> str:
        notes = {
            "ready_for_query_planning": (
                "Enough non-secret physical metadata is present to plan a query."
            ),
            "needs_review": (
                "Physical query planning is possible, but metadata warnings should "
                "be reviewed first."
            ),
            "insufficient_metadata": (
                "Required physical metadata is missing, so query planning is "
                "incomplete."
            ),
            "blocked_by_contradiction": (
                "A layout contradiction blocks physical query planning until it is "
                "resolved."
            ),
        }
        note = notes.get(readiness, "Query planning readiness is unknown.")
        if any(issue.severity == "info" for issue in issues):
            note = (
                f"{note} Informational physical metadata notes are present but "
                "do not block planning."
            )
        if analysis_warnings:
            note = (
                f"{note} Analysis warnings are separate caveats to review before "
                "trusting aggregations or interpretations."
            )
        return note

    def _add_layout_status_issue(
        self,
        issues: list[QueryPlanningIssue],
        *,
        status: ResourceSummary | None,
        note: str | None,
        resource: ResourceSummary,
        context: str,
        include_missing_status: bool = False,
    ) -> None:
        if status is None:
            if include_missing_status:
                message = (
                    f"No layout verification status is recorded for {context}; "
                    "treat the path/layout metadata as needing confirmation "
                    "before executable use."
                )
                if note:
                    message = f"{message} Note: {note}"
                issues.append(
                    QueryPlanningIssue(
                        code="verification_status_not_recorded",
                        severity="info",
                        message=message,
                        resource=resource,
                    )
                )
            return
        verified_statuses = {
            self.expand_iri("rc:VerifiedByListingLayout"),
            self.expand_iri("rc:VerifiedByQueryLayout"),
        }
        if status.iri in verified_statuses:
            return
        if status.iri == self.expand_iri("rc:ContradictedLayout"):
            severity = "error"
            code = "contradicted_layout"
            message = f"{context} is marked contradicted."
        else:
            severity = "warning"
            code = "layout_needs_verification"
            message = f"{context} has not been verified by listing or query."
        if note:
            message = f"{message} Note: {note}"
        issues.append(
            QueryPlanningIssue(
                code=code,
                severity=severity,
                message=message,
                resource=resource,
            )
        )

    def _summary_from_description(self, description: Any) -> ResourceSummary:
        return ResourceSummary(
            iri=description.iri,
            label=description.label or self._local_name(description.iri),
            description=description.description,
        )

    def _upstream_caveats_for_dataset(
        self,
        direct_caveat_iris: Iterable[str],
        relationships: Iterable[RelationshipDescription],
    ) -> list[CaveatDescription]:
        direct_caveat_set = set(direct_caveat_iris)
        upstream_by_iri: dict[str, CaveatDescription] = {}
        for relationship in relationships:
            for caveat in relationship.source_caveats:
                if caveat.iri not in direct_caveat_set:
                    upstream_by_iri.setdefault(caveat.iri, caveat)
        return sorted(
            upstream_by_iri.values(),
            key=lambda caveat: (caveat.label or "", caveat.iri),
        )

    def _profile_observations_for_target(
        self,
        *,
        target_iri: str,
        target_predicate: str,
        exclude_observed_column: bool = False,
        limit: int | None = 5,
    ) -> list[ProfileObservationSummary]:
        lookup_graphs = self._lookup_graphs(self._expand_graphs(["all"]))
        observation_iris = self._profile_observation_iris_for_target(
            target_iri=target_iri,
            target_predicate=target_predicate,
            exclude_observed_column=exclude_observed_column,
        )
        summaries = [
            self._profile_observation_summary(observation_iri, lookup_graphs)
            for observation_iri in observation_iris
        ]
        summaries.sort(
            key=self._profile_observation_sort_key,
            reverse=True,
        )
        return summaries if limit is None else summaries[:limit]

    def _profile_observation_sort_key(
        self,
        profile: ProfileObservationSummary,
    ) -> tuple[str, str, str]:
        return (
            profile.observed_at or "",
            profile.summary or "",
            profile.iri,
        )

    def _missing_dataset_profile_hint(
        self,
        dataset_iri: str,
        display_iri: str,
    ) -> str:
        profile_observation_iris = self._profile_observation_iris_for_target(
            target_iri=dataset_iri,
            target_predicate="rc:observedAsset",
        )
        if not profile_observation_iris:
            return ""
        evidence_counts: dict[str, int] = {}
        for observation_iri in profile_observation_iris:
            for evidence_iri in self._objects(
                ["observations"],
                observation_iri,
                "rc:evidence",
            ):
                evidence_counts[evidence_iri] = evidence_counts.get(evidence_iri, 0) + 1
        hint = (
            f"; {len(profile_observation_iris)} profile observation(s) reference "
            "this dataset in the observations graph. "
        )
        if evidence_counts:
            evidence_iri = sorted(
                evidence_counts,
                key=lambda item: (-evidence_counts[item], item),
            )[0]
            hint += (
                "For a profile-only handoff, try "
                f"describe_profile_run({display_iri!r}, {evidence_iri!r}) or "
            )
        else:
            hint += "For a profile-only handoff, "
        return (
            hint
            + "seed describe_context_slice from the profile observation IRIs. "
            "Record map dataset context with record_map_dataset before using "
            "describe_dataset."
        )

    def _profile_observation_iris_for_target(
        self,
        *,
        target_iri: str,
        target_predicate: str,
        exclude_observed_column: bool = False,
    ) -> list[str]:
        observation_graphs = ["observations"]
        profile_type = self.expand_iri("rc:ProfileObservation")
        return [
            observation_iri
            for observation_iri in self._subjects(
                observation_graphs,
                target_predicate,
                target_iri,
            )
            if profile_type
            in self._types_from_graphs(observation_graphs, observation_iri)
            and (
                not exclude_observed_column
                or self._first_object(
                    observation_graphs,
                    observation_iri,
                    "rc:observedColumn",
                )
                is None
            )
        ]

    def _profile_observation_count_for_target(
        self,
        *,
        target_iri: str,
        target_predicate: str,
        exclude_observed_column: bool = False,
    ) -> int:
        return len(
            self._profile_observation_iris_for_target(
                target_iri=target_iri,
                target_predicate=target_predicate,
                exclude_observed_column=exclude_observed_column,
            )
        )

    def _unmapped_column_profile_observations_for_dataset(
        self,
        dataset_iri: str,
        *,
        mapped_column_iris: Iterable[str],
        limit: int | None = 5,
    ) -> list[ProfileObservationSummary]:
        mapped_columns = set(mapped_column_iris)
        profile_observations = self._profile_observations_for_target(
            target_iri=dataset_iri,
            target_predicate="rc:observedAsset",
            limit=None,
        )
        return [
            profile
            for profile in profile_observations
            if profile.observed_column is not None
            and profile.observed_column.iri not in mapped_columns
        ][:limit]

    def _profiles_with_evidence(
        self,
        profiles: Iterable[ProfileObservationSummary],
        evidence_iri: str,
    ) -> list[ProfileObservationSummary]:
        return [
            profile
            for profile in profiles
            if any(evidence.iri == evidence_iri for evidence in profile.evidence)
        ]

    def _unmapped_column_profile_observation_count_for_dataset(
        self,
        dataset_iri: str,
        *,
        mapped_column_iris: Iterable[str],
    ) -> int:
        mapped_columns = set(mapped_column_iris)
        observation_graphs = ["observations"]
        return sum(
            1
            for observation_iri in self._profile_observation_iris_for_target(
                target_iri=dataset_iri,
                target_predicate="rc:observedAsset",
            )
            if (
                observed_column := self._first_object(
                    observation_graphs,
                    observation_iri,
                    "rc:observedColumn",
                )
            )
            is not None
            and observed_column not in mapped_columns
        )

    def _profile_summary(
        self,
        dataset_profiles: list[ProfileObservationSummary],
        columns: list[ColumnDescription],
        unmapped_column_profiles: list[ProfileObservationSummary],
        *,
        total_dataset_profile_count: int,
        total_mapped_column_profile_count: int,
        total_unmapped_column_profile_count: int,
        row_count_snapshot: int | None = None,
    ) -> ProfileSummary:
        mapped_column_profile_count = sum(
            len(column.profile_observations) for column in columns
        )
        mapped_profiled_column_count = sum(
            1 for column in columns if column.profile_observations
        )
        dataset_profile_count = len(dataset_profiles)
        unmapped_column_profile_count = len(unmapped_column_profiles)
        returned_profiles = [
            *dataset_profiles,
            *unmapped_column_profiles,
            *(
                profile
                for column in columns
                for profile in column.profile_observations
            ),
        ]
        evidence_profile_counts: dict[str, int] = {}
        evidence_profile_iris: dict[str, list[str]] = {}
        for profile in returned_profiles:
            for evidence_iri in {
                evidence.iri for evidence in profile.evidence if evidence.iri
            }:
                evidence_profile_iris.setdefault(evidence_iri, []).append(profile.iri)
        evidence_profile_counts = {
            evidence_iri: len(profile_iris)
            for evidence_iri, profile_iris in evidence_profile_iris.items()
        }
        evidence_iris = sorted(evidence_profile_counts)
        returned_profile_count = (
            dataset_profile_count
            + mapped_column_profile_count
            + unmapped_column_profile_count
        )
        total_profile_count = (
            total_dataset_profile_count
            + total_mapped_column_profile_count
            + total_unmapped_column_profile_count
        )
        omitted_dataset_profile_count = max(
            total_dataset_profile_count - dataset_profile_count,
            0,
        )
        omitted_mapped_column_profile_count = max(
            total_mapped_column_profile_count - mapped_column_profile_count,
            0,
        )
        omitted_unmapped_column_profile_count = max(
            total_unmapped_column_profile_count - unmapped_column_profile_count,
            0,
        )
        omitted_profile_count = max(total_profile_count - returned_profile_count, 0)
        shared_evidence_iris = [
            evidence_iri
            for evidence_iri in evidence_iris
            if returned_profile_count > 0
            and evidence_profile_counts[evidence_iri] == returned_profile_count
        ]
        dataset_profile_row_counts_by_evidence: dict[str, list[int]] = {}
        dataset_profile_row_count_bases_by_evidence: dict[
            str,
            dict[int, set[str]],
        ] = {}
        for profile in dataset_profiles:
            if profile.row_count is None:
                continue
            basis = self._profile_observation_basis(profile)
            for evidence_iri in {
                evidence.iri for evidence in profile.evidence if evidence.iri
            }:
                dataset_profile_row_counts_by_evidence.setdefault(
                    evidence_iri,
                    [],
                ).append(profile.row_count)
                dataset_profile_row_count_bases_by_evidence.setdefault(
                    evidence_iri,
                    {},
                ).setdefault(profile.row_count, set()).add(basis)
        profile_run_candidates = [
            ProfileRunCandidate(
                evidence_iri=evidence_iri,
                returned_profile_count=evidence_profile_counts[evidence_iri],
                profile_observation_iris=evidence_profile_iris[evidence_iri],
                dataset_profile_row_counts=sorted(
                    set(dataset_profile_row_counts_by_evidence.get(evidence_iri, []))
                ),
                dataset_profile_row_count_bases={
                    str(row_count): sorted(bases)
                    for row_count, bases in sorted(
                        dataset_profile_row_count_bases_by_evidence.get(
                            evidence_iri,
                            {},
                        ).items()
                    )
                },
                row_count_snapshot_matches=(
                    row_count_snapshot is not None
                    and row_count_snapshot
                    in dataset_profile_row_counts_by_evidence.get(evidence_iri, [])
                ),
                row_count_snapshot_basis=self._profile_row_count_snapshot_basis(
                    row_count_snapshot,
                    dataset_profile_row_count_bases_by_evidence.get(
                        evidence_iri,
                        {},
                    ),
                ),
                shared_by_all_returned_profiles=(
                    returned_profile_count > 0
                    and evidence_profile_counts[evidence_iri]
                    == returned_profile_count
                ),
            )
            for evidence_iri in evidence_iris
            if evidence_profile_counts[evidence_iri] > 1
        ]
        profile_run_candidates.sort(
            key=lambda candidate: (
                -candidate.returned_profile_count,
                not candidate.row_count_snapshot_matches,
                candidate.evidence_iri,
            )
        )
        return ProfileSummary(
            returned_dataset_profile_count=dataset_profile_count,
            returned_mapped_column_profile_count=mapped_column_profile_count,
            returned_unmapped_column_profile_count=unmapped_column_profile_count,
            returned_profile_count=returned_profile_count,
            total_dataset_profile_count=total_dataset_profile_count,
            total_mapped_column_profile_count=total_mapped_column_profile_count,
            total_unmapped_column_profile_count=(
                total_unmapped_column_profile_count
            ),
            total_profile_count=total_profile_count,
            omitted_dataset_profile_count=omitted_dataset_profile_count,
            omitted_mapped_column_profile_count=omitted_mapped_column_profile_count,
            omitted_unmapped_column_profile_count=(
                omitted_unmapped_column_profile_count
            ),
            omitted_profile_count=omitted_profile_count,
            mapped_profiled_column_count=mapped_profiled_column_count,
            evidence_iris=evidence_iris,
            evidence_profile_counts=evidence_profile_counts,
            shared_evidence_iris=shared_evidence_iris,
            profile_run_candidates=profile_run_candidates,
            handoff_note=self._profile_handoff_note(
                returned_profile_count=returned_profile_count,
                unmapped_column_profile_count=unmapped_column_profile_count,
                shared_evidence_count=len(shared_evidence_iris),
                omitted_profile_count=omitted_profile_count,
            ),
        )

    @staticmethod
    def _profile_row_count_snapshot_basis(
        row_count_snapshot: int | None,
        row_count_bases: dict[int, set[str]],
    ) -> str | None:
        if row_count_snapshot is None or row_count_snapshot not in row_count_bases:
            return None
        bases = sorted(row_count_bases[row_count_snapshot])
        if len(bases) == 1:
            return bases[0]
        return "mixed"

    def _profile_observation_basis(self, profile: ProfileObservationSummary) -> str:
        return self._profile_observation_basis_from_values(
            sample_size=profile.sample_size,
            sample_scope=profile.sample_scope,
            sample_method=profile.sample_method,
            row_count=profile.row_count,
        )

    @staticmethod
    def _profile_observation_basis_from_values(
        *,
        sample_size: int | None,
        sample_scope: str | None,
        sample_method: str | None,
        row_count: int | None,
    ) -> str:
        text = " ".join(
            value.lower()
            for value in (sample_method, sample_scope)
            if value
        )
        sample_markers = ("sample", "sampled", "sampling")
        if any(marker in text for marker in sample_markers):
            return "sample"
        full_scan_markers = (
            "full scan",
            "full-table",
            "full table",
            "complete scan",
            "all rows",
            "all records",
            "entire table",
            "whole table",
        )
        if (
            any(marker in text for marker in full_scan_markers)
            or (
                sample_size is not None
                and row_count is not None
                and sample_size == row_count
            )
        ):
            return "full_scan"
        if sample_size is not None or "sample" in text:
            return "sample"
        return "unknown"

    def _profile_map_column_name(
        self,
        column: ColumnDescription,
        profile: ProfileObservationSummary,
    ) -> str:
        return (
            column.column_name
            or profile.observed_column_name
            or (profile.observed_column.column_name if profile.observed_column else None)
            or (profile.observed_column.label if profile.observed_column else None)
            or column.iri.rsplit("#", 1)[-1].rsplit("/", 1)[-1]
        )

    def _profile_observed_column_name(
        self,
        profile: ProfileObservationSummary,
    ) -> str | None:
        if profile.observed_column is None:
            return None
        return (
            profile.observed_column_name
            or profile.observed_column.column_name
            or profile.observed_column.label
            or profile.observed_column.iri.rsplit("#", 1)[-1].rsplit("/", 1)[-1]
        )

    def _profile_type_finding_advisories(
        self,
        profiles: list[ProfileObservationSummary],
        evidence_iri: str,
        *,
        columns_by_iri: dict[str, ColumnDescription],
        recommendations: list[ProfileMapUpdateRecommendation],
    ) -> list[ProfileTypeFindingAdvisory]:
        advisories: list[ProfileTypeFindingAdvisory] = []
        for profile in profiles:
            if profile.observed_column is None:
                continue
            if (
                profile.observed_physical_type is None
                and profile.observed_value_type is None
            ):
                continue
            column = columns_by_iri.get(profile.observed_column.iri)
            current_physical_type = column.physical_type if column is not None else None
            current_value_type = column.value_type if column is not None else None
            if column is not None and self._profile_type_finding_matches_current_map(
                profile,
                current_physical_type=current_physical_type,
                current_value_type=current_value_type,
            ):
                continue
            advisory_status = self._profile_type_advisory_status(
                profile,
                map_column_found=column is not None,
                current_physical_type=current_physical_type,
                current_value_type=current_value_type,
            )
            related_recommendations = (
                self._profile_type_related_recommendations(
                    profile,
                    recommendations,
                    advisory_status=advisory_status,
                )
            )
            related_recommendation_indexes = [
                recommendation.recommendation_index
                for recommendation in related_recommendations
            ]
            related_recommendation_kinds = list(
                dict.fromkeys(
                    recommendation.kind for recommendation in related_recommendations
                )
            )
            value_type_promotion_pattern_iris = (
                self._profile_value_type_promotion_pattern_iris(
                    value_type_iri=profile.observed_value_type.iri,
                    evidence_iri=evidence_iri,
                )
                if profile.observed_value_type is not None
                and self._profile_value_type_needs_ontology_skeleton(
                    profile.observed_value_type.iri
                )
                else []
            )
            suggested_next_actions = self._profile_type_advisory_actions(
                profile=profile,
                evidence_iri=evidence_iri,
                advisory_status=advisory_status,
                map_column_found=column is not None,
                current_physical_type=current_physical_type,
                current_value_type=current_value_type,
                value_type_promotion_pattern_iris=(
                    value_type_promotion_pattern_iris
                ),
            )
            advisories.append(
                ProfileTypeFindingAdvisory(
                    profile_observation_iri=profile.iri,
                    type_advisory_index=len(advisories),
                    evidence_iri=evidence_iri,
                    observed_column=profile.observed_column,
                    observed_column_name=profile.observed_column_name,
                    observed_physical_type=profile.observed_physical_type,
                    observed_value_type=profile.observed_value_type,
                    map_column_found=column is not None,
                    current_physical_type=current_physical_type,
                    current_value_type=current_value_type,
                    promotion_patterns=self._resource_summaries(
                        self._lookup_graphs(["patterns"]),
                        value_type_promotion_pattern_iris,
                    ),
                    promotion_pattern_count=len(value_type_promotion_pattern_iris),
                    mixed_support_patterns=[],
                    mixed_support_pattern_count=0,
                    mixed_support_note=None,
                    advisory_status=advisory_status,
                    recommendation="review_profile_type_finding_before_map_update",
                    rationale=self._profile_type_advisory_rationale(
                        profile,
                        advisory_status=advisory_status,
                    ),
                    routing_note=self._profile_type_advisory_routing_note(
                        advisory_status,
                        related_recommendation_indexes=(
                            related_recommendation_indexes
                        ),
                        related_recommendation_kinds=related_recommendation_kinds,
                    ),
                    related_recommendation_indexes=related_recommendation_indexes,
                    related_recommendation_kinds=related_recommendation_kinds,
                    suggested_next_actions=suggested_next_actions,
                    suggested_next_calls=[
                        action.call for action in suggested_next_actions
                    ],
                )
            )
        return self._with_profile_type_advisory_duplicate_metadata(advisories)

    @staticmethod
    def _profile_type_related_recommendations(
        profile: ProfileObservationSummary,
        recommendations: list[ProfileMapUpdateRecommendation],
        *,
        advisory_status: str,
    ) -> list[ProfileMapUpdateRecommendation]:
        if (
            advisory_status != "type_finding_unmapped_column"
            or profile.observed_column is None
        ):
            return []
        return [
            recommendation
            for recommendation in recommendations
            if recommendation.kind == "unmapped_profiled_column"
            and recommendation.profile_observation_iri == profile.iri
            and recommendation.resource.iri == profile.observed_column.iri
        ]

    @staticmethod
    def _profile_type_finding_matches_current_map(
        profile: ProfileObservationSummary,
        *,
        current_physical_type: ResourceSummary | None,
        current_value_type: ResourceSummary | None,
    ) -> bool:
        if (
            profile.observed_physical_type is not None
            and (
                current_physical_type is None
                or current_physical_type.iri != profile.observed_physical_type.iri
            )
        ):
            return False
        if (
            profile.observed_value_type is not None
            and (
                current_value_type is None
                or current_value_type.iri != profile.observed_value_type.iri
            )
        ):
            return False
        return True

    def _profile_type_advisory_status(
        self,
        profile: ProfileObservationSummary,
        *,
        map_column_found: bool,
        current_physical_type: ResourceSummary | None,
        current_value_type: ResourceSummary | None,
    ) -> str:
        if not map_column_found:
            return "type_finding_unmapped_column"
        conflicts = False
        missing = False
        if profile.observed_physical_type is not None:
            if current_physical_type is None:
                missing = True
            elif current_physical_type.iri != profile.observed_physical_type.iri:
                conflicts = True
        if profile.observed_value_type is not None:
            if current_value_type is None:
                missing = True
            elif current_value_type.iri != profile.observed_value_type.iri:
                conflicts = True
        if conflicts:
            return "type_finding_conflicts_current_map"
        if missing:
            return "type_finding_missing_map_type"
        return "type_finding_needs_review"

    def _with_profile_type_advisory_duplicate_metadata(
        self,
        advisories: list[ProfileTypeFindingAdvisory],
    ) -> list[ProfileTypeFindingAdvisory]:
        groups: dict[str, list[tuple[int, ProfileTypeFindingAdvisory]]] = {}
        for index, advisory in enumerate(advisories):
            groups.setdefault(
                self._profile_type_advisory_duplicate_group_key(advisory),
                [],
            ).append((index, advisory))

        annotated: list[ProfileTypeFindingAdvisory] = []
        for index, advisory in enumerate(advisories):
            group_key = self._profile_type_advisory_duplicate_group_key(advisory)
            group = groups[group_key]
            duplicate_advisory_indexes = [group_index for group_index, _ in group]
            duplicate_profile_observation_iris = list(
                dict.fromkeys(item.profile_observation_iri for _, item in group)
            )
            related_recommendation_indexes = list(
                dict.fromkeys(
                    recommendation_index
                    for _, item in group
                    for recommendation_index in item.related_recommendation_indexes
                )
            )
            related_recommendation_kinds = list(
                dict.fromkeys(
                    recommendation_kind
                    for _, item in group
                    for recommendation_kind in item.related_recommendation_kinds
                )
            )
            suggested_next_actions = (
                self._profile_type_advisory_actions_with_duplicate_support(
                    advisory.suggested_next_actions,
                    duplicate_profile_observation_iris,
                )
            )
            annotated.append(
                replace(
                    advisory,
                    type_advisory_index=index,
                    duplicate_group_key=group_key,
                    duplicate_count=len(group),
                    duplicate_advisory_indexes=duplicate_advisory_indexes,
                    duplicate_profile_observation_iris=(
                        duplicate_profile_observation_iris
                    ),
                    related_recommendation_indexes=related_recommendation_indexes,
                    related_recommendation_kinds=related_recommendation_kinds,
                    routing_note=self._profile_type_advisory_routing_note(
                        advisory.advisory_status,
                        related_recommendation_indexes=(
                            related_recommendation_indexes
                        ),
                        related_recommendation_kinds=related_recommendation_kinds,
                    ),
                    suggested_next_actions=suggested_next_actions,
                    suggested_next_calls=[
                        action.call for action in suggested_next_actions
                    ],
                )
            )
        return annotated

    def _profile_type_advisory_actions_with_duplicate_support(
        self,
        actions: list[SuggestedNextAction],
        duplicate_profile_observation_iris: list[str],
    ) -> list[SuggestedNextAction]:
        if not duplicate_profile_observation_iris:
            return actions
        updated_actions: list[SuggestedNextAction] = []
        for action in actions:
            arguments = dict(action.arguments)
            if action.tool_name == "describe_context_slice":
                seed_iris = list(arguments.get("seed_iris") or [])
                arguments["seed_iris"] = list(
                    dict.fromkeys(
                        [*duplicate_profile_observation_iris, *seed_iris]
                    )
                )
            elif action.tool_name in {
                "record_pattern",
                "stage_map_assertion_change",
            }:
                arguments["supporting_observations"] = (
                    duplicate_profile_observation_iris
                )
                if (
                    action.tool_name == "stage_map_assertion_change"
                    and len(duplicate_profile_observation_iris) > 1
                ):
                    arguments["rationale"] = (
                        "Duplicate profile observations "
                        f"{', '.join(duplicate_profile_observation_iris)} "
                        f"recorded {arguments.get('predicate')} "
                        f"{arguments.get('object')} for "
                        f"{arguments.get('subject')}. Treat this as a "
                        "candidate map assertion and review current context "
                        "before applying."
                    )
            else:
                updated_actions.append(action)
                continue
            updated_actions.append(
                replace(
                    action,
                    arguments=arguments,
                    call=self._suggested_call_string(action.tool_name, arguments),
                )
            )
        return updated_actions

    @staticmethod
    def _profile_type_advisory_duplicate_group_key(
        advisory: ProfileTypeFindingAdvisory,
    ) -> str:
        payload = {
            "evidence_iri": advisory.evidence_iri,
            "observed_column_iri": advisory.observed_column.iri,
            "observed_column_name": advisory.observed_column_name,
            "observed_physical_type_iri": (
                advisory.observed_physical_type.iri
                if advisory.observed_physical_type is not None
                else None
            ),
            "observed_value_type_iri": (
                advisory.observed_value_type.iri
                if advisory.observed_value_type is not None
                else None
            ),
            "map_column_found": advisory.map_column_found,
            "current_physical_type_iri": (
                advisory.current_physical_type.iri
                if advisory.current_physical_type is not None
                else None
            ),
            "current_value_type_iri": (
                advisory.current_value_type.iri
                if advisory.current_value_type is not None
                else None
            ),
            "advisory_status": advisory.advisory_status,
            "related_recommendation_kinds": advisory.related_recommendation_kinds,
        }
        digest = hashlib.sha256(
            json.dumps(payload, sort_keys=True, default=str).encode("utf-8")
        ).hexdigest()[:12]
        return f"profile-type-advisory:{digest}"

    @staticmethod
    def _profile_type_advisory_suggested_actions(
        advisories: list[ProfileTypeFindingAdvisory],
    ) -> list[SuggestedNextAction]:
        return DoxaBase._profile_advisory_suggested_actions(
            advisories,
            advisory_kind="profile_type_review",
            index_field="type_advisory_index",
        )

    def _profile_type_advisory_actions(
        self,
        *,
        profile: ProfileObservationSummary,
        evidence_iri: str,
        advisory_status: str,
        map_column_found: bool,
        current_physical_type: ResourceSummary | None,
        current_value_type: ResourceSummary | None,
        value_type_promotion_pattern_iris: list[str],
    ) -> list[SuggestedNextAction]:
        assert profile.observed_column is not None
        actions: list[SuggestedNextAction] = []

        def add_action(
            tool_name: str,
            arguments: dict[str, Any],
            reason: str,
            *,
            action_label: str,
        ) -> None:
            actions.append(
                SuggestedNextAction(
                    action_label=action_label,
                    tool_name=tool_name,
                    mcp_tool_name=f"doxabase.{tool_name}",
                    arguments=arguments,
                    reason=reason,
                    call=self._suggested_call_string(tool_name, arguments),
                )
            )

        type_implication_iris = [
            profile.observed_column.iri,
            *(
                [profile.observed_physical_type.iri]
                if profile.observed_physical_type is not None
                else []
            ),
            *(
                [profile.observed_value_type.iri]
                if profile.observed_value_type is not None
                else []
            ),
        ]
        seed_iris = [
            profile.iri,
            profile.observed_column.iri,
            *self._profile_type_existing_type_seed_iris(profile),
        ]
        add_action(
            "describe_context_slice",
            {
                "seed_iris": list(dict.fromkeys(seed_iris)),
                "profile": "dataset_brief",
            },
            (
                "Load bounded lore around the profile observation, column, and "
                "observed type resources before turning the type finding into "
                "a current map assertion."
            ),
            action_label="Inspect profile type context",
        )
        column_label = (
            profile.observed_column.label
            or profile.observed_column.column_name
            or profile.observed_column_name
            or profile.observed_column.iri
        )
        add_action(
            "record_pattern",
            {
                "summary": f"Review profiled type for {column_label}",
                "pattern_text": (
                    f"Profile evidence observed type information for {column_label}. "
                    "Treat it as interpretation evidence until reviewed against "
                    "current map context and value-type semantics."
                ),
                "rationale": (
                    "Profile type findings are evidence, not automatic map "
                    "updates. Preserve the judgement before staging a map "
                    "assertion or systematisation."
                ),
                "pattern_targets": [profile.observed_column.iri],
                "supporting_observations": [profile.iri],
                "evidence_iri": evidence_iri,
                "map_implications": list(dict.fromkeys(type_implication_iris)),
            },
            (
                "Record a synthesis if this type finding needs semantic review "
                "before becoming a durable map assertion."
            ),
            action_label="Record type-finding pattern",
        )
        pattern_carry_forward_note = (
            " If you used the suggested record_pattern action, add its returned "
            "pattern_iri to supporting_patterns on this staging call."
        )
        if value_type_promotion_pattern_iris:
            for pattern_iri in value_type_promotion_pattern_iris[:3]:
                add_action(
                    "describe_pattern",
                    {"iri": pattern_iri},
                    (
                        "Inspect the same-evidence pattern before promoting "
                        "this project value type into ontology vocabulary."
                    ),
                    action_label="Inspect value type promotion pattern",
                )
            add_action(
                "stage_pattern_promotion",
                self._profile_value_type_promotion_skeleton_arguments(
                    value_type_iri=profile.observed_value_type.iri,
                    pattern_iris=value_type_promotion_pattern_iris,
                    evidence_iri=evidence_iri,
                ),
                (
                    "Stage a reviewable ontology skeleton for this project "
                    "value type only after checking that the same-evidence "
                    "pattern captures its domain meaning and physical-type "
                    "expectations."
                ),
                action_label="Stage value type vocabulary skeleton",
            )

        if map_column_found:
            if (
                profile.observed_physical_type is not None
                and (
                    current_physical_type is None
                    or current_physical_type.iri
                    != profile.observed_physical_type.iri
                )
            ):
                add_action(
                    "stage_map_assertion_change",
                    self._profile_type_assertion_action_arguments(
                        profile=profile,
                        evidence_iri=evidence_iri,
                        predicate="rc:physicalType",
                        object_iri=profile.observed_physical_type.iri,
                        advisory_status=advisory_status,
                    ),
                    (
                        "Stage a reviewable physical-type assertion only after "
                        "checking the profile evidence and value-type context."
                        f"{pattern_carry_forward_note}"
                    ),
                    action_label="Stage physical type assertion",
                )
            if (
                profile.observed_value_type is not None
                and (
                    current_value_type is None
                    or current_value_type.iri != profile.observed_value_type.iri
                )
            ):
                add_action(
                    "stage_map_assertion_change",
                    self._profile_type_assertion_action_arguments(
                        profile=profile,
                        evidence_iri=evidence_iri,
                        predicate="rc:valueType",
                        object_iri=profile.observed_value_type.iri,
                        advisory_status=advisory_status,
                    ),
                    (
                        "Stage a reviewable value-type assertion only after "
                        "checking the profile evidence and domain semantics."
                        f"{pattern_carry_forward_note}"
                    ),
                    action_label="Stage value type assertion",
                )
        return actions

    def _profile_value_type_needs_ontology_skeleton(
        self,
        value_type_iri: str,
    ) -> bool:
        if value_type_iri.startswith(PREFIXES["rc"]):
            return False
        ontology_graphs = self._expand_graphs(["ontology"])
        value_type_class = self.expand_iri("rc:ValueType")
        return value_type_class not in self._types_from_graphs(
            ontology_graphs,
            value_type_iri,
        )

    def _profile_value_type_promotion_pattern_iris(
        self,
        *,
        value_type_iri: str,
        evidence_iri: str,
    ) -> list[str]:
        pattern_graphs = ["patterns"]
        same_evidence = set(self._subjects(pattern_graphs, "rc:evidence", evidence_iri))
        if not same_evidence:
            return []
        value_type_related = set(
            self._subjects(pattern_graphs, "rc:patternTarget", value_type_iri)
        )
        value_type_related.update(
            self._subjects(pattern_graphs, "rc:mapImplication", value_type_iri)
        )
        return sorted(same_evidence & value_type_related)

    def _profile_value_type_promotion_skeleton_arguments(
        self,
        *,
        value_type_iri: str,
        pattern_iris: list[str],
        evidence_iri: str | None,
    ) -> dict[str, Any]:
        value_type_label = self._local_name(value_type_iri) or value_type_iri
        semantic_hint = self._profile_value_type_promotion_semantic_hint(
            value_type_iri=value_type_iri,
            pattern_iris=pattern_iris,
        )
        comment = (
            f"Project-specific value type observed in profile evidence: "
            f"{semantic_hint}"
            if semantic_hint is not None
            else (
                "Project-specific value type observed in profile evidence; "
                "review and sharpen its domain meaning, allowed values, and "
                "physical-type expectations before applying this vocabulary "
                "definition."
            )
        )
        content = (
            "@prefix rc: <https://richcanopy.org/ns/rc#> .\n"
            "@prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .\n\n"
            f"<{value_type_iri}> a rc:ValueType ;\n"
            f"    rdfs:label {Literal(value_type_label).n3()} ;\n"
            "    rdfs:comment " + Literal(comment).n3() + " ."
        )
        arguments: dict[str, Any] = {
            "patterns": pattern_iris,
            "summary": f"Define {value_type_label} value type",
            "intent": (
                "Stage project ontology vocabulary for a value type that "
                "already has same-evidence pattern support."
            ),
            "rationale": (
                "The type advisory found a project-specific value type that is "
                "undefined or not yet typed as rc:ValueType, plus an existing "
                "pattern tied to the same evidence. Keep this as a staged "
                "ontology proposal until domain meaning and physical-type "
                "expectations have been reviewed."
            ),
            "framings": [
                {
                    "label": "Value type definition",
                    "graph": "ontology",
                    "content": content,
                    "review_note": (
                        "Generated as a value-type promotion skeleton from "
                        "draft_profile_map_updates; review wording before "
                        "applying."
                    ),
                    "review_recommendation": (
                        "Apply only after the value type's domain meaning, "
                        "allowed values, and physical-type expectations are "
                        "explicit enough for reuse."
                    ),
                }
            ],
            "anchors": [value_type_iri],
            "validation_scope": "all",
        }
        if evidence_iri is not None:
            arguments["evidence"] = [evidence_iri]
        return arguments

    def _profile_value_type_promotion_semantic_hint(
        self,
        *,
        value_type_iri: str,
        pattern_iris: list[str],
    ) -> str | None:
        for pattern_iri in pattern_iris:
            try:
                pattern = self.describe_pattern(pattern_iri)
            except DoxaBaseError:
                continue
            for value in (pattern.pattern_text, pattern.rationale, pattern.summary):
                if value is None:
                    continue
                if not self._profile_metric_text_mentions_metric(
                    value,
                    metric_iri=value_type_iri,
                ):
                    continue
                hint = self._compact_restage_reason(value, limit=260)
                if hint:
                    return hint
        return None

    def _profile_type_existing_type_seed_iris(
        self,
        profile: ProfileObservationSummary,
    ) -> list[str]:
        all_graphs = self._expand_graphs(["all"])
        seed_iris: list[str] = []
        for observed_type in (
            profile.observed_physical_type,
            profile.observed_value_type,
        ):
            if observed_type is None:
                continue
            if self._subject_exists(observed_type.iri, all_graphs):
                seed_iris.append(observed_type.iri)
        return seed_iris

    def _profile_type_assertion_action_arguments(
        self,
        *,
        profile: ProfileObservationSummary,
        evidence_iri: str,
        predicate: str,
        object_iri: str,
        advisory_status: str,
    ) -> dict[str, Any]:
        assert profile.observed_column is not None
        column_label = (
            profile.observed_column.label
            or profile.observed_column.column_name
            or profile.observed_column_name
            or profile.observed_column.iri
        )
        return {
            "subject": profile.observed_column.iri,
            "predicate": predicate,
            "object": object_iri,
            "object_kind": "iri",
            "change_kind": "replace",
            "rationale": (
                f"Profile observation {profile.iri} recorded {predicate} "
                f"{object_iri} for {column_label}. Treat this as a candidate "
                "map assertion and review current context before applying."
            ),
            "supporting_observations": [profile.iri],
            "supporting_patterns": [],
            "evidence": [evidence_iri],
            "revision_anchors": [profile.observed_column.iri, object_iri],
            "review_note": (
                "Generated from a profile type-finding advisory; profile type "
                "findings are evidence, not automatic map updates. If the "
                "suggested type-finding pattern was recorded first, add its "
                "pattern_iri to supporting_patterns before staging."
            ),
            "review_recommendation": (
                "Apply only if the profile evidence and current map/value-type "
                f"context support replacing or recording this assertion "
                f"(advisory_status={advisory_status})."
            ),
            "validation_scope": "all",
        }

    @staticmethod
    def _profile_type_advisory_rationale(
        profile: ProfileObservationSummary,
        *,
        advisory_status: str,
    ) -> str:
        if profile.observed_column is not None:
            column_label = (
                profile.observed_column.label
                or profile.observed_column.column_name
                or profile.observed_column_name
                or profile.observed_column.iri
            )
        else:
            column_label = "the observed column"
        if advisory_status == "type_finding_unmapped_column":
            return (
                f"The profile observed type information for {column_label}, "
                "but the column is not a current map column. Preserve or stage "
                "the interpretation with a column shell or systematisation "
                "before recording current map type facts."
            )
        if advisory_status == "type_finding_conflicts_current_map":
            return (
                f"The profile observed type information for {column_label} that "
                "differs from current map type facts. Review semantic risk and "
                "value-type context before replacing current assertions."
            )
        if advisory_status == "type_finding_missing_map_type":
            return (
                f"The profile observed type information for {column_label} where "
                "the current map lacks one or more corresponding type facts. "
                "Review before recording them as durable map context."
            )
        return (
            f"The profile observed type information for {column_label}. Review "
            "the profile evidence and modelling intent before recording map "
            "type facts."
        )

    @staticmethod
    def _profile_type_advisory_routing_note(
        advisory_status: str,
        *,
        related_recommendation_indexes: list[int],
        related_recommendation_kinds: list[str],
    ) -> str:
        if advisory_status == "type_finding_unmapped_column":
            if related_recommendation_indexes:
                indexes = ", ".join(
                    str(index) for index in related_recommendation_indexes
                )
                kinds = ", ".join(related_recommendation_kinds)
                return (
                    f"Review the related {kinds} recommendation index(es) "
                    f"{indexes} first. Stage/apply the column shell if "
                    "appropriate, then rerun or review type assertions after "
                    "the column is map-present. When these indexes are a "
                    "duplicate group, following the representative "
                    "stage_profile_map_updates action is enough to stage the "
                    "shared shell before rerun."
                )
            return (
                "No related unmapped_profiled_column recommendation was found; "
                "preserve the type finding as observation/pattern lore until "
                "there is current map column context to review."
            )
        if advisory_status == "type_finding_conflicts_current_map":
            return (
                "Inspect current map context and value-type semantics before "
                "staging any replacement type assertion."
            )
        if advisory_status == "type_finding_missing_map_type":
            return (
                "Inspect current map context before staging missing type facts "
                "as durable map assertions."
            )
        return (
            "Inspect the profile evidence and modelling intent before recording "
            "map type facts."
        )

    def _profile_metric_vocabulary_advisories(
        self,
        profiles: list[ProfileObservationSummary],
        evidence_iri: str,
    ) -> list[ProfileMetricVocabularyAdvisory]:
        advisories: list[ProfileMetricVocabularyAdvisory] = []
        ontology_graphs = self._expand_graphs(["ontology"])
        profile_metric_kind = self.expand_iri("rc:ProfileMetricKind")
        for profile in profiles:
            for metric in profile.profile_metrics:
                if metric.metric.iri.startswith(PREFIXES["rc"]):
                    continue
                metric_iri = metric.metric.iri
                definition_found = self._subject_exists(metric_iri, ontology_graphs)
                metric_types = self._types_from_graphs(ontology_graphs, metric_iri)
                definition = (
                    self._resource_summary(ontology_graphs, metric_iri)
                    if definition_found
                    else None
                )
                if profile_metric_kind in metric_types:
                    advisory_status = "project_metric_defined"
                elif definition_found:
                    advisory_status = "project_metric_definition_ambiguous"
                else:
                    advisory_status = "project_metric_undefined"
                promotion_pattern_iris = (
                    self._profile_metric_promotion_pattern_iris(
                        metric_iri=metric_iri,
                        evidence_iri=evidence_iri,
                    )
                    if advisory_status
                    in {
                        "project_metric_undefined",
                        "project_metric_definition_ambiguous",
                    }
                    else []
                )
                context_pattern_iris = (
                    self._profile_metric_context_pattern_iris(
                        metric_iri=metric_iri,
                        evidence_iri=evidence_iri,
                        exclude_pattern_iris=promotion_pattern_iris,
                    )
                    if advisory_status
                    in {
                        "project_metric_undefined",
                        "project_metric_definition_ambiguous",
                    }
                    else []
                )
                suggested_next_actions = self._profile_metric_advisory_actions(
                    observed_metric_iri=metric.iri,
                    profile_observation_iri=profile.iri,
                    metric_iri=metric_iri,
                    advisory_status=advisory_status,
                    promotion_pattern_iris=promotion_pattern_iris,
                    context_pattern_iris=context_pattern_iris,
                    evidence_iri=evidence_iri,
                )
                advisories.append(
                    ProfileMetricVocabularyAdvisory(
                        profile_observation_iri=profile.iri,
                        observed_metric_iri=metric.iri,
                        metric_advisory_index=len(advisories),
                        evidence_iri=evidence_iri,
                        metric=metric.metric,
                        target=metric.target,
                        value=metric.value,
                        value_datatype=metric.value_datatype,
                        value_lang=metric.value_lang,
                        advisory_status=advisory_status,
                        definition_found=definition_found,
                        definition=definition,
                        promotion_patterns=self._resource_summaries(
                            self._lookup_graphs(["patterns"]),
                            promotion_pattern_iris,
                        ),
                        promotion_pattern_count=len(promotion_pattern_iris),
                        mixed_support_patterns=[],
                        mixed_support_pattern_count=0,
                        mixed_support_note=None,
                        context_patterns=self._resource_summaries(
                            self._lookup_graphs(["patterns"]),
                            context_pattern_iris,
                        ),
                        context_pattern_count=len(context_pattern_iris),
                        recommendation="review_metric_vocabulary_before_reuse",
                        rationale=(
                            "Project-specific profile metric IRIs are valid "
                            "observation lore, but reusable comparison or map "
                            "policy should define the metric meaning, unit, and "
                            "calculation in project ontology or supporting lore."
                        ),
                        suggested_next_actions=suggested_next_actions,
                        suggested_next_calls=[
                            action.call for action in suggested_next_actions
                        ],
                    )
                )
        return self._with_profile_metric_advisory_duplicate_metadata(advisories)

    def _with_profile_metric_advisory_duplicate_metadata(
        self,
        advisories: list[ProfileMetricVocabularyAdvisory],
    ) -> list[ProfileMetricVocabularyAdvisory]:
        groups: dict[str, list[tuple[int, ProfileMetricVocabularyAdvisory]]] = {}
        for index, advisory in enumerate(advisories):
            groups.setdefault(
                self._profile_metric_advisory_duplicate_group_key(advisory),
                [],
            ).append((index, advisory))

        annotated: list[ProfileMetricVocabularyAdvisory] = []
        for index, advisory in enumerate(advisories):
            group_key = self._profile_metric_advisory_duplicate_group_key(advisory)
            group = groups[group_key]
            annotated.append(
                replace(
                    advisory,
                    metric_advisory_index=index,
                    duplicate_group_key=group_key,
                    duplicate_count=len(group),
                    duplicate_advisory_indexes=[
                        group_index for group_index, _ in group
                    ],
                    duplicate_profile_observation_iris=list(
                        dict.fromkeys(
                            item.profile_observation_iri for _, item in group
                        )
                    ),
                )
            )
        return annotated

    @staticmethod
    def _profile_metric_advisory_duplicate_group_key(
        advisory: ProfileMetricVocabularyAdvisory,
    ) -> str:
        payload = {
            "evidence_iri": advisory.evidence_iri,
            "metric_iri": advisory.metric.iri,
            "target_iri": advisory.target.iri if advisory.target else None,
            "value": advisory.value,
            "value_datatype": advisory.value_datatype,
            "value_lang": advisory.value_lang,
            "advisory_status": advisory.advisory_status,
            "definition_found": advisory.definition_found,
            "definition_iri": advisory.definition.iri if advisory.definition else None,
            "promotion_pattern_iris": [
                pattern.iri for pattern in advisory.promotion_patterns
            ],
            "context_pattern_iris": [
                pattern.iri for pattern in advisory.context_patterns
            ],
            "recommendation": advisory.recommendation,
        }
        digest = hashlib.sha256(
            json.dumps(payload, sort_keys=True, default=str).encode("utf-8")
        ).hexdigest()[:12]
        return f"profile-metric-advisory:{digest}"

    def _with_profile_advisory_mixed_support(
        self,
        metric_advisories: list[ProfileMetricVocabularyAdvisory],
        type_advisories: list[ProfileTypeFindingAdvisory],
    ) -> tuple[
        list[ProfileMetricVocabularyAdvisory],
        list[ProfileTypeFindingAdvisory],
    ]:
        metric_pattern_iris = {
            pattern.iri
            for advisory in metric_advisories
            for pattern in advisory.promotion_patterns
        }
        type_pattern_iris = {
            pattern.iri
            for advisory in type_advisories
            for pattern in advisory.promotion_patterns
        }
        mixed_pattern_iris = metric_pattern_iris & type_pattern_iris
        if not mixed_pattern_iris:
            return metric_advisories, type_advisories

        metric_note = self._profile_advisory_mixed_support_note(
            "metric_vocabulary_review",
        )
        type_note = self._profile_advisory_mixed_support_note(
            "profile_type_review",
        )

        def annotate(
            advisory: ProfileMetricVocabularyAdvisory | ProfileTypeFindingAdvisory,
            *,
            note: str,
        ) -> ProfileMetricVocabularyAdvisory | ProfileTypeFindingAdvisory:
            mixed_patterns = [
                pattern
                for pattern in advisory.promotion_patterns
                if pattern.iri in mixed_pattern_iris
            ]
            if not mixed_patterns:
                return advisory
            suggested_next_actions = (
                self._profile_advisory_actions_with_mixed_support(
                    advisory.suggested_next_actions,
                    mixed_pattern_iris=mixed_pattern_iris,
                    mixed_support_note=note,
                )
            )
            return replace(
                advisory,
                mixed_support_patterns=mixed_patterns,
                mixed_support_pattern_count=len(mixed_patterns),
                mixed_support_note=note,
                suggested_next_actions=suggested_next_actions,
                suggested_next_calls=[
                    action.call for action in suggested_next_actions
                ],
            )

        annotated_metric_advisories = [
            annotate(advisory, note=metric_note) for advisory in metric_advisories
        ]
        annotated_type_advisories = [
            annotate(advisory, note=type_note) for advisory in type_advisories
        ]
        return annotated_metric_advisories, annotated_type_advisories

    @staticmethod
    def _profile_advisory_mixed_support_note(advisory_kind: str) -> str:
        other_lane = (
            "profile type review"
            if advisory_kind == "metric_vocabulary_review"
            else "metric vocabulary review"
        )
        return (
            "Mixed support: one or more same-evidence promotion patterns also "
            f"support {other_lane}. Inspect the shared pattern carefully before "
            "promoting or asserting this lane independently. Review or export "
            "the generated promotion or assertion drafts together before "
            "applying either lane independently."
        )

    def _profile_advisory_actions_with_mixed_support(
        self,
        actions: list[SuggestedNextAction],
        *,
        mixed_pattern_iris: set[str],
        mixed_support_note: str,
    ) -> list[SuggestedNextAction]:
        updated_actions: list[SuggestedNextAction] = []
        for action in actions:
            arguments = action.arguments
            reason = action.reason
            should_note = False
            if (
                action.tool_name == "describe_pattern"
                and arguments.get("iri") in mixed_pattern_iris
            ):
                should_note = True
            elif (
                action.tool_name == "stage_pattern_promotion"
                and set(arguments.get("patterns") or []) & mixed_pattern_iris
            ):
                should_note = True
            elif action.tool_name == "stage_map_assertion_change":
                should_note = True

            if not should_note:
                updated_actions.append(action)
                continue

            updated_arguments = copy.deepcopy(arguments)
            if action.tool_name in {
                "stage_pattern_promotion",
                "stage_map_assertion_change",
            }:
                self._add_mixed_support_review_note(
                    updated_arguments,
                    mixed_support_note,
                )
            updated_actions.append(
                replace(
                    action,
                    arguments=updated_arguments,
                    reason=f"{reason} {mixed_support_note}",
                    call=self._suggested_call_string(
                        action.tool_name,
                        updated_arguments,
                    ),
                )
            )
        return updated_actions

    @staticmethod
    def _add_mixed_support_review_note(
        arguments: dict[str, Any],
        mixed_support_note: str,
    ) -> None:
        if "framings" in arguments:
            for framing in arguments.get("framings") or []:
                framing["review_note"] = (
                    f"{framing.get('review_note') or ''} {mixed_support_note}"
                ).strip()
                framing["review_recommendation"] = (
                    f"{framing.get('review_recommendation') or ''} "
                    f"{mixed_support_note}"
                ).strip()
            return
        arguments["review_note"] = (
            f"{arguments.get('review_note') or ''} {mixed_support_note}"
        ).strip()
        arguments["review_recommendation"] = (
            f"{arguments.get('review_recommendation') or ''} "
            f"{mixed_support_note}"
        ).strip()

    @staticmethod
    def _profile_advisory_suggested_actions(
        advisories: Iterable[
            ProfileMetricVocabularyAdvisory | ProfileTypeFindingAdvisory
        ],
        *,
        advisory_kind: str,
        index_field: str,
    ) -> list[SuggestedNextAction]:
        actions_by_key: dict[tuple[str, str], SuggestedNextAction] = {}
        source_by_key: dict[tuple[str, str], dict[str, Any]] = {}
        action_order: list[tuple[str, str]] = []

        for advisory in advisories:
            advisory_index = getattr(advisory, index_field)
            duplicate_advisory_indexes = (
                advisory.duplicate_advisory_indexes or [advisory_index]
            )
            duplicate_profile_observation_iris = (
                advisory.duplicate_profile_observation_iris
                or [advisory.profile_observation_iri]
            )
            for action in advisory.suggested_next_actions:
                key = (action.tool_name, action.call)
                if key not in actions_by_key:
                    actions_by_key[key] = action
                    action_order.append(key)
                    source_by_key[key] = {
                        "advisory_kind": advisory_kind,
                        "index_field": index_field,
                        "advisory_indexes": [],
                        "duplicate_group_keys": [],
                        "duplicate_advisory_indexes": [],
                        "duplicate_profile_observation_iris": [],
                    }
                source = source_by_key[key]
                DoxaBase._append_unique(source["advisory_indexes"], advisory_index)
                mixed_support_patterns = getattr(
                    advisory,
                    "mixed_support_patterns",
                    [],
                )
                mixed_support_note = getattr(advisory, "mixed_support_note", None)
                if mixed_support_patterns:
                    mixed_support = source.setdefault(
                        "mixed_support",
                        {
                            "pattern_iris": [],
                            "pattern_count": 0,
                            "other_review_lanes": [],
                            "note": mixed_support_note,
                        },
                    )
                    other_lane = (
                        "profile_type_review"
                        if advisory_kind == "metric_vocabulary_review"
                        else "metric_vocabulary_review"
                    )
                    DoxaBase._append_unique(
                        mixed_support["other_review_lanes"],
                        other_lane,
                    )
                    for pattern in mixed_support_patterns:
                        DoxaBase._append_unique(
                            mixed_support["pattern_iris"],
                            pattern.iri,
                        )
                    mixed_support["pattern_count"] = len(
                        mixed_support["pattern_iris"]
                    )
                if advisory.duplicate_group_key:
                    DoxaBase._append_unique(
                        source["duplicate_group_keys"],
                        advisory.duplicate_group_key,
                    )
                for duplicate_index in duplicate_advisory_indexes:
                    DoxaBase._append_unique(
                        source["duplicate_advisory_indexes"],
                        duplicate_index,
                    )
                for observation_iri in duplicate_profile_observation_iris:
                    DoxaBase._append_unique(
                        source["duplicate_profile_observation_iris"],
                        observation_iri,
                    )
                observed_metric_iri = getattr(advisory, "observed_metric_iri", None)
                if observed_metric_iri:
                    observed_metric_iris = source.setdefault(
                        "observed_metric_iris",
                        [],
                    )
                    DoxaBase._append_unique(
                        observed_metric_iris,
                        observed_metric_iri,
                    )

        return [
            DoxaBase._profile_advisory_suggested_action(
                actions_by_key[key],
                source_profile_advisory=source_by_key[key],
            )
            for key in action_order
        ]

    @staticmethod
    def _append_unique(values: list[Any], value: Any) -> None:
        if value not in values:
            values.append(value)

    @staticmethod
    def _profile_advisory_suggested_action(
        action: SuggestedNextAction,
        *,
        source_profile_advisory: dict[str, Any],
    ) -> ProfileAdvisorySuggestedNextAction:
        return ProfileAdvisorySuggestedNextAction(
            action_label=action.action_label,
            tool_name=action.tool_name,
            mcp_tool_name=action.mcp_tool_name,
            arguments=action.arguments,
            reason=action.reason,
            call=action.call,
            source_profile_advisory=source_profile_advisory,
        )

    def _profile_metric_advisory_actions(
        self,
        *,
        observed_metric_iri: str | None,
        profile_observation_iri: str | None,
        metric_iri: str,
        advisory_status: str,
        promotion_pattern_iris: list[str] | None = None,
        context_pattern_iris: list[str] | None = None,
        evidence_iri: str | None = None,
    ) -> list[SuggestedNextAction]:
        actions: list[SuggestedNextAction] = []
        promotion_pattern_values = list(promotion_pattern_iris or [])
        context_pattern_values = list(context_pattern_iris or [])
        focused_seed_iri = observed_metric_iri or profile_observation_iri or metric_iri

        def add_action(
            tool_name: str,
            arguments: dict[str, Any],
            reason: str,
            *,
            action_label: str,
        ) -> None:
            actions.append(
                SuggestedNextAction(
                    action_label=action_label,
                    tool_name=tool_name,
                    mcp_tool_name=f"doxabase.{tool_name}",
                    arguments=arguments,
                    reason=reason,
                    call=self._suggested_call_string(tool_name, arguments),
                )
            )

        add_action(
            "describe_context_slice",
            {"seed_iris": [focused_seed_iri], "profile": "dataset_brief"},
            (
                "Load bounded lore around this observed profile metric before "
                "reusing its project-specific metric kind in comparison, map "
                "policy, or ontology."
            ),
            action_label="Inspect observed metric context",
        )
        if advisory_status in {
            "project_metric_defined",
            "project_metric_definition_ambiguous",
        }:
            add_action(
                "describe_resource",
                {"iri": metric_iri, "graph": "ontology"},
                (
                    "Inspect the existing project ontology definition before "
                    "using or repairing this metric in durable comparisons or "
                    "map policy."
                ),
                action_label="Inspect metric definition",
            )
        if advisory_status != "project_metric_defined":
            add_action(
                "list_entities",
                {
                    "type": "rc:ProfileMetricKind",
                    "graph": "ontology",
                    "text": self._local_name(metric_iri),
                },
                (
                    "Look for nearby metric vocabulary before recording claims, "
                    "patterns, or a promoted ontology definition for this metric."
                ),
                action_label="List nearby metric vocabulary",
            )

        def add_context_pattern_actions() -> None:
            for pattern_iri in context_pattern_values[:3]:
                add_action(
                    "describe_pattern",
                    {"iri": pattern_iri},
                    (
                        "Inspect this same-evidence metric pattern as context. "
                        "It is not structurally tied to the metric as a target "
                        "or map implication, so it is not used as automatic "
                        "promotion support."
                    ),
                    action_label="Inspect metric context pattern",
                )

        if (
            advisory_status
            in {
                "project_metric_undefined",
                "project_metric_definition_ambiguous",
            }
            and promotion_pattern_values
        ):
            for pattern_iri in promotion_pattern_values[:3]:
                add_action(
                    "describe_pattern",
                    {"iri": pattern_iri},
                    (
                        "Inspect the same-evidence pattern before promoting this "
                        "project metric into ontology vocabulary."
                    ),
                    action_label="Inspect metric promotion pattern",
                )
            add_context_pattern_actions()
            add_action(
                "stage_pattern_promotion",
                self._profile_metric_promotion_skeleton_arguments(
                    metric_iri=metric_iri,
                    pattern_iris=promotion_pattern_values,
                    evidence_iri=evidence_iri,
                ),
                (
                    "Stage a reviewable ontology skeleton for this project metric "
                    "only after checking that the same-evidence pattern captures "
                    "its calculation, unit, and comparison semantics."
                ),
                action_label="Stage metric vocabulary skeleton",
            )
        else:
            add_context_pattern_actions()
        return actions

    def _profile_metric_promotion_pattern_iris(
        self,
        *,
        metric_iri: str,
        evidence_iri: str,
    ) -> list[str]:
        pattern_graphs = ["patterns"]
        same_evidence = set(self._subjects(pattern_graphs, "rc:evidence", evidence_iri))
        if not same_evidence:
            return []
        metric_related = set(
            self._subjects(pattern_graphs, "rc:patternTarget", metric_iri)
        )
        metric_related.update(
            self._subjects(pattern_graphs, "rc:mapImplication", metric_iri)
        )
        return sorted(same_evidence & metric_related)

    def _profile_metric_context_pattern_iris(
        self,
        *,
        metric_iri: str,
        evidence_iri: str,
        exclude_pattern_iris: Iterable[str] = (),
    ) -> list[str]:
        pattern_graphs = ["patterns"]
        same_evidence = set(self._subjects(pattern_graphs, "rc:evidence", evidence_iri))
        if not same_evidence:
            return []
        excluded = set(exclude_pattern_iris)
        local_name = self._local_name(metric_iri)
        matches: list[str] = []
        for pattern_iri in sorted(same_evidence - excluded):
            text_parts = [
                value
                for value in (
                    self._first_object(pattern_graphs, pattern_iri, "rc:patternText"),
                    self._first_object(pattern_graphs, pattern_iri, "rc:rationale"),
                    self._first_object(pattern_graphs, pattern_iri, "rc:summary"),
                )
                if value
            ]
            haystack = "\n".join(text_parts).lower()
            if metric_iri.lower() in haystack or (
                local_name and local_name.lower() in haystack
            ):
                matches.append(pattern_iri)
        return matches

    def _profile_metric_promotion_skeleton_arguments(
        self,
        *,
        metric_iri: str,
        pattern_iris: list[str],
        evidence_iri: str | None,
    ) -> dict[str, Any]:
        metric_label = self._local_name(metric_iri) or metric_iri
        semantic_hint = self._profile_metric_promotion_semantic_hint(
            metric_iri=metric_iri,
            pattern_iris=pattern_iris,
        )
        comment = (
            f"Project-specific profile metric observed in profile evidence: "
            f"{semantic_hint}"
            if semantic_hint is not None
            else (
                "Project-specific profile metric observed in profile evidence; "
                "review and sharpen its calculation, unit, and comparison "
                "semantics before applying this vocabulary definition."
            )
        )
        content = (
            "@prefix rc: <https://richcanopy.org/ns/rc#> .\n"
            "@prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .\n\n"
            f"<{metric_iri}> a rc:ProfileMetricKind ;\n"
            f"    rdfs:label {Literal(metric_label).n3()} ;\n"
            "    rdfs:comment " + Literal(comment).n3() + " ."
        )
        arguments: dict[str, Any] = {
            "patterns": pattern_iris,
            "summary": f"Define {metric_label} profile metric",
            "intent": (
                "Stage project ontology vocabulary for a profile metric that "
                "already has same-evidence pattern support."
            ),
            "rationale": (
                "The metric advisory found a project-specific profile metric "
                "that is undefined or not yet typed as rc:ProfileMetricKind, "
                "plus an existing pattern tied to the same evidence. Keep this "
                "as a staged ontology proposal until calculation, unit, and "
                "comparison semantics have been reviewed."
            ),
            "framings": [
                {
                    "label": "Profile metric kind definition",
                    "graph": "ontology",
                    "content": content,
                    "review_note": (
                        "Generated as a metric-vocabulary promotion skeleton from "
                        "draft_profile_map_updates; review wording before applying."
                    ),
                    "review_recommendation": (
                        "Apply only after the metric calculation, unit, and "
                        "comparison semantics are explicit enough for reuse."
                    ),
                }
            ],
            "anchors": [metric_iri],
            "validation_scope": "all",
        }
        if evidence_iri is not None:
            arguments["evidence"] = [evidence_iri]
        return arguments

    def _profile_metric_promotion_semantic_hint(
        self,
        *,
        metric_iri: str,
        pattern_iris: list[str],
    ) -> str | None:
        for pattern_iri in pattern_iris:
            try:
                pattern = self.describe_pattern(pattern_iri)
            except DoxaBaseError:
                continue
            for value in (pattern.pattern_text, pattern.rationale, pattern.summary):
                if value is None:
                    continue
                if not self._profile_metric_text_mentions_metric(
                    value,
                    metric_iri=metric_iri,
                ):
                    continue
                hint = self._compact_restage_reason(value, limit=260)
                if hint:
                    return hint
        return None

    def _profile_metric_text_mentions_metric(
        self,
        text: str,
        *,
        metric_iri: str,
    ) -> bool:
        text_lower = text.lower()
        if metric_iri.lower() in text_lower:
            return True
        local_name = self._local_name(metric_iri)
        if not local_name:
            return False
        if self._contains_name_like_token(text_lower, local_name.lower()):
            return True
        phrase = self._profile_metric_local_name_phrase(local_name)
        return bool(phrase and self._contains_name_like_token(text_lower, phrase))

    @staticmethod
    def _profile_metric_local_name_phrase(local_name: str) -> str:
        spaced = re.sub(r"([a-z0-9])([A-Z])", r"\1 \2", local_name)
        return " ".join(
            token.lower()
            for token in re.findall(r"[A-Za-z0-9]+", spaced)
        )

    @staticmethod
    def _contains_name_like_token(text_lower: str, needle_lower: str) -> bool:
        if not needle_lower:
            return False
        return (
            re.search(
                rf"(?<![A-Za-z0-9]){re.escape(needle_lower)}(?![A-Za-z0-9])",
                text_lower,
            )
            is not None
        )

    def _profile_handoff_note(
        self,
        *,
        returned_profile_count: int,
        unmapped_column_profile_count: int,
        shared_evidence_count: int,
        omitted_profile_count: int,
    ) -> str:
        if returned_profile_count == 0:
            return (
                "No profile observations are included in this bounded dataset "
                "description; do not treat that as evidence that profiling has "
                "never been run."
            )
        note = (
            f"This bounded dataset description includes {returned_profile_count} "
            "profile observation(s). Profile lore is observed evidence, not "
            "physical query-planning metadata; storage/path/layout warnings "
            "remain physical metadata gaps rather than profile-recording failures."
        )
        if unmapped_column_profile_count:
            note += (
                f" {unmapped_column_profile_count} returned column profile(s) "
                "are not mapped as current columns."
            )
        if shared_evidence_count:
            note += (
                " At least one evidence resource is shared by every returned "
                "profile observation, which usually indicates one profiler run."
            )
        if omitted_profile_count:
            note += (
                f" {omitted_profile_count} additional profile observation(s) "
                "exist beyond this bounded response."
            )
        return note

    def _profile_observation_summary(
        self,
        observation_iri: str,
        lookup_graphs: list[str],
    ) -> ProfileObservationSummary:
        observation_graphs = ["observations"]
        evidence_graphs = ["evidence"]
        observed_asset = self._first_object(
            observation_graphs,
            observation_iri,
            "rc:observedAsset",
        )
        observed_column = self._first_object(
            observation_graphs,
            observation_iri,
            "rc:observedColumn",
        )
        observed_column_name = self._first_object(
            observation_graphs,
            observation_iri,
            "rc:observedColumnName",
        )
        observed_physical_type = self._first_object(
            observation_graphs,
            observation_iri,
            "rc:observedPhysicalType",
        )
        observed_value_type = self._first_object(
            observation_graphs,
            observation_iri,
            "rc:observedValueType",
        )
        return ProfileObservationSummary(
            iri=observation_iri,
            summary=self._first_object(observation_graphs, observation_iri, "rc:summary"),
            observed_at=self._first_object(
                observation_graphs,
                observation_iri,
                "rc:observedAt",
            ),
            observed_by=self._first_object(
                observation_graphs,
                observation_iri,
                "rc:observedBy",
            ),
            observed_asset=(
                self._resource_summary(lookup_graphs, observed_asset)
                if observed_asset is not None
                else None
            ),
            observed_column=(
                self._profile_observed_column_summary(
                    lookup_graphs,
                    observed_column,
                    observed_column_name=observed_column_name,
                )
                if observed_column is not None
                else None
            ),
            observed_column_name=observed_column_name,
            observed_physical_type=self._optional_resource_summary(
                lookup_graphs,
                observed_physical_type,
            ),
            observed_value_type=self._optional_resource_summary(
                lookup_graphs,
                observed_value_type,
            ),
            sample_size=self._int_object(
                observation_graphs,
                observation_iri,
                "rc:sampleSize",
            ),
            sample_scope=self._first_object(
                observation_graphs,
                observation_iri,
                "rc:sampleScope",
            ),
            sample_method=self._first_object(
                observation_graphs,
                observation_iri,
                "rc:sampleMethod",
            ),
            row_count=self._int_object(
                observation_graphs,
                observation_iri,
                "rc:rowCount",
            ),
            null_count=self._int_object(
                observation_graphs,
                observation_iri,
                "rc:nullCount",
            ),
            distinct_count=self._int_object(
                observation_graphs,
                observation_iri,
                "rc:distinctCount",
            ),
            value_frequencies=self._observed_value_frequency_summaries(
                observation_graphs,
                observation_iri,
            ),
            profile_metrics=self._observed_profile_metric_summaries(
                observation_graphs,
                lookup_graphs,
                observation_iri,
            ),
            evidence=[
                self._describe_evidence(evidence_iri, evidence_graphs, lookup_graphs)
                for evidence_iri in self._objects(
                    observation_graphs,
                    observation_iri,
                    "rc:evidence",
                )
            ],
        )

    def _profile_observed_column_summary(
        self,
        lookup_graphs: list[str],
        observed_column: str,
        *,
        observed_column_name: str | None,
    ) -> ResourceSummary:
        summary = self._resource_summary(lookup_graphs, observed_column)
        if summary.column_name is not None or observed_column_name is None:
            return summary
        return replace(
            summary,
            label=observed_column_name,
            column_name=observed_column_name,
        )

    def _observed_value_frequency_summaries(
        self,
        graphs: list[str],
        observation_iri: str,
    ) -> list[ObservedValueFrequencySummary]:
        summaries: list[ObservedValueFrequencySummary] = []
        for value_frequency_iri in self._objects(
            graphs,
            observation_iri,
            "rc:observedValueFrequency",
        ):
            value = self._first_object(
                graphs,
                value_frequency_iri,
                "rc:observedValue",
            )
            frequency = self._int_object(
                graphs,
                value_frequency_iri,
                "rc:valueFrequency",
            )
            if value is None or frequency is None:
                continue
            summaries.append(
                ObservedValueFrequencySummary(
                    iri=value_frequency_iri,
                    value=value,
                    frequency=frequency,
                )
            )
        return sorted(
            summaries,
            key=lambda item: (-item.frequency, item.value, item.iri),
        )

    def _observed_profile_metric_summaries(
        self,
        graphs: list[str],
        lookup_graphs: list[str],
        observation_iri: str,
    ) -> list[ObservedProfileMetricSummary]:
        summaries: list[ObservedProfileMetricSummary] = []
        for metric_iri in self._objects(
            graphs,
            observation_iri,
            "rc:observedProfileMetric",
        ):
            metric_kind = self._first_object(
                graphs,
                metric_iri,
                "rc:profileMetricKind",
            )
            value_row = self._first_object_row(
                graphs,
                metric_iri,
                "rc:profileMetricValue",
            )
            target_iri = self._first_object(
                graphs,
                metric_iri,
                "rc:profileMetricTarget",
            )
            if metric_kind is None or value_row is None:
                continue
            summaries.append(
                ObservedProfileMetricSummary(
                    iri=metric_iri,
                    metric=self._resource_summary(lookup_graphs, metric_kind),
                    target=self._optional_resource_summary(lookup_graphs, target_iri),
                    value=value_row["object"],
                    value_datatype=value_row["datatype"],
                    value_lang=value_row["lang"],
                )
            )
        return sorted(
            summaries,
            key=lambda item: (
                item.metric.label or item.metric.iri,
                item.value,
                item.iri,
            ),
        )

    def record_observation(
        self,
        summary: str,
        *,
        observation_type: TypingLiteral["observation", "profile"] = "observation",
        observed_asset: str | None = None,
        observed_column: str | None = None,
        observed_column_name: str | None = None,
        observed_at: datetime | str | None = None,
        observed_by: str | None = None,
        evidence_summary: str | None = None,
        evidence_sources: Iterable[str] | None = None,
        sample_size: int | None = None,
        sample_scope: str | None = None,
        sample_method: str | None = None,
        row_count: int | None = None,
        null_count: int | None = None,
        distinct_count: int | None = None,
        value_frequencies: Iterable[Mapping[str, Any]] | None = None,
        profile_metrics: Iterable[Mapping[str, Any]] | None = None,
        observed_physical_type: str | None = None,
        observed_value_type: str | None = None,
        observation_iri: str | None = None,
        evidence_iri: str | None = None,
    ) -> ObservationRecord:
        if not summary.strip():
            raise DoxaBaseError("Observation summary must not be empty")
        observation_class = {
            "observation": "rc:Observation",
            "profile": "rc:ProfileObservation",
        }.get(observation_type)
        if observation_class is None:
            raise DoxaBaseError(
                "observation_type must be either 'observation' or 'profile'"
            )
        for name, value in {
            "sample_size": sample_size,
            "row_count": row_count,
            "null_count": null_count,
            "distinct_count": distinct_count,
        }.items():
            self._ensure_non_negative(name, value)
        value_frequency_values = self._profile_value_frequency_values(
            value_frequencies
        )
        profile_metric_values = self._profile_metric_values(profile_metrics)
        observed_physical_type_ref = (
            self._resource_ref("observed_physical_type", observed_physical_type)
            if observed_physical_type is not None
            else None
        )
        observed_value_type_ref = (
            self._resource_ref("observed_value_type", observed_value_type)
            if observed_value_type is not None
            else None
        )
        if (
            observed_physical_type_ref is not None
            or observed_value_type_ref is not None
        ):
            if observation_type != "profile":
                raise DoxaBaseError(
                    "observed_physical_type and observed_value_type require "
                    "observation_type='profile'"
                )
            if observed_column is None:
                raise DoxaBaseError(
                    "observed type findings require observed_column"
                )

        evidence_source_values = (
            [evidence_sources]
            if isinstance(evidence_sources, str)
            else list(evidence_sources or [])
        )
        should_write_evidence = bool(
            evidence_summary or evidence_source_values or evidence_iri
        )
        observation_subject = URIRef(observation_iri or self._mint_iri("observation"))
        evidence_subject = (
            URIRef(evidence_iri or self._mint_iri("evidence"))
            if should_write_evidence
            else None
        )
        if evidence_subject is not None:
            self._preflight_evidence_summary_reuse(
                str(evidence_subject),
                evidence_summary,
            )

        observation_graph = Graph()
        self._bind_prefixes(observation_graph)
        observation_graph.add(
            (observation_subject, RDF.type, URIRef(self.expand_iri(observation_class)))
        )
        observation_graph.add(
            (observation_subject, URIRef(self.expand_iri("rc:summary")), Literal(summary))
        )
        observation_graph.add(
            (
                observation_subject,
                URIRef(self.expand_iri("rc:observedAt")),
                self._datetime_literal(observed_at),
            )
        )
        if observed_asset is not None:
            observation_graph.add(
                (
                    observation_subject,
                    URIRef(self.expand_iri("rc:observedAsset")),
                    URIRef(self.expand_iri(observed_asset)),
                )
            )
        if observed_column is not None:
            observation_graph.add(
                (
                    observation_subject,
                    URIRef(self.expand_iri("rc:observedColumn")),
                    URIRef(self.expand_iri(observed_column)),
                )
            )
        if observed_column_name is not None:
            if observed_column is None:
                raise DoxaBaseError(
                    "observed_column_name requires observed_column"
                )
            column_name_value = observed_column_name.strip()
            if not column_name_value:
                raise DoxaBaseError("observed_column_name must not be empty")
            observation_graph.add(
                (
                    observation_subject,
                    URIRef(self.expand_iri("rc:observedColumnName")),
                    Literal(column_name_value),
                )
            )
        if observed_physical_type_ref is not None:
            observation_graph.add(
                (
                    observation_subject,
                    URIRef(self.expand_iri("rc:observedPhysicalType")),
                    observed_physical_type_ref,
                )
            )
        if observed_value_type_ref is not None:
            observation_graph.add(
                (
                    observation_subject,
                    URIRef(self.expand_iri("rc:observedValueType")),
                    observed_value_type_ref,
                )
            )
        if observed_by is not None:
            observation_graph.add(
                (
                    observation_subject,
                    URIRef(self.expand_iri("rc:observedBy")),
                    self._resource_or_literal(observed_by),
                )
            )
        self._add_optional_literal(
            observation_graph,
            observation_subject,
            "rc:sampleScope",
            sample_scope,
        )
        self._add_optional_literal(
            observation_graph,
            observation_subject,
            "rc:sampleMethod",
            sample_method,
        )
        for predicate, value in (
            ("rc:sampleSize", sample_size),
            ("rc:rowCount", row_count),
            ("rc:nullCount", null_count),
            ("rc:distinctCount", distinct_count),
        ):
            if value is not None:
                observation_graph.add(
                    (
                        observation_subject,
                        URIRef(self.expand_iri(predicate)),
                        Literal(value, datatype=XSD.integer),
                    )
                )
        for observed_value, frequency in value_frequency_values:
            value_frequency_subject = URIRef(
                self._mint_iri("observed-value-frequency")
            )
            observation_graph.add(
                (
                    observation_subject,
                    URIRef(self.expand_iri("rc:observedValueFrequency")),
                    value_frequency_subject,
                )
            )
            observation_graph.add(
                (
                    value_frequency_subject,
                    RDF.type,
                    URIRef(self.expand_iri("rc:ObservedValueFrequency")),
                )
            )
            observation_graph.add(
                (
                    value_frequency_subject,
                    URIRef(self.expand_iri("rc:observedValue")),
                    Literal(observed_value),
                )
            )
            observation_graph.add(
                (
                    value_frequency_subject,
                    URIRef(self.expand_iri("rc:valueFrequency")),
                    Literal(frequency, datatype=XSD.integer),
                )
            )
        for (
            metric_kind,
            metric_value,
            datatype,
            lang,
            metric_target,
        ) in profile_metric_values:
            metric_subject = URIRef(self._mint_iri("observed-profile-metric"))
            observation_graph.add(
                (
                    observation_subject,
                    URIRef(self.expand_iri("rc:observedProfileMetric")),
                    metric_subject,
                )
            )
            observation_graph.add(
                (
                    metric_subject,
                    RDF.type,
                    URIRef(self.expand_iri("rc:ObservedProfileMetric")),
                )
            )
            observation_graph.add(
                (
                    metric_subject,
                    URIRef(self.expand_iri("rc:profileMetricKind")),
                    URIRef(self.expand_iri(metric_kind)),
                )
            )
            if metric_target is not None:
                observation_graph.add(
                    (
                        metric_subject,
                        URIRef(self.expand_iri("rc:profileMetricTarget")),
                        URIRef(metric_target),
                    )
                )
            literal = (
                Literal(str(metric_value), lang=lang)
                if lang is not None
                else Literal(
                    metric_value,
                    datatype=URIRef(self.expand_iri(datatype)) if datatype else None,
                )
            )
            observation_graph.add(
                (
                    metric_subject,
                    URIRef(self.expand_iri("rc:profileMetricValue")),
                    literal,
                )
            )
        if evidence_subject is not None:
            observation_graph.add(
                (
                    observation_subject,
                    URIRef(self.expand_iri("rc:evidence")),
                    evidence_subject,
                )
            )

        evidence_triples = 0
        if evidence_subject is not None:
            evidence_graph = Graph()
            self._bind_prefixes(evidence_graph)
            evidence_graph.add(
                (
                    evidence_subject,
                    RDF.type,
                    URIRef(self.expand_iri("rc:Evidence")),
                )
            )
            if evidence_summary:
                evidence_graph.add(
                    (
                        evidence_subject,
                        URIRef(self.expand_iri("rc:summary")),
                        Literal(evidence_summary),
                    )
                )
            for source in evidence_source_values:
                evidence_graph.add((evidence_subject, DCTERMS.source, Literal(source)))
            evidence_triples = self._insert_graph("evidence", evidence_graph)

        observation_triples = self._insert_graph("observations", observation_graph)
        return ObservationRecord(
            observation_iri=str(observation_subject),
            observation_type=observation_type,
            evidence_iri=str(evidence_subject) if evidence_subject is not None else None,
            observation_triples=observation_triples,
            evidence_triples=evidence_triples,
        )

    def record_query_result(
        self,
        summary: str,
        *,
        observed_asset: str | None = None,
        observed_at: datetime | str | None = None,
        observed_by: str | None = None,
        execution_status: str = "succeeded",
        engine: str | None = None,
        query_source_path: str | None = None,
        query_source_section: str | None = None,
        start_line: int | None = None,
        end_line: int | None = None,
        query_hash: str | None = None,
        result_sources: Iterable[str] | str | None = None,
        evidence_summary: str | None = None,
        failure_summary: str | None = None,
        sample_size: int | None = None,
        sample_scope: str | None = None,
        sample_method: str | None = None,
        row_count: int | None = None,
        null_count: int | None = None,
        distinct_count: int | None = None,
        value_frequencies: Iterable[Mapping[str, Any]] | None = None,
        profile_metrics: Iterable[Mapping[str, Any]] | None = None,
        observation_iri: str | None = None,
        evidence_iri: str | None = None,
        source_span_iri: str | None = None,
    ) -> QueryResultRecord:
        """Record an externally executed query result or failure as evidence."""
        status_value = self._query_execution_status(execution_status)
        engine_value = engine.strip() if engine and engine.strip() else None
        query_source_path_value = (
            query_source_path.strip()
            if query_source_path and query_source_path.strip()
            else None
        )
        query_source_section_value = (
            query_source_section.strip()
            if query_source_section and query_source_section.strip()
            else None
        )
        query_hash_value = (
            query_hash.strip() if query_hash and query_hash.strip() else None
        )
        failure_summary_value = (
            failure_summary.strip()
            if failure_summary and failure_summary.strip()
            else None
        )
        result_source_values = self._string_values("result_sources", result_sources)
        if not result_source_values and query_source_path_value is None:
            raise DoxaBaseError(
                "record_query_result requires result_sources or query_source_path"
            )
        for name, value in {"start_line": start_line, "end_line": end_line}.items():
            if value is not None and value < 1:
                raise DoxaBaseError(f"{name} must be a positive one-based line number")
        profile_payload_present = any(
            value is not None
            for value in (
                sample_size,
                row_count,
                null_count,
                distinct_count,
                value_frequencies,
                profile_metrics,
            )
        )
        if status_value != "succeeded" and profile_payload_present:
            raise DoxaBaseError(
                "profile result fields require execution_status='succeeded'"
            )
        observation_type: TypingLiteral["observation", "profile"] = (
            "profile" if profile_payload_present else "observation"
        )
        evidence_summary_value = evidence_summary
        if evidence_summary_value is None:
            evidence_summary_value = self._query_result_evidence_summary(
                status=status_value,
                engine=engine_value,
                query_hash=query_hash_value,
                failure_summary=failure_summary_value,
            )

        observation = self.record_observation(
            summary=summary,
            observation_type=observation_type,
            observed_asset=observed_asset,
            observed_at=observed_at,
            observed_by=observed_by,
            evidence_summary=evidence_summary_value,
            evidence_sources=result_source_values,
            sample_size=sample_size,
            sample_scope=sample_scope,
            sample_method=sample_method,
            row_count=row_count,
            null_count=null_count,
            distinct_count=distinct_count,
            value_frequencies=value_frequencies,
            profile_metrics=profile_metrics,
            observation_iri=observation_iri,
            evidence_iri=evidence_iri,
        )
        assert observation.evidence_iri is not None
        source_span_triples = 0
        source_span_value: str | None = None
        if query_source_path_value is not None:
            source_span_value, source_span_triples = (
                self._insert_evidence_source_span(
                    evidence_iri=observation.evidence_iri,
                    source_path=query_source_path_value,
                    source_section=query_source_section_value,
                    start_line=start_line,
                    end_line=end_line,
                    source_kind="rc:QuerySource",
                    source_span_iri=source_span_iri,
                )
            )

        return QueryResultRecord(
            observation_iri=observation.observation_iri,
            observation_type=observation.observation_type,
            evidence_iri=observation.evidence_iri,
            source_span_iri=source_span_value,
            execution_status=status_value,
            engine=engine_value,
            query_source_path=query_source_path_value,
            query_hash=query_hash_value,
            result_sources=result_source_values,
            observation_triples=observation.observation_triples,
            evidence_triples=observation.evidence_triples + source_span_triples,
            source_span_triples=source_span_triples,
        )

    @staticmethod
    def _query_execution_status(status: str) -> str:
        status_value = status.strip().lower()
        allowed = {"succeeded", "failed", "partial", "cancelled", "blocked"}
        if status_value not in allowed:
            allowed_display = ", ".join(sorted(allowed))
            raise DoxaBaseError(
                f"execution_status must be one of: {allowed_display}"
            )
        return status_value

    @staticmethod
    def _query_result_evidence_summary(
        *,
        status: str,
        engine: str | None,
        query_hash: str | None,
        failure_summary: str | None,
    ) -> str:
        parts = [f"External query execution {status}."]
        if engine is not None:
            parts.append(f"Engine: {engine}.")
        if query_hash is not None:
            parts.append(f"Query hash: {query_hash}.")
        if failure_summary is not None:
            parts.append(f"Failure summary: {failure_summary}")
        return " ".join(parts)

    def _insert_evidence_source_span(
        self,
        *,
        evidence_iri: str,
        source_path: str,
        source_section: str | None = None,
        start_line: int | None = None,
        end_line: int | None = None,
        source_kind: str | None = None,
        source_span_iri: str | None = None,
    ) -> tuple[str, int]:
        source_span_subject = URIRef(
            source_span_iri or self._mint_iri("source-span")
        )
        evidence_subject = URIRef(evidence_iri)
        evidence_graph = Graph()
        self._bind_prefixes(evidence_graph)
        evidence_graph.add(
            (
                evidence_subject,
                URIRef(self.expand_iri("rc:sourceSpan")),
                source_span_subject,
            )
        )
        evidence_graph.add(
            (
                source_span_subject,
                RDF.type,
                URIRef(self.expand_iri("rc:SourceSpan")),
            )
        )
        evidence_graph.add(
            (
                source_span_subject,
                URIRef(self.expand_iri("rc:sourcePath")),
                Literal(source_path),
            )
        )
        if source_section:
            evidence_graph.add(
                (
                    source_span_subject,
                    URIRef(self.expand_iri("rc:sourceSection")),
                    Literal(source_section),
                )
            )
        if start_line is not None:
            evidence_graph.add(
                (
                    source_span_subject,
                    URIRef(self.expand_iri("rc:startLine")),
                    Literal(start_line, datatype=XSD.integer),
                )
            )
        if end_line is not None:
            evidence_graph.add(
                (
                    source_span_subject,
                    URIRef(self.expand_iri("rc:endLine")),
                    Literal(end_line, datatype=XSD.integer),
                )
            )
        if source_kind is not None:
            evidence_graph.add(
                (
                    source_span_subject,
                    URIRef(self.expand_iri("rc:sourceKind")),
                    URIRef(self.expand_iri(source_kind)),
                )
            )
        return str(source_span_subject), self._insert_graph("evidence", evidence_graph)

    def record_claim_observation(
        self,
        summary: str,
        *,
        claim_text: str,
        claim_kind: str,
        claim_targets: Iterable[str] | str,
        observed_asset: str | None = None,
        observed_column: str | None = None,
        observed_at: datetime | str | None = None,
        observed_by: str | None = None,
        evidence_summary: str | None = None,
        evidence_sources: Iterable[str] | str | None = None,
        source_path: str | None = None,
        source_section: str | None = None,
        start_line: int | None = None,
        end_line: int | None = None,
        source_kind: str | None = None,
        confidence: str | None = "rc:MediumConfidence",
        observation_status: str | None = "rc:Tentative",
        proposed_assertions: Iterable[str] | str | None = None,
        observation_iri: str | None = None,
        claim_iri: str | None = None,
        evidence_iri: str | None = None,
        source_span_iri: str | None = None,
    ) -> ClaimObservationRecord:
        if not summary.strip():
            raise DoxaBaseError("Observation summary must not be empty")
        if not claim_text.strip():
            raise DoxaBaseError("Claim text must not be empty")
        claim_kind_value = claim_kind.strip()
        if not claim_kind_value:
            raise DoxaBaseError("claim_kind must not be empty")
        confidence_value = (
            confidence.strip()
            if confidence and confidence.strip()
            else None
        )
        observation_status_value = (
            observation_status.strip()
            if observation_status and observation_status.strip()
            else None
        )
        source_kind_value = (
            source_kind.strip()
            if source_kind and source_kind.strip()
            else None
        )
        claim_target_values = self._string_values(
            "claim_targets",
            claim_targets,
            required=True,
        )
        evidence_source_values = self._string_values(
            "evidence_sources",
            evidence_sources,
        )
        source_path_value = (
            source_path.strip()
            if source_path and source_path.strip()
            else None
        )
        source_section_value = (
            source_section.strip()
            if source_section and source_section.strip()
            else None
        )
        proposed_assertion_values = self._string_values(
            "proposed_assertions",
            proposed_assertions,
        )
        self._validate_resource_values("claim_targets", claim_target_values)
        self._validate_resource_values(
            "proposed_assertions",
            proposed_assertion_values,
        )
        if not evidence_source_values and source_path_value is None:
            raise DoxaBaseError(
                "record_claim_observation requires evidence_sources or source_path"
            )
        for name, value in {"start_line": start_line, "end_line": end_line}.items():
            if value is not None and value < 1:
                raise DoxaBaseError(f"{name} must be a positive one-based line number")

        observation_subject = URIRef(observation_iri or self._mint_iri("observation"))
        claim_subject = URIRef(claim_iri or self._mint_iri("claim"))
        evidence_subject = URIRef(evidence_iri or self._mint_iri("evidence"))
        self._preflight_evidence_summary_reuse(
            str(evidence_subject),
            evidence_summary,
        )
        source_span_subject = (
            URIRef(source_span_iri or self._mint_iri("source-span"))
            if source_path_value is not None
            else None
        )

        observation_graph = Graph()
        self._bind_prefixes(observation_graph)
        observation_graph.add(
            (observation_subject, RDF.type, URIRef(self.expand_iri("rc:Observation")))
        )
        observation_graph.add(
            (observation_subject, URIRef(self.expand_iri("rc:summary")), Literal(summary))
        )
        observation_graph.add(
            (
                observation_subject,
                URIRef(self.expand_iri("rc:observedAt")),
                self._datetime_literal(observed_at),
            )
        )
        observation_graph.add(
            (
                observation_subject,
                URIRef(self.expand_iri("rc:evidence")),
                evidence_subject,
            )
        )
        observation_graph.add(
            (
                observation_subject,
                URIRef(self.expand_iri("rc:hasClaim")),
                claim_subject,
            )
        )
        if observation_status_value is not None:
            observation_graph.add(
                (
                    observation_subject,
                    URIRef(self.expand_iri("rc:observationStatus")),
                    URIRef(self.expand_iri(observation_status_value)),
                )
            )
        if observed_asset is not None:
            observation_graph.add(
                (
                    observation_subject,
                    URIRef(self.expand_iri("rc:observedAsset")),
                    URIRef(self.expand_iri(observed_asset)),
                )
            )
        if observed_column is not None:
            observation_graph.add(
                (
                    observation_subject,
                    URIRef(self.expand_iri("rc:observedColumn")),
                    URIRef(self.expand_iri(observed_column)),
                )
            )
        if observed_by is not None:
            observation_graph.add(
                (
                    observation_subject,
                    URIRef(self.expand_iri("rc:observedBy")),
                    self._resource_or_literal(observed_by),
                )
            )

        observation_graph.add(
            (claim_subject, RDF.type, URIRef(self.expand_iri("rc:Claim")))
        )
        observation_graph.add(
            (
                claim_subject,
                URIRef(self.expand_iri("rc:claimKind")),
                URIRef(self.expand_iri(claim_kind_value)),
            )
        )
        observation_graph.add(
            (
                claim_subject,
                URIRef(self.expand_iri("rc:claimText")),
                Literal(claim_text),
            )
        )
        for target in claim_target_values:
            observation_graph.add(
                (
                    claim_subject,
                    URIRef(self.expand_iri("rc:claimTarget")),
                    URIRef(self.expand_iri(target)),
                )
            )
        if confidence_value is not None:
            observation_graph.add(
                (
                    claim_subject,
                    URIRef(self.expand_iri("rc:confidence")),
                    URIRef(self.expand_iri(confidence_value)),
                )
            )
        if observation_status_value is not None:
            observation_graph.add(
                (
                    claim_subject,
                    URIRef(self.expand_iri("rc:observationStatus")),
                    URIRef(self.expand_iri(observation_status_value)),
                )
            )
        for assertion in proposed_assertion_values:
            observation_graph.add(
                (
                    claim_subject,
                    URIRef(self.expand_iri("rc:proposedAssertion")),
                    URIRef(self.expand_iri(assertion)),
                )
            )

        evidence_graph = Graph()
        self._bind_prefixes(evidence_graph)
        evidence_graph.add(
            (evidence_subject, RDF.type, URIRef(self.expand_iri("rc:Evidence")))
        )
        if evidence_summary:
            evidence_graph.add(
                (
                    evidence_subject,
                    URIRef(self.expand_iri("rc:summary")),
                    Literal(evidence_summary),
                )
            )
        for source in evidence_source_values:
            evidence_graph.add((evidence_subject, DCTERMS.source, Literal(source)))
        if source_path_value is not None:
            assert source_span_subject is not None
            evidence_graph.add(
                (
                    evidence_subject,
                    URIRef(self.expand_iri("rc:sourceSpan")),
                    source_span_subject,
                )
            )
            evidence_graph.add(
                (
                    source_span_subject,
                    RDF.type,
                    URIRef(self.expand_iri("rc:SourceSpan")),
                )
            )
            evidence_graph.add(
                (
                    source_span_subject,
                    URIRef(self.expand_iri("rc:sourcePath")),
                    Literal(source_path_value),
                )
            )
            if source_section_value:
                evidence_graph.add(
                    (
                        source_span_subject,
                        URIRef(self.expand_iri("rc:sourceSection")),
                        Literal(source_section_value),
                    )
                )
            if start_line is not None:
                evidence_graph.add(
                    (
                        source_span_subject,
                        URIRef(self.expand_iri("rc:startLine")),
                        Literal(start_line, datatype=XSD.integer),
                    )
                )
            if end_line is not None:
                evidence_graph.add(
                    (
                        source_span_subject,
                        URIRef(self.expand_iri("rc:endLine")),
                        Literal(end_line, datatype=XSD.integer),
                    )
                )
            if source_kind_value is not None:
                evidence_graph.add(
                    (
                        source_span_subject,
                        URIRef(self.expand_iri("rc:sourceKind")),
                        URIRef(self.expand_iri(source_kind_value)),
                    )
                )

        evidence_triples = self._insert_graph("evidence", evidence_graph)
        observation_triples = self._insert_graph("observations", observation_graph)
        return ClaimObservationRecord(
            observation_iri=str(observation_subject),
            claim_iri=str(claim_subject),
            evidence_iri=str(evidence_subject),
            source_span_iri=(
                str(source_span_subject) if source_span_subject is not None else None
            ),
            observation_triples=observation_triples,
            evidence_triples=evidence_triples,
        )

    def record_pattern(
        self,
        summary: str,
        *,
        pattern_text: str,
        rationale: str,
        pattern_targets: Iterable[str] | str,
        supporting_observations: Iterable[str] | str | None = None,
        supporting_claims: Iterable[str] | str | None = None,
        synthesized_at: datetime | str | None = None,
        synthesized_by: str | None = None,
        evidence_summary: str | None = None,
        evidence_sources: Iterable[str] | str | None = None,
        source_path: str | None = None,
        source_section: str | None = None,
        start_line: int | None = None,
        end_line: int | None = None,
        source_kind: str | None = None,
        confidence: str | None = "rc:MediumConfidence",
        pattern_status: str | None = "rc:Tentative",
        pattern_stability: str | None = "rc:EmergingPattern",
        map_implications: Iterable[str] | str | None = None,
        pattern_iri: str | None = None,
        evidence_iri: str | None = None,
        source_span_iri: str | None = None,
    ) -> PatternRecord:
        if not summary.strip():
            raise DoxaBaseError("Pattern summary must not be empty")
        if not pattern_text.strip():
            raise DoxaBaseError("pattern_text must not be empty")
        if not rationale.strip():
            raise DoxaBaseError("rationale must not be empty")

        pattern_target_values = self._string_values(
            "pattern_targets",
            pattern_targets,
            required=True,
        )
        supporting_observation_values = self._string_values(
            "supporting_observations",
            supporting_observations,
        )
        supporting_claim_values = self._string_values(
            "supporting_claims",
            supporting_claims,
        )
        evidence_source_values = self._string_values(
            "evidence_sources",
            evidence_sources,
        )
        map_implication_values = self._string_values(
            "map_implications",
            map_implications,
        )
        self._validate_resource_values("pattern_targets", pattern_target_values)
        self._validate_resource_values(
            "supporting_observations",
            supporting_observation_values,
        )
        self._validate_resource_values("supporting_claims", supporting_claim_values)
        self._validate_resource_values("map_implications", map_implication_values)
        source_path_value = (
            source_path.strip()
            if source_path and source_path.strip()
            else None
        )
        source_section_value = (
            source_section.strip()
            if source_section and source_section.strip()
            else None
        )
        source_kind_value = (
            source_kind.strip()
            if source_kind and source_kind.strip()
            else None
        )
        confidence_value = (
            confidence.strip()
            if confidence and confidence.strip()
            else None
        )
        pattern_status_value = (
            pattern_status.strip()
            if pattern_status and pattern_status.strip()
            else None
        )
        pattern_stability_value = (
            pattern_stability.strip()
            if pattern_stability and pattern_stability.strip()
            else None
        )
        evidence_iri_value = (
            evidence_iri.strip()
            if evidence_iri and evidence_iri.strip()
            else None
        )

        if (
            not supporting_observation_values
            and not supporting_claim_values
            and not evidence_source_values
            and source_path_value is None
            and evidence_iri_value is None
        ):
            raise DoxaBaseError(
                "record_pattern requires supporting_observations, "
                "supporting_claims, evidence_sources, source_path, or evidence_iri"
            )
        if evidence_summary and not evidence_source_values and source_path_value is None:
            raise DoxaBaseError(
                "evidence_summary requires evidence_sources or source_path"
            )
        for name, value in {"start_line": start_line, "end_line": end_line}.items():
            if value is not None and value < 1:
                raise DoxaBaseError(f"{name} must be a positive one-based line number")

        pattern_subject = URIRef(pattern_iri or self._mint_iri("pattern"))
        evidence_subject = (
            URIRef(evidence_iri_value)
            if evidence_iri_value is not None
            else URIRef(self._mint_iri("evidence"))
            if evidence_source_values or source_path_value
            else None
        )
        if evidence_subject is not None:
            self._preflight_evidence_summary_reuse(
                str(evidence_subject),
                evidence_summary,
            )
        source_span_subject = (
            URIRef(source_span_iri or self._mint_iri("source-span"))
            if source_path_value is not None
            else None
        )

        pattern_graph = Graph()
        self._bind_prefixes(pattern_graph)
        pattern_graph.add(
            (pattern_subject, RDF.type, URIRef(self.expand_iri("rc:Pattern")))
        )
        pattern_graph.add(
            (pattern_subject, URIRef(self.expand_iri("rc:summary")), Literal(summary))
        )
        pattern_graph.add(
            (
                pattern_subject,
                URIRef(self.expand_iri("rc:patternText")),
                Literal(pattern_text),
            )
        )
        pattern_graph.add(
            (
                pattern_subject,
                URIRef(self.expand_iri("rc:rationale")),
                Literal(rationale),
            )
        )
        pattern_graph.add(
            (
                pattern_subject,
                URIRef(self.expand_iri("rc:synthesizedAt")),
                self._datetime_literal(synthesized_at),
            )
        )
        if synthesized_by is not None:
            pattern_graph.add(
                (
                    pattern_subject,
                    URIRef(self.expand_iri("rc:synthesizedBy")),
                    self._resource_or_literal(synthesized_by),
                )
            )
        for target in pattern_target_values:
            pattern_graph.add(
                (
                    pattern_subject,
                    URIRef(self.expand_iri("rc:patternTarget")),
                    URIRef(self.expand_iri(target)),
                )
            )
        for observation in supporting_observation_values:
            pattern_graph.add(
                (
                    pattern_subject,
                    URIRef(self.expand_iri("rc:supportingObservation")),
                    URIRef(self.expand_iri(observation)),
                )
            )
        for claim in supporting_claim_values:
            pattern_graph.add(
                (
                    pattern_subject,
                    URIRef(self.expand_iri("rc:supportingClaim")),
                    URIRef(self.expand_iri(claim)),
                )
            )
        if evidence_subject is not None:
            pattern_graph.add(
                (
                    pattern_subject,
                    URIRef(self.expand_iri("rc:evidence")),
                    evidence_subject,
                )
            )
        if confidence_value is not None:
            pattern_graph.add(
                (
                    pattern_subject,
                    URIRef(self.expand_iri("rc:confidence")),
                    URIRef(self.expand_iri(confidence_value)),
                )
            )
        if pattern_status_value is not None:
            pattern_graph.add(
                (
                    pattern_subject,
                    URIRef(self.expand_iri("rc:observationStatus")),
                    URIRef(self.expand_iri(pattern_status_value)),
                )
            )
        if pattern_stability_value is not None:
            pattern_graph.add(
                (
                    pattern_subject,
                    URIRef(self.expand_iri("rc:patternStability")),
                    URIRef(self.expand_iri(pattern_stability_value)),
                )
            )
        for implication in map_implication_values:
            pattern_graph.add(
                (
                    pattern_subject,
                    URIRef(self.expand_iri("rc:mapImplication")),
                    URIRef(self.expand_iri(implication)),
                )
            )

        evidence_triples = 0
        if evidence_subject is not None and (evidence_source_values or source_path_value):
            evidence_graph = Graph()
            self._bind_prefixes(evidence_graph)
            evidence_graph.add(
                (evidence_subject, RDF.type, URIRef(self.expand_iri("rc:Evidence")))
            )
            if evidence_summary:
                evidence_graph.add(
                    (
                        evidence_subject,
                        URIRef(self.expand_iri("rc:summary")),
                        Literal(evidence_summary),
                    )
                )
            for source in evidence_source_values:
                evidence_graph.add((evidence_subject, DCTERMS.source, Literal(source)))
            if source_path_value is not None:
                assert source_span_subject is not None
                evidence_graph.add(
                    (
                        evidence_subject,
                        URIRef(self.expand_iri("rc:sourceSpan")),
                        source_span_subject,
                    )
                )
                evidence_graph.add(
                    (
                        source_span_subject,
                        RDF.type,
                        URIRef(self.expand_iri("rc:SourceSpan")),
                    )
                )
                evidence_graph.add(
                    (
                        source_span_subject,
                        URIRef(self.expand_iri("rc:sourcePath")),
                        Literal(source_path_value),
                    )
                )
                if source_section_value:
                    evidence_graph.add(
                        (
                            source_span_subject,
                            URIRef(self.expand_iri("rc:sourceSection")),
                            Literal(source_section_value),
                        )
                    )
                if start_line is not None:
                    evidence_graph.add(
                        (
                            source_span_subject,
                            URIRef(self.expand_iri("rc:startLine")),
                            Literal(start_line, datatype=XSD.integer),
                        )
                    )
                if end_line is not None:
                    evidence_graph.add(
                        (
                            source_span_subject,
                            URIRef(self.expand_iri("rc:endLine")),
                            Literal(end_line, datatype=XSD.integer),
                        )
                    )
                if source_kind_value is not None:
                    evidence_graph.add(
                        (
                            source_span_subject,
                            URIRef(self.expand_iri("rc:sourceKind")),
                            URIRef(self.expand_iri(source_kind_value)),
                        )
                    )
            evidence_triples = self._insert_graph("evidence", evidence_graph)

        pattern_triples = self._insert_graph("patterns", pattern_graph)
        return PatternRecord(
            pattern_iri=str(pattern_subject),
            evidence_iri=str(evidence_subject) if evidence_subject is not None else None,
            source_span_iri=(
                str(source_span_subject) if source_span_subject is not None else None
            ),
            pattern_triples=pattern_triples,
            evidence_triples=evidence_triples,
        )

    def record_dataset_profile(
        self,
        dataset_iri: str,
        *,
        summary: str,
        observed_at: datetime | str | None = None,
        observed_by: str | None = None,
        evidence_summary: str | None = None,
        evidence_sources: Iterable[str] | str | None = None,
        sample_size: int | None = None,
        sample_scope: str | None = None,
        sample_method: str | None = None,
        row_count: int | None = None,
        null_count: int | None = None,
        distinct_count: int | None = None,
        value_frequencies: Iterable[Mapping[str, Any]] | None = None,
        profile_metrics: Iterable[Mapping[str, Any]] | None = None,
        update_map_snapshot: bool = True,
        allow_sampled_row_count_snapshot: bool = False,
        map_label: str | None = None,
        map_description: str | None = None,
        is_table: bool | None = None,
        pattern_summary: str | None = None,
        pattern_text: str | None = None,
        pattern_rationale: str | None = None,
        pattern_confidence: str | None = "rc:MediumConfidence",
        pattern_status: str | None = "rc:Tentative",
        pattern_stability: str | None = "rc:EmergingPattern",
        pattern_map_implications: Iterable[str] | str | None = None,
        observation_iri: str | None = None,
        evidence_iri: str | None = None,
        pattern_iri: str | None = None,
    ) -> DatasetProfileRecord:
        dataset_value = self._required_iri("dataset_iri", dataset_iri)
        profile_metric_items = (
            list(profile_metrics) if profile_metrics is not None else None
        )
        should_record_pattern = self._profile_pattern_requested(
            pattern_summary,
            pattern_text,
            pattern_rationale,
        )

        observation = self.record_observation(
            summary=summary,
            observation_type="profile",
            observed_asset=dataset_value,
            observed_at=observed_at,
            observed_by=observed_by,
            evidence_summary=evidence_summary,
            evidence_sources=evidence_sources,
            sample_size=sample_size,
            sample_scope=sample_scope,
            sample_method=sample_method,
            row_count=row_count,
            null_count=null_count,
            distinct_count=distinct_count,
            value_frequencies=value_frequencies,
            profile_metrics=profile_metric_items,
            observation_iri=observation_iri,
            evidence_iri=evidence_iri,
        )

        map_dataset: MapResourceRecord | None = None
        row_count_snapshot = self._profile_row_count_snapshot_value(
            row_count=row_count,
            sample_size=sample_size,
            sample_scope=sample_scope,
            sample_method=sample_method,
            allow_sampled_row_count_snapshot=allow_sampled_row_count_snapshot,
        )
        should_update_map = update_map_snapshot and (
            row_count_snapshot is not None
            or map_label is not None
            or map_description is not None
            or is_table is not None
        )
        if should_update_map:
            map_dataset = self.record_map_dataset(
                dataset_value,
                label=map_label,
                description=map_description,
                is_table=is_table,
                row_count_snapshot=row_count_snapshot,
            )

        pattern: PatternRecord | None = None
        if should_record_pattern:
            assert pattern_summary is not None
            assert pattern_text is not None
            assert pattern_rationale is not None
            implication_values = self._profile_pattern_map_implications(
                dataset_value,
                pattern_map_implications,
                ("profile_metrics", profile_metric_items),
            )
            pattern = self.record_pattern(
                summary=pattern_summary,
                pattern_text=pattern_text,
                rationale=pattern_rationale,
                pattern_targets=[dataset_value],
                supporting_observations=[observation.observation_iri],
                evidence_iri=observation.evidence_iri,
                confidence=pattern_confidence,
                pattern_status=pattern_status,
                pattern_stability=pattern_stability,
                map_implications=implication_values,
                pattern_iri=pattern_iri,
            )

        return DatasetProfileRecord(
            dataset_iri=dataset_value,
            observation=observation,
            map_dataset=map_dataset,
            pattern=pattern,
        )

    def _profile_row_count_snapshot_value(
        self,
        *,
        row_count: int | None,
        sample_size: int | None,
        sample_scope: str | None,
        sample_method: str | None,
        allow_sampled_row_count_snapshot: bool,
    ) -> int | None:
        if row_count is None:
            return None
        basis = self._profile_observation_basis_from_values(
            sample_size=sample_size,
            sample_scope=sample_scope,
            sample_method=sample_method,
            row_count=row_count,
        )
        if basis == "full_scan" or allow_sampled_row_count_snapshot:
            return row_count
        return None

    def record_column_profile(
        self,
        column_iri: str,
        *,
        column_name: str,
        summary: str,
        table_iri: str | None = None,
        observed_at: datetime | str | None = None,
        observed_by: str | None = None,
        evidence_summary: str | None = None,
        evidence_sources: Iterable[str] | str | None = None,
        sample_size: int | None = None,
        sample_scope: str | None = None,
        sample_method: str | None = None,
        row_count: int | None = None,
        null_count: int | None = None,
        distinct_count: int | None = None,
        value_frequencies: Iterable[Mapping[str, Any]] | None = None,
        profile_metrics: Iterable[Mapping[str, Any]] | None = None,
        update_map_column: bool = True,
        map_label: str | None = None,
        map_description: str | None = None,
        physical_type: str | None = None,
        value_type: str | None = None,
        nullable: bool | None = None,
        pattern_summary: str | None = None,
        pattern_text: str | None = None,
        pattern_rationale: str | None = None,
        pattern_confidence: str | None = "rc:MediumConfidence",
        pattern_status: str | None = "rc:Tentative",
        pattern_stability: str | None = "rc:EmergingPattern",
        pattern_map_implications: Iterable[str] | str | None = None,
        observation_iri: str | None = None,
        evidence_iri: str | None = None,
        pattern_iri: str | None = None,
    ) -> ColumnProfileRecord:
        column_value = self._required_iri("column_iri", column_iri)
        profile_metric_items = (
            list(profile_metrics) if profile_metrics is not None else None
        )
        table_value = (
            self._required_iri("table_iri", table_iri)
            if table_iri is not None
            else None
        )
        should_record_pattern = self._profile_pattern_requested(
            pattern_summary,
            pattern_text,
            pattern_rationale,
        )

        observation = self.record_observation(
            summary=summary,
            observation_type="profile",
            observed_asset=table_value,
            observed_column=column_value,
            observed_column_name=column_name,
            observed_at=observed_at,
            observed_by=observed_by,
            evidence_summary=evidence_summary,
            evidence_sources=evidence_sources,
            sample_size=sample_size,
            sample_scope=sample_scope,
            sample_method=sample_method,
            row_count=row_count,
            null_count=null_count,
            distinct_count=distinct_count,
            value_frequencies=value_frequencies,
            profile_metrics=profile_metric_items,
            observed_physical_type=physical_type,
            observed_value_type=value_type,
            observation_iri=observation_iri,
            evidence_iri=evidence_iri,
        )

        map_column: MapResourceRecord | None = None
        should_update_map = update_map_column and (
            table_value is not None
            or map_label is not None
            or map_description is not None
            or physical_type is not None
            or value_type is not None
            or nullable is not None
        )
        if should_update_map:
            map_column = self.record_map_column(
                column_value,
                column_name=column_name,
                table_iri=table_value,
                label=map_label,
                description=map_description,
                physical_type=physical_type,
                value_type=value_type,
                nullable=nullable,
            )

        pattern: PatternRecord | None = None
        if should_record_pattern:
            assert pattern_summary is not None
            assert pattern_text is not None
            assert pattern_rationale is not None
            implication_values = self._profile_pattern_map_implications(
                column_value,
                pattern_map_implications,
                ("profile_metrics", profile_metric_items),
            )
            pattern = self.record_pattern(
                summary=pattern_summary,
                pattern_text=pattern_text,
                rationale=pattern_rationale,
                pattern_targets=[column_value],
                supporting_observations=[observation.observation_iri],
                evidence_iri=observation.evidence_iri,
                confidence=pattern_confidence,
                pattern_status=pattern_status,
                pattern_stability=pattern_stability,
                map_implications=implication_values,
                pattern_iri=pattern_iri,
            )

        return ColumnProfileRecord(
            column_iri=column_value,
            table_iri=table_value,
            observation=observation,
            map_column=map_column,
            pattern=pattern,
        )

    def record_profile_bundle(
        self,
        dataset_iri: str,
        *,
        dataset_summary: str,
        column_profiles: Iterable[Mapping[str, Any]] | None = None,
        observed_at: datetime | str | None = None,
        observed_by: str | None = None,
        evidence_summary: str | None = None,
        evidence_sources: Iterable[str] | str | None = None,
        sample_size: int | None = None,
        sample_scope: str | None = None,
        sample_method: str | None = None,
        row_count: int | None = None,
        null_count: int | None = None,
        distinct_count: int | None = None,
        value_frequencies: Iterable[Mapping[str, Any]] | None = None,
        profile_metrics: Iterable[Mapping[str, Any]] | None = None,
        update_map_snapshot: bool = True,
        allow_sampled_row_count_snapshot: bool = False,
        map_label: str | None = None,
        map_description: str | None = None,
        is_table: bool | None = None,
        pattern_summary: str | None = None,
        pattern_text: str | None = None,
        pattern_rationale: str | None = None,
        pattern_confidence: str | None = "rc:MediumConfidence",
        pattern_status: str | None = "rc:Tentative",
        pattern_stability: str | None = "rc:EmergingPattern",
        pattern_map_implications: Iterable[str] | str | None = None,
        pattern_support_scope: TypingLiteral["dataset_profile", "all_profiles"]
        | str = "dataset_profile",
        shared_evidence_iri: str | None = None,
        column_defaults: Mapping[str, Any] | None = None,
    ) -> ProfileBundleRecord:
        dataset_value = self._required_iri("dataset_iri", dataset_iri)
        profile_metric_items = (
            list(profile_metrics) if profile_metrics is not None else None
        )
        pattern_support_scope_value = self._profile_bundle_pattern_support_scope(
            pattern_support_scope
        )
        allowed_column_keys = {
            "column_iri",
            "column_name",
            "summary",
            "table_iri",
            "observed_at",
            "observed_by",
            "evidence_summary",
            "evidence_sources",
            "sample_size",
            "sample_scope",
            "sample_method",
            "row_count",
            "null_count",
            "distinct_count",
            "value_frequencies",
            "profile_metrics",
            "update_map_column",
            "map_label",
            "map_description",
            "physical_type",
            "value_type",
            "nullable",
            "pattern_summary",
            "pattern_text",
            "pattern_rationale",
            "pattern_confidence",
            "pattern_status",
            "pattern_stability",
            "pattern_map_implications",
            "observation_iri",
            "evidence_iri",
            "pattern_iri",
        }
        required_column_keys = {"column_iri", "column_name", "summary"}

        shared_column_defaults: dict[str, Any] = {
            "table_iri": dataset_value,
            "observed_at": observed_at,
            "observed_by": observed_by,
            "evidence_summary": evidence_summary,
            "evidence_sources": evidence_sources,
            "sample_size": sample_size,
            "sample_scope": sample_scope,
            "sample_method": sample_method,
            "evidence_iri": shared_evidence_iri,
        }
        merged_defaults = {
            key: value
            for key, value in shared_column_defaults.items()
            if value is not None
        }
        if column_defaults is not None:
            merged_defaults.update(dict(column_defaults))
        unknown_defaults = sorted(set(merged_defaults) - allowed_column_keys)
        if unknown_defaults:
            raise DoxaBaseError(
                "column_defaults contains unsupported record_column_profile "
                f"field(s): {', '.join(unknown_defaults)}"
            )
        should_record_pattern = self._profile_pattern_requested(
            pattern_summary,
            pattern_text,
            pattern_rationale,
        )

        prepared_column_profiles: list[dict[str, Any]] = []
        for index, profile_mapping in enumerate(column_profiles or []):
            try:
                profile_values = dict(profile_mapping)
            except (TypeError, ValueError) as exc:
                raise DoxaBaseError(
                    f"column_profiles[{index}] must be a mapping"
                ) from exc
            unknown_keys = sorted(set(profile_values) - allowed_column_keys)
            if unknown_keys:
                raise DoxaBaseError(
                    f"column_profiles[{index}] contains unsupported "
                    f"record_column_profile field(s): {', '.join(unknown_keys)}"
                )
            column_kwargs = {**merged_defaults, **profile_values}
            if column_kwargs.get("profile_metrics") is not None:
                column_kwargs["profile_metrics"] = list(
                    column_kwargs["profile_metrics"]
                )
            missing_keys = sorted(
                key for key in required_column_keys if not column_kwargs.get(key)
            )
            if missing_keys:
                raise DoxaBaseError(
                    f"column_profiles[{index}] is missing required field(s): "
                    f"{', '.join(missing_keys)}"
                )
            self._preflight_profile_bundle_column(index, column_kwargs)
            prepared_column_profiles.append(column_kwargs)

        bundle_pattern_implications: list[str] | None = None
        if should_record_pattern:
            metric_sets: list[tuple[str, Iterable[Mapping[str, Any]] | None]] = [
                ("profile_metrics", profile_metric_items)
            ]
            if pattern_support_scope_value == "all_profiles":
                metric_sets.extend(
                    (
                        f"column_profiles[{index}].profile_metrics",
                        column_kwargs.get("profile_metrics"),
                    )
                    for index, column_kwargs in enumerate(prepared_column_profiles)
                )
            bundle_pattern_implications = self._profile_pattern_map_implications(
                dataset_value,
                pattern_map_implications,
                *metric_sets,
            )
            self._validate_resource_values(
                "pattern_map_implications",
                bundle_pattern_implications,
            )

        self._preflight_profile_bundle_evidence_summaries(
            shared_evidence_iri=shared_evidence_iri,
            dataset_evidence_summary=evidence_summary,
            column_profiles=prepared_column_profiles,
        )

        dataset_profile = self.record_dataset_profile(
            dataset_value,
            summary=dataset_summary,
            observed_at=observed_at,
            observed_by=observed_by,
            evidence_summary=evidence_summary,
            evidence_sources=evidence_sources,
            sample_size=sample_size,
            sample_scope=sample_scope,
            sample_method=sample_method,
            row_count=row_count,
            null_count=null_count,
            distinct_count=distinct_count,
            value_frequencies=value_frequencies,
            profile_metrics=profile_metric_items,
            update_map_snapshot=update_map_snapshot,
            allow_sampled_row_count_snapshot=allow_sampled_row_count_snapshot,
            map_label=map_label,
            map_description=map_description,
            is_table=is_table,
            pattern_summary=(
                pattern_summary
                if pattern_support_scope_value == "dataset_profile"
                else None
            ),
            pattern_text=(
                pattern_text
                if pattern_support_scope_value == "dataset_profile"
                else None
            ),
            pattern_rationale=(
                pattern_rationale
                if pattern_support_scope_value == "dataset_profile"
                else None
            ),
            pattern_confidence=pattern_confidence,
            pattern_status=pattern_status,
            pattern_stability=pattern_stability,
            pattern_map_implications=(
                bundle_pattern_implications
                if pattern_support_scope_value == "dataset_profile"
                else None
            ),
            evidence_iri=shared_evidence_iri,
        )

        recorded_columns: list[ColumnProfileRecord] = []
        for column_kwargs in prepared_column_profiles:
            recorded_columns.append(
                self.record_column_profile(**column_kwargs)  # type: ignore[arg-type]
            )

        if should_record_pattern and pattern_support_scope_value == "all_profiles":
            assert pattern_summary is not None
            assert pattern_text is not None
            assert pattern_rationale is not None
            assert bundle_pattern_implications is not None
            pattern = self.record_pattern(
                summary=pattern_summary,
                pattern_text=pattern_text,
                rationale=pattern_rationale,
                pattern_targets=[dataset_value],
                supporting_observations=[
                    dataset_profile.observation.observation_iri,
                    *(
                        column_profile.observation.observation_iri
                        for column_profile in recorded_columns
                    ),
                ],
                evidence_iri=dataset_profile.observation.evidence_iri,
                confidence=pattern_confidence,
                pattern_status=pattern_status,
                pattern_stability=pattern_stability,
                map_implications=bundle_pattern_implications,
            )
            dataset_profile = replace(dataset_profile, pattern=pattern)

        return ProfileBundleRecord(
            dataset_iri=dataset_value,
            shared_evidence_iri=shared_evidence_iri,
            dataset_profile=dataset_profile,
            column_profiles=recorded_columns,
            handoff_entrypoints=self._profile_bundle_handoff_entrypoints(
                dataset_iri=dataset_value,
                shared_evidence_iri=shared_evidence_iri,
                dataset_profile=dataset_profile,
                column_profiles=recorded_columns,
            ),
        )

    def _profile_bundle_handoff_entrypoints(
        self,
        *,
        dataset_iri: str,
        shared_evidence_iri: str | None,
        dataset_profile: DatasetProfileRecord,
        column_profiles: list[ColumnProfileRecord],
    ) -> ProfileBundleHandoffEntryPoints:
        dataset_profile_observation_iri = (
            dataset_profile.observation.observation_iri
        )
        column_profile_observation_iris = [
            column_profile.observation.observation_iri
            for column_profile in column_profiles
        ]
        profile_observation_iris = [
            dataset_profile_observation_iri,
            *column_profile_observation_iris,
        ]
        profile_run_evidence_iri = (
            dataset_profile.observation.evidence_iri
            if shared_evidence_iri is not None
            else None
        )
        dataset_describe_available = self._subject_exists(
            dataset_iri,
            self._expand_graphs(["map"]),
        )
        map_dataset_recorded = dataset_profile.map_dataset is not None
        profile_run_available = profile_run_evidence_iri is not None
        map_graphs = self._expand_graphs(["map"])
        updated_map_column_iris = [
            column_profile.column_iri
            for column_profile in column_profiles
            if column_profile.map_column is not None
        ]
        mapped_profiled_column_iris = [
            column_profile.column_iri
            for column_profile in column_profiles
            if self.expand_iri("rc:Column")
            in self._types_from_graphs(map_graphs, column_profile.column_iri)
        ]
        suggested_next_actions: list[SuggestedNextAction] = []

        def add_action(
            tool_name: str,
            arguments: dict[str, Any],
            reason: str,
            *,
            action_label: str,
            call: str,
        ) -> None:
            suggested_next_actions.append(
                SuggestedNextAction(
                    action_label=action_label,
                    tool_name=tool_name,
                    mcp_tool_name=f"doxabase.{tool_name}",
                    arguments=arguments,
                    reason=reason,
                    call=call,
                )
            )

        if dataset_describe_available:
            add_action(
                "describe_dataset",
                {"iri": dataset_iri},
                (
                    "Inspect the bounded dataset view with current map facts "
                    "and returned profile summaries."
                ),
                action_label="Describe dataset",
                call=f"describe_dataset({dataset_iri!r})",
            )
        if profile_run_available:
            add_action(
                "describe_profile_run",
                {
                    "dataset_iri": dataset_iri,
                    "evidence_iri": profile_run_evidence_iri,
                },
                (
                    "Inspect every returned profile observation linked to the "
                    "shared evidence run."
                ),
                action_label="Describe profile run",
                call=(
                    "describe_profile_run("
                    f"{dataset_iri!r}, {profile_run_evidence_iri!r}"
                    ")"
                ),
            )
        if dataset_describe_available and profile_run_available:
            add_action(
                "draft_profile_map_updates",
                {
                    "dataset_iri": dataset_iri,
                    "evidence_iri": profile_run_evidence_iri,
                },
                (
                    "Draft reviewable map update recommendations from this "
                    "profile run before deciding which findings should become "
                    "durable map facts."
                ),
                action_label="Draft profile map updates",
                call=(
                    "draft_profile_map_updates("
                    f"{dataset_iri!r}, {profile_run_evidence_iri!r}"
                    ")"
                ),
            )
        if dataset_describe_available:
            add_action(
                "describe_context_slice",
                {"seed_iris": [dataset_iri], "profile": "dataset_brief"},
                (
                    "Load route-explained dataset context before deciding "
                    "which profile findings should become durable map facts."
                ),
                action_label="Load dataset context slice",
                call=(
                    "describe_context_slice("
                    f"[{dataset_iri!r}], profile='dataset_brief'"
                    ")"
                ),
            )
        add_action(
            "describe_context_slice",
            {"seed_iris": profile_observation_iris, "profile": "dataset_brief"},
            (
                "Load profile-observation-seeded context when map dataset "
                "context is unavailable or the profile run needs a direct handoff."
            ),
            action_label="Load profile context slice",
            call=(
                "describe_context_slice("
                f"{profile_observation_iris!r}, profile='dataset_brief'"
                ")"
            ),
        )
        suggested_next_calls = [action.call for action in suggested_next_actions]
        if dataset_describe_available and profile_run_available:
            if map_dataset_recorded:
                handoff_note = (
                    "Map dataset context is available; use describe_dataset for the "
                    "bounded dataset view or describe_profile_run for the shared "
                    "evidence run."
                )
            else:
                handoff_note = (
                    "Map dataset context already existed; this profile bundle did "
                    "not write dataset map facts or a row-count snapshot. Use "
                    "describe_dataset for the bounded dataset view or "
                    "describe_profile_run for the shared evidence run."
                )
        elif dataset_describe_available:
            if map_dataset_recorded:
                handoff_note = (
                    "Map dataset context is available, but no shared evidence IRI "
                    "was supplied; use profile_observation_iris for run-level "
                    "handoff."
                )
            else:
                handoff_note = (
                    "Map dataset context already existed, but this profile bundle "
                    "did not write dataset map facts and no shared evidence IRI "
                    "was supplied; use profile_observation_iris for run-level "
                    "handoff."
                )
        elif profile_run_available:
            handoff_note = (
                "No map dataset subject is currently available; use "
                "describe_profile_run or seed describe_context_slice from the "
                "profile observation IRIs."
            )
        else:
            handoff_note = (
                "No map dataset subject or shared evidence IRI is currently "
                "available; use profile_observation_iris as the handoff seeds."
            )
        return ProfileBundleHandoffEntryPoints(
            dataset_iri=dataset_iri,
            shared_evidence_iri=profile_run_evidence_iri,
            dataset_profile_observation_iri=dataset_profile_observation_iri,
            column_profile_observation_iris=column_profile_observation_iris,
            profile_observation_iris=profile_observation_iris,
            map_dataset_recorded=map_dataset_recorded,
            map_column_iris=updated_map_column_iris,
            updated_map_column_iris=updated_map_column_iris,
            mapped_profiled_column_iris=mapped_profiled_column_iris,
            dataset_describe_available=dataset_describe_available,
            profile_run_available=profile_run_available,
            suggested_next_actions=suggested_next_actions,
            suggested_next_calls=suggested_next_calls,
            handoff_note=handoff_note,
        )

    def _preflight_profile_bundle_evidence_summaries(
        self,
        *,
        shared_evidence_iri: str | None,
        dataset_evidence_summary: str | None,
        column_profiles: Iterable[Mapping[str, Any]],
    ) -> None:
        summaries_by_evidence: dict[str, tuple[str, str]] = {}

        def add_summary(
            label: str,
            evidence_iri: Any,
            evidence_summary: Any,
        ) -> None:
            if not isinstance(evidence_iri, str) or not evidence_iri.strip():
                return
            if not isinstance(evidence_summary, str) or not evidence_summary.strip():
                return
            evidence_value = evidence_iri.strip()
            existing = summaries_by_evidence.get(evidence_value)
            if existing is not None and existing[0] != evidence_summary:
                raise DoxaBaseError(
                    "record_profile_bundle reuses evidence_iri "
                    f"{evidence_value!r} with conflicting evidence_summary "
                    f"values in {existing[1]} and {label}"
                )
            summaries_by_evidence[evidence_value] = (evidence_summary, label)
            self._preflight_evidence_summary_reuse(
                evidence_value,
                evidence_summary,
                field_name=f"{label}.evidence_summary",
            )

        add_summary(
            "dataset profile",
            shared_evidence_iri,
            dataset_evidence_summary,
        )
        for index, column_kwargs in enumerate(column_profiles):
            add_summary(
                f"column_profiles[{index}]",
                column_kwargs.get("evidence_iri"),
                column_kwargs.get("evidence_summary"),
            )

    def _profile_bundle_pattern_support_scope(self, value: str | None) -> str:
        if value is None:
            return "dataset_profile"
        scope = value.strip().lower()
        if scope in {"dataset_profile", "all_profiles"}:
            return scope
        raise DoxaBaseError(
            "pattern_support_scope must be one of: dataset_profile, all_profiles"
        )

    def _preflight_profile_bundle_column(
        self,
        index: int,
        column_kwargs: Mapping[str, Any],
    ) -> None:
        column_value = self._required_iri(
            f"column_profiles[{index}].column_iri",
            column_kwargs["column_iri"],
        )
        table_value = (
            self._required_iri(
                f"column_profiles[{index}].table_iri",
                column_kwargs["table_iri"],
            )
            if column_kwargs.get("table_iri") is not None
            else None
        )
        column_name = column_kwargs["column_name"]
        column_name_value = column_name.strip()
        if not column_name_value:
            raise DoxaBaseError(
                f"column_profiles[{index}].column_name must not be empty"
            )
        summary = column_kwargs["summary"]
        if not summary.strip():
            raise DoxaBaseError(
                f"column_profiles[{index}].summary must not be empty"
            )
        for name in (
            "sample_size",
            "row_count",
            "null_count",
            "distinct_count",
        ):
            self._ensure_non_negative(
                f"column_profiles[{index}].{name}",
                column_kwargs.get(name),
            )
        self._profile_value_frequency_values(
            column_kwargs.get("value_frequencies"),
            field_name=f"column_profiles[{index}].value_frequencies",
        )
        self._profile_metric_values(
            column_kwargs.get("profile_metrics"),
            field_name=f"column_profiles[{index}].profile_metrics",
        )

        evidence_sources = column_kwargs.get("evidence_sources")
        if isinstance(evidence_sources, str):
            evidence_source_values = [evidence_sources]
        else:
            evidence_source_values = list(evidence_sources or [])
        if any(not isinstance(source, str) for source in evidence_source_values):
            raise DoxaBaseError(
                f"column_profiles[{index}].evidence_sources must contain strings"
            )
        if column_kwargs.get("physical_type") is not None:
            self._resource_ref(
                f"column_profiles[{index}].physical_type",
                column_kwargs["physical_type"],
            )
        if column_kwargs.get("value_type") is not None:
            self._resource_ref(
                f"column_profiles[{index}].value_type",
                column_kwargs["value_type"],
            )

        should_update_map = column_kwargs.get("update_map_column", True) and (
            table_value is not None
            or column_kwargs.get("map_label") is not None
            or column_kwargs.get("map_description") is not None
            or column_kwargs.get("physical_type") is not None
            or column_kwargs.get("value_type") is not None
            or column_kwargs.get("nullable") is not None
        )
        if should_update_map:
            if table_value is not None:
                self._resource_ref(
                    f"column_profiles[{index}].table_iri",
                    table_value,
                )

        if self._profile_pattern_requested(
            column_kwargs.get("pattern_summary"),
            column_kwargs.get("pattern_text"),
            column_kwargs.get("pattern_rationale"),
        ):
            implication_values = self._string_values(
                f"column_profiles[{index}].pattern_map_implications",
                column_kwargs.get("pattern_map_implications"),
            )
            self._validate_resource_values(
                f"column_profiles[{index}].pattern_map_implications",
                implication_values or [column_value],
            )

    def _profile_pattern_requested(
        self,
        pattern_summary: str | None,
        pattern_text: str | None,
        pattern_rationale: str | None,
    ) -> bool:
        pattern_fields = [pattern_summary, pattern_text, pattern_rationale]
        has_pattern_field = any(
            field is not None and field.strip() for field in pattern_fields
        )
        has_complete_pattern = all(
            field is not None and field.strip() for field in pattern_fields
        )
        if has_pattern_field and not has_complete_pattern:
            raise DoxaBaseError(
                "pattern_summary, pattern_text, and pattern_rationale must be "
                "provided together"
            )
        return has_complete_pattern

    def record_claim_reconsideration(
        self,
        *,
        newer_claim: str,
        older_claim: str,
        relation: TypingLiteral[
            "weakens",
            "contradicts",
            "supersedes",
            "refines",
        ]
        | str,
        rationale: str,
        summary: str | None = None,
        reconsidered_at: datetime | str | None = None,
        reconsidered_by: str | None = None,
        evidence_summary: str | None = None,
        evidence_sources: Iterable[str] | str | None = None,
        source_path: str | None = None,
        source_section: str | None = None,
        start_line: int | None = None,
        end_line: int | None = None,
        source_kind: str | None = None,
        older_claim_status: str | None = None,
        reconsideration_iri: str | None = None,
        evidence_iri: str | None = None,
        source_span_iri: str | None = None,
    ) -> ClaimReconsiderationRecord:
        if not rationale.strip():
            raise DoxaBaseError("reconsideration rationale must not be empty")
        newer_claim_iri = str(self._resource_ref("newer_claim", newer_claim))
        older_claim_iri = str(self._resource_ref("older_claim", older_claim))
        if newer_claim_iri == older_claim_iri:
            raise DoxaBaseError("newer_claim and older_claim must be different")
        relation_iri, direct_predicate, default_status = (
            self._claim_reconsideration_relation(relation)
        )
        status_value = (
            older_claim_status.strip()
            if older_claim_status and older_claim_status.strip()
            else default_status
        )
        self._ensure_claim_resource("newer_claim", newer_claim_iri)
        self._ensure_claim_resource("older_claim", older_claim_iri)
        if status_value is not None:
            self._resource_ref("older_claim_status", status_value)

        evidence_source_values = self._string_values(
            "evidence_sources",
            evidence_sources,
        )
        source_path_value = (
            source_path.strip()
            if source_path and source_path.strip()
            else None
        )
        source_section_value = (
            source_section.strip()
            if source_section and source_section.strip()
            else None
        )
        source_kind_value = (
            source_kind.strip()
            if source_kind and source_kind.strip()
            else None
        )
        evidence_iri_value = (
            evidence_iri.strip()
            if evidence_iri and evidence_iri.strip()
            else None
        )
        if evidence_summary and not (
            evidence_source_values or source_path_value or evidence_iri_value
        ):
            raise DoxaBaseError(
                "evidence_summary requires evidence_sources, source_path, or evidence_iri"
            )
        for name, value in {"start_line": start_line, "end_line": end_line}.items():
            if value is not None and value < 1:
                raise DoxaBaseError(f"{name} must be a positive one-based line number")

        reconsideration_subject = URIRef(
            reconsideration_iri or self._mint_iri("claim-reconsideration")
        )
        evidence_subject = (
            URIRef(evidence_iri_value)
            if evidence_iri_value is not None
            else URIRef(self._mint_iri("evidence"))
            if evidence_source_values or source_path_value
            else None
        )
        if evidence_subject is not None:
            self._preflight_evidence_summary_reuse(
                str(evidence_subject),
                evidence_summary,
            )
        source_span_subject = (
            URIRef(source_span_iri or self._mint_iri("source-span"))
            if source_path_value is not None
            else None
        )
        summary_text = (
            summary.strip()
            if summary and summary.strip()
            else f"{self._label_for_resource(relation_iri) or relation} claim reconsideration"
        )

        reconsideration_graph = Graph()
        self._bind_prefixes(reconsideration_graph)
        reconsideration_graph.add(
            (
                reconsideration_subject,
                RDF.type,
                URIRef(self.expand_iri("rc:ClaimReconsideration")),
            )
        )
        reconsideration_graph.add(
            (
                reconsideration_subject,
                URIRef(self.expand_iri("rc:summary")),
                Literal(summary_text),
            )
        )
        reconsideration_graph.add(
            (
                reconsideration_subject,
                URIRef(self.expand_iri("rc:reconsideringClaim")),
                URIRef(newer_claim_iri),
            )
        )
        reconsideration_graph.add(
            (
                reconsideration_subject,
                URIRef(self.expand_iri("rc:reconsideredClaim")),
                URIRef(older_claim_iri),
            )
        )
        reconsideration_graph.add(
            (
                reconsideration_subject,
                URIRef(self.expand_iri("rc:reconsiderationRelation")),
                URIRef(relation_iri),
            )
        )
        reconsideration_graph.add(
            (
                reconsideration_subject,
                URIRef(self.expand_iri("rc:reconsiderationRationale")),
                Literal(rationale),
            )
        )
        reconsideration_graph.add(
            (
                reconsideration_subject,
                URIRef(self.expand_iri("rc:reconsideredAt")),
                self._datetime_literal(reconsidered_at, name="reconsidered_at"),
            )
        )
        reconsideration_graph.add(
            (
                URIRef(newer_claim_iri),
                URIRef(self.expand_iri(direct_predicate)),
                URIRef(older_claim_iri),
            )
        )
        if reconsidered_by is not None:
            reconsideration_graph.add(
                (
                    reconsideration_subject,
                    URIRef(self.expand_iri("rc:reconsideredBy")),
                    self._resource_or_literal(reconsidered_by),
                )
            )
        if evidence_subject is not None:
            reconsideration_graph.add(
                (
                    reconsideration_subject,
                    URIRef(self.expand_iri("rc:evidence")),
                    evidence_subject,
                )
            )

        evidence_triples = 0
        if evidence_subject is not None and (
            evidence_source_values or source_path_value
        ):
            evidence_graph = Graph()
            self._bind_prefixes(evidence_graph)
            evidence_graph.add(
                (evidence_subject, RDF.type, URIRef(self.expand_iri("rc:Evidence")))
            )
            if evidence_summary:
                evidence_graph.add(
                    (
                        evidence_subject,
                        URIRef(self.expand_iri("rc:summary")),
                        Literal(evidence_summary),
                    )
                )
            for source in evidence_source_values:
                evidence_graph.add((evidence_subject, DCTERMS.source, Literal(source)))
            if source_path_value is not None:
                assert source_span_subject is not None
                evidence_graph.add(
                    (
                        evidence_subject,
                        URIRef(self.expand_iri("rc:sourceSpan")),
                        source_span_subject,
                    )
                )
                evidence_graph.add(
                    (
                        source_span_subject,
                        RDF.type,
                        URIRef(self.expand_iri("rc:SourceSpan")),
                    )
                )
                evidence_graph.add(
                    (
                        source_span_subject,
                        URIRef(self.expand_iri("rc:sourcePath")),
                        Literal(source_path_value),
                    )
                )
                if source_section_value:
                    evidence_graph.add(
                        (
                            source_span_subject,
                            URIRef(self.expand_iri("rc:sourceSection")),
                            Literal(source_section_value),
                        )
                    )
                if start_line is not None:
                    evidence_graph.add(
                        (
                            source_span_subject,
                            URIRef(self.expand_iri("rc:startLine")),
                            Literal(start_line, datatype=XSD.integer),
                        )
                    )
                if end_line is not None:
                    evidence_graph.add(
                        (
                            source_span_subject,
                            URIRef(self.expand_iri("rc:endLine")),
                            Literal(end_line, datatype=XSD.integer),
                        )
                    )
                if source_kind_value is not None:
                    evidence_graph.add(
                        (
                            source_span_subject,
                            URIRef(self.expand_iri("rc:sourceKind")),
                            URIRef(self.expand_iri(source_kind_value)),
                        )
                    )
            evidence_triples = self._insert_graph("evidence", evidence_graph)

        reconsideration_triples = self._insert_graph(
            "observations",
            reconsideration_graph,
        )
        status_triples = 0
        if status_value is not None:
            status_graph = Graph()
            self._bind_prefixes(status_graph)
            status_graph.add(
                (
                    URIRef(older_claim_iri),
                    URIRef(self.expand_iri("rc:observationStatus")),
                    URIRef(self.expand_iri(status_value)),
                )
            )
            status_triples = self._replace_subject_triples(
                "observations",
                older_claim_iri,
                [self.expand_iri("rc:observationStatus")],
                status_graph,
            )

        return ClaimReconsiderationRecord(
            reconsideration_iri=str(reconsideration_subject),
            newer_claim_iri=newer_claim_iri,
            older_claim_iri=older_claim_iri,
            relation=relation_iri,
            relation_label=self._label_for_resource(relation_iri),
            direct_predicate=self.expand_iri(direct_predicate),
            older_claim_status=(
                self.expand_iri(status_value) if status_value is not None else None
            ),
            evidence_iri=str(evidence_subject) if evidence_subject is not None else None,
            source_span_iri=(
                str(source_span_subject) if source_span_subject is not None else None
            ),
            reconsideration_triples=reconsideration_triples,
            evidence_triples=evidence_triples,
            status_triples=status_triples,
        )

    def record_map_dataset(
        self,
        iri: str,
        *,
        label: str | None = None,
        description: str | None = None,
        is_table: bool | None = None,
        columns: Iterable[str] | str | None = None,
        path_templates: Iterable[str] | str | None = None,
        row_count_snapshot: int | None = None,
        row_semantics: str | None = None,
        entity_key: str | None = None,
        schema_stability: str | None = None,
        layout_verification_status: str | None = None,
        layout_verification_note: str | None = None,
        caveats: Iterable[str] | str | None = None,
        storage_accesses: Iterable[str] | str | None = None,
        physical_layouts: Iterable[str] | str | None = None,
        companion_datasets: Iterable[str] | str | None = None,
        extra_types: Iterable[str] | str | None = None,
    ) -> MapResourceRecord:
        dataset_iri = self._required_iri("iri", iri)
        self._ensure_non_negative("row_count_snapshot", row_count_snapshot)
        column_values = self._string_values("columns", columns)
        path_template_values = self._string_values("path_templates", path_templates)
        caveat_values = self._string_values("caveats", caveats)
        storage_access_values = self._string_values("storage_accesses", storage_accesses)
        physical_layout_values = self._string_values("physical_layouts", physical_layouts)
        companion_values = self._string_values("companion_datasets", companion_datasets)
        extra_type_values = self._string_values("extra_types", extra_types)
        column_refs = [self._resource_ref("columns", column) for column in column_values]
        caveat_refs = [self._resource_ref("caveats", caveat) for caveat in caveat_values]
        storage_access_refs = [
            self._resource_ref("storage_accesses", access)
            for access in storage_access_values
        ]
        physical_layout_refs = [
            self._resource_ref("physical_layouts", layout)
            for layout in physical_layout_values
        ]
        companion_refs = [
            self._resource_ref("companion_datasets", companion)
            for companion in companion_values
        ]
        extra_type_refs = [
            self._resource_ref("extra_types", type_value)
            for type_value in extra_type_values
        ]
        row_semantics_ref = (
            self._resource_ref("row_semantics", row_semantics)
            if row_semantics is not None
            else None
        )
        entity_key_ref = (
            self._resource_ref("entity_key", entity_key)
            if entity_key is not None
            else None
        )
        schema_stability_ref = (
            self._controlled_resource_ref(
                "schema_stability",
                schema_stability,
                SCHEMA_STABILITY_LEVELS,
            )
            if schema_stability is not None
            else None
        )
        layout_verification_status_ref = (
            self._controlled_resource_ref(
                "layout_verification_status",
                layout_verification_status,
                LAYOUT_VERIFICATION_STATUSES,
            )
            if layout_verification_status is not None
            else None
        )

        dataset_type = self.expand_iri("rc:Dataset")
        table_type = self.expand_iri("rc:Table")
        expanded_extra_types = [str(type_ref) for type_ref in extra_type_refs]
        current_types = set(self._types("map", dataset_iri))
        dataset_is_table = is_table is True or (
            is_table is None
            and (table_type in current_types or table_type in expanded_extra_types)
        )

        graph = Graph()
        self._bind_prefixes(graph)
        subject = URIRef(dataset_iri)
        graph.add((subject, RDF.type, URIRef(dataset_type)))
        if dataset_is_table:
            graph.add((subject, RDF.type, URIRef(table_type)))
        for type_ref in extra_type_refs:
            graph.add((subject, RDF.type, type_ref))
        self._add_optional_literal(graph, subject, str(RDFS.label), label)
        self._add_optional_literal(graph, subject, str(RDFS.comment), description)
        for column_ref in column_refs:
            graph.add(
                (
                    subject,
                    URIRef(self.expand_iri("rc:hasColumn")),
                    column_ref,
                )
            )
        for path_template in path_template_values:
            graph.add(
                (
                    subject,
                    URIRef(self.expand_iri("rc:pathTemplate")),
                    Literal(path_template),
                )
            )
        if row_count_snapshot is not None:
            graph.add(
                (
                    subject,
                    URIRef(self.expand_iri("rc:rowCountSnapshot")),
                    Literal(row_count_snapshot, datatype=XSD.integer),
                )
            )
        if row_semantics is not None:
            graph.add(
                (
                    subject,
                    URIRef(self.expand_iri("rc:rowSemantics")),
                    row_semantics_ref,
                )
            )
        if entity_key is not None:
            graph.add(
                (
                    subject,
                    URIRef(self.expand_iri("rc:entityKey")),
                    entity_key_ref,
                )
            )
        if schema_stability is not None:
            graph.add(
                (
                    subject,
                    URIRef(self.expand_iri("rc:schemaStability")),
                    schema_stability_ref,
                )
            )
        if layout_verification_status is not None:
            graph.add(
                (
                    subject,
                    URIRef(self.expand_iri("rc:layoutVerificationStatus")),
                    layout_verification_status_ref,
                )
            )
        self._add_optional_literal(
            graph,
            subject,
            "rc:layoutVerificationNote",
            layout_verification_note,
        )
        for caveat_ref in caveat_refs:
            graph.add(
                (
                    subject,
                    URIRef(self.expand_iri("rc:hasKnownCaveat")),
                    caveat_ref,
                )
            )
        for access_ref in storage_access_refs:
            graph.add(
                (
                    subject,
                    URIRef(self.expand_iri("rc:hasStorageAccess")),
                    access_ref,
                )
            )
        for layout_ref in physical_layout_refs:
            graph.add(
                (
                    subject,
                    URIRef(self.expand_iri("rc:hasPhysicalLayout")),
                    layout_ref,
                )
            )
        for companion_ref in companion_refs:
            graph.add(
                (
                    subject,
                    URIRef(self.expand_iri("rc:companionOf")),
                    companion_ref,
                )
            )

        predicates: list[str] = []
        if is_table is not None or not current_types:
            predicates.append(str(RDF.type))
        if label is not None:
            predicates.append(str(RDFS.label))
        if description is not None:
            predicates.append(str(RDFS.comment))
        if columns is not None:
            predicates.append(self.expand_iri("rc:hasColumn"))
        if path_templates is not None:
            predicates.append(self.expand_iri("rc:pathTemplate"))
        if row_count_snapshot is not None:
            predicates.append(self.expand_iri("rc:rowCountSnapshot"))
        if row_semantics is not None:
            predicates.append(self.expand_iri("rc:rowSemantics"))
        if entity_key is not None:
            predicates.append(self.expand_iri("rc:entityKey"))
        if schema_stability is not None:
            predicates.append(self.expand_iri("rc:schemaStability"))
        if layout_verification_status is not None:
            predicates.append(self.expand_iri("rc:layoutVerificationStatus"))
        if layout_verification_note is not None:
            predicates.append(self.expand_iri("rc:layoutVerificationNote"))
        if caveats is not None:
            predicates.append(self.expand_iri("rc:hasKnownCaveat"))
        if storage_accesses is not None:
            predicates.append(self.expand_iri("rc:hasStorageAccess"))
        if physical_layouts is not None:
            predicates.append(self.expand_iri("rc:hasPhysicalLayout"))
        if companion_datasets is not None:
            predicates.append(self.expand_iri("rc:companionOf"))
        triples = self._replace_subject_triples("map", dataset_iri, predicates, graph)
        resource_type = table_type if dataset_is_table else dataset_type
        return MapResourceRecord(
            iri=dataset_iri,
            resource_type=resource_type,
            graph="map",
            triples=triples,
        )

    def record_map_column(
        self,
        iri: str,
        *,
        column_name: str,
        table_iri: str | None = None,
        label: str | None = None,
        description: str | None = None,
        physical_type: str | None = None,
        value_type: str | None = None,
        nullable: bool | None = None,
    ) -> MapResourceRecord:
        column_iri = self._required_iri("iri", iri)
        column_name_value = column_name.strip()
        if not column_name_value:
            raise DoxaBaseError("column_name must not be empty")
        physical_type_ref = (
            self._resource_ref("physical_type", physical_type)
            if physical_type is not None
            else None
        )
        value_type_ref = (
            self._resource_ref("value_type", value_type)
            if value_type is not None
            else None
        )
        table_ref = (
            self._resource_ref("table_iri", table_iri)
            if table_iri is not None
            else None
        )

        graph = Graph()
        self._bind_prefixes(graph)
        subject = URIRef(column_iri)
        graph.add((subject, RDF.type, URIRef(self.expand_iri("rc:Column"))))
        graph.add(
            (
                subject,
                URIRef(self.expand_iri("rc:columnName")),
                Literal(column_name_value),
            )
        )
        self._add_optional_literal(graph, subject, str(RDFS.label), label)
        self._add_optional_literal(graph, subject, str(RDFS.comment), description)
        if physical_type is not None:
            graph.add(
                (
                    subject,
                    URIRef(self.expand_iri("rc:physicalType")),
                    physical_type_ref,
                )
            )
        if value_type is not None:
            graph.add(
                (
                    subject,
                    URIRef(self.expand_iri("rc:valueType")),
                    value_type_ref,
                )
            )
        if nullable is not None:
            graph.add(
                (
                    subject,
                    URIRef(self.expand_iri("rc:nullable")),
                    Literal(nullable, datatype=XSD.boolean),
                )
            )

        predicates = [
            str(RDF.type),
            self.expand_iri("rc:columnName"),
        ]
        if label is not None:
            predicates.append(str(RDFS.label))
        if description is not None:
            predicates.append(str(RDFS.comment))
        if physical_type is not None:
            predicates.append(self.expand_iri("rc:physicalType"))
        if value_type is not None:
            predicates.append(self.expand_iri("rc:valueType"))
        if nullable is not None:
            predicates.append(self.expand_iri("rc:nullable"))
        triples = self._replace_subject_triples("map", column_iri, predicates, graph)
        if table_iri is not None:
            link_graph = Graph()
            self._bind_prefixes(link_graph)
            link_graph.add(
                (
                    table_ref,
                    URIRef(self.expand_iri("rc:hasColumn")),
                    subject,
                )
            )
            triples += self._insert_graph("map", link_graph)
        return MapResourceRecord(
            iri=column_iri,
            resource_type=self.expand_iri("rc:Column"),
            graph="map",
            triples=triples,
        )

    def record_map_caveat(
        self,
        iri: str,
        *,
        description: str,
        label: str | None = None,
        impact: str | None = None,
        severity: str | None = None,
        targets: Iterable[str] | str | None = None,
    ) -> MapResourceRecord:
        caveat_iri = self._required_iri("iri", iri)
        description_value = description.strip()
        if not description_value:
            raise DoxaBaseError("description must not be empty")
        target_values = self._string_values("targets", targets)
        severity_ref = (
            self._resource_ref("severity", severity)
            if severity is not None
            else None
        )

        graph = Graph()
        self._bind_prefixes(graph)
        subject = URIRef(caveat_iri)
        graph.add((subject, RDF.type, URIRef(self.expand_iri("rc:KnownCaveat"))))
        graph.add(
            (
                subject,
                URIRef(self.expand_iri("rc:caveatDescription")),
                Literal(description_value),
            )
        )
        self._add_optional_literal(graph, subject, str(RDFS.label), label)
        self._add_optional_literal(graph, subject, "rc:impact", impact)
        if severity is not None:
            graph.add(
                (
                    subject,
                    URIRef(self.expand_iri("rc:severity")),
                    severity_ref,
                )
            )

        predicates = [
            str(RDF.type),
            self.expand_iri("rc:caveatDescription"),
        ]
        if label is not None:
            predicates.append(str(RDFS.label))
        if impact is not None:
            predicates.append(self.expand_iri("rc:impact"))
        if severity is not None:
            predicates.append(self.expand_iri("rc:severity"))
        triples = self._replace_subject_triples("map", caveat_iri, predicates, graph)
        if target_values:
            link_graph = Graph()
            self._bind_prefixes(link_graph)
            for target in target_values:
                link_graph.add(
                    (
                        self._resource_ref("targets", target),
                        URIRef(self.expand_iri("rc:hasKnownCaveat")),
                        subject,
                    )
                )
            triples += self._insert_graph("map", link_graph)
        return MapResourceRecord(
            iri=caveat_iri,
            resource_type=self.expand_iri("rc:KnownCaveat"),
            graph="map",
            triples=triples,
        )

